-- Poems batch 88
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('c1b1b45f-8aa7-4f4a-af98-0eacfd755390','題浄明觀用舊韻簡黎才翁','胡寅','宋','宋诗','song-poetry','','[]','得酒相逢笑絕纓，而今雙鬢不全青。',32,'全唐诗/poet.song.108000.json','["得酒相逢笑絕纓，而今雙鬢不全青。", "蓬萊尚說三四淺，何況方平與蔡經。"]'),
('8111327f-d51b-4631-9722-9be1927e2d7f','示詩僧了信','胡寅','宋','宋诗','song-poetry','','[]','伊誰遣子著袈裟，幸自同源又一家。',64,'全唐诗/poet.song.108000.json','["伊誰遣子著袈裟，幸自同源又一家。", "尚喜深山閟珍璞，曾看枯枿粲奇葩。", "空言組繡真無用，實際津途亦易差。", "衣敝履穿頭欲雪，定於何處作生涯。"]'),
('3ed841d9-1db0-44ec-b368-14b09b72fa05','春雪','胡寅','宋','宋诗','song-poetry','','[]','北客南來十五春，今年春雪妙洪鈞。',128,'全唐诗/poet.song.109000.json','["北客南來十五春，今年春雪妙洪鈞。", "梅花著子無堪比，柳絮藏條未有因。", "何限萌芽煩蹙縮，幾多峯嶺倦顰伸。", "紅桃頮面還添粉，翠竹垂頭詎辱身。", "爭似松枝擎蒨絢，恰如桂魄浄埃塵。", "無人敢琢非牢玉，有客曾歌是爛銀。", "一夜東風吹地匝，四簷甘雨落階勻。", "天公變化誰能測，坐看郊原景物新。"]'),
('df9ee027-3ba9-44f5-965e-c4db2198ae2d','謝諸友見和','胡寅','宋','宋诗','song-poetry','','[]','飛霙三日太欺春，撲地鵝毛積萬鈞。',128,'全唐诗/poet.song.109000.json','["飛霙三日太欺春，撲地鵝毛積萬鈞。", "沙上幾人迷去迹，風前何處問來因。", "諒非天造夸工巧，當是神機有屈伸。", "松竹未應寒改操，龍蛇有喜蟄存身。", "綠窗朱戶偏饒色，瓊樹瑶林不染塵。", "笑粲爭妍人似玉，狂歌先醉髮如銀。", "方看衣袂天花集，俄見庭除木屑勻。", "多謝衆詩相映發，筆端六出更尖新。"]'),
('eddbbe19-c4b6-44c5-b2d7-014da4fbba81','和李生九日二首  其一','胡寅','宋','宋诗','song-poetry','','[]','節物休驚木葉催，相逢佳節興悠哉。',64,'全唐诗/poet.song.109000.json','["節物休驚木葉催，相逢佳節興悠哉。", "尊如北海聊同醉，菊傍東籬也自開。", "烏帽任教吹脫落，紫萸仍得看徘徊。", "諸君合有登高賦，爲繼當年戲馬臺。"]'),
('16a8c367-64c9-46da-96a7-f1be648f86a1','和李生九日二首  其二','胡寅','宋','宋诗','song-poetry','','[]','騷客悲秋心易催，主人醪醴正時哉。',64,'全唐诗/poet.song.109000.json','["騷客悲秋心易催，主人醪醴正時哉。", "登高何必仙家術，酬節聊憑笑口開。", "鳳嶺勝遊詩自好，龍山高宴首空回。", "獨餘眇莽梁園念，想見黄花滿吹臺。"]'),
('5190291d-245d-48cb-8be7-d7a21b2f774c','過明田寺會楊李二生於碧玉三首  其一','胡寅','宋','宋诗','song-poetry','','[]','已宅連延紫蓋椒，尋山依舊不辭遥。',64,'全唐诗/poet.song.109000.json','["已宅連延紫蓋椒，尋山依舊不辭遥。", "借床未暇桑三宿，解飯還須水一瓢。", "風外野雲俱淡蕩，雨餘秋氣亦蕭條。", "故人適有登高約，又拄枯藤過野橋。"]'),
('bce8346b-09e6-4204-bb85-42f2d2e702ce','過明田寺會楊李二生於碧玉三首  其二','胡寅','宋','宋诗','song-poetry','','[]','騷人空自怨蘭椒，更遣招辭歎遠遥。',64,'全唐诗/poet.song.109000.json','["騷人空自怨蘭椒，更遣招辭歎遠遥。", "爭似夷齊飽薇蕨，每同嵇阮醉觚瓢。", "清歌窈眇成珠貫，仙步虛徐按玉條。", "最憶向來携手處，雲平溪樹水平橋。"]'),
('4c6e7ad6-d366-4c06-ac5d-b51c32f97685','過明田寺會楊李二生於碧玉三首  其三','胡寅','宋','宋诗','song-poetry','','[]','漿酒香浮桂與椒，此間誰惜馬蹄遥。',64,'全唐诗/poet.song.109000.json','["漿酒香浮桂與椒，此間誰惜馬蹄遥。", "愛君澗壑沉吟樹，笑我江湖濩落瓢。", "前日好風猶泛座，只今零露已盈條。", "東山妓女誠何算，頗羨周郎得小橋。"]'),
('ef11a4df-d2dc-43fd-9d0c-0dd0145b7a51','和叔夏視穫三首  其一','胡寅','宋','宋诗','song-poetry','','[]','閒客何如樂聖時，欣聞威鳳再鳴岐。',64,'全唐诗/poet.song.109000.json','["閒客何如樂聖時，欣聞威鳳再鳴岐。", "且將詩筆耕堯壤，寧記書囊集漢帷。", "日錯碎金歸野菊，風欺危綠戰棠梨。", "殷勤雲將豐年問，無奈鴻蒙謝不知。"]'),
('f476776e-72ad-49a2-9e9b-9c1b3da3a4f1','和叔夏視穫三首  其二','胡寅','宋','宋诗','song-poetry','','[]','莫嗤公子務農時，后稷生民亦嶷岐。',64,'全唐诗/poet.song.109000.json','["莫嗤公子務農時，后稷生民亦嶷岐。", "稻割黄金鐮似月，汗揮白雨袂連帷。", "願趨座上雞和黍，未種胸中棗與梨。", "此樂若嫌兒輩覺，後知何以頼先知。"]'),
('2aa99278-6c04-47c0-8c49-902b393a7da4','和叔夏視穫三首  其三','胡寅','宋','宋诗','song-poetry','','[]','天賜豐年豈不時，閔公荒度傚徂岐。',64,'全唐诗/poet.song.109000.json','["天賜豐年豈不時，閔公荒度傚徂岐。", "經丘烈日能焦扇，獨夜秋風已泛帷。", "豈愧石兄推竹弟，聊斟杜酒破張梨。", "過門若有樊遲問，老子於中正遍知。"]'),
('a42d3ec9-306f-4e60-b917-395f41e4453d','和叔夏遊雙峰二首  其一','胡寅','宋','宋诗','song-poetry','','[]','有佛留深境，無僧闡大音。',48,'全唐诗/poet.song.109000.json','["有佛留深境，無僧闡大音。", "殷勤五字句，摇蕩衆香林。", "自適登臨興，誰窺隠顯心。", "從來多暇日，悔不早追尋。"]'),
('ce1d708f-ea7a-4e15-810a-854485e55bc0','和叔夏遊雙峰二首  其二','胡寅','宋','宋诗','song-poetry','','[]','山擁交加翠，風傳瑣碎音。',48,'全唐诗/poet.song.109000.json','["山擁交加翠，風傳瑣碎音。", "想聞尊有酒，待得月穿林。", "真樂難陪席，蕪詞漫寫心。", "要須專一壑，散策每相尋。"]'),
('8f3fb016-edf1-4137-b33f-4cd9112ec082','阻雪慈雲有懷叔夏','胡寅','宋','宋诗','song-poetry','','[]','常恨山陽少，籃輿故出郊。',288,'全唐诗/poet.song.109000.json','["常恨山陽少，籃輿故出郊。", "玄冥方北騖，屏翳又南交。", "勁氣將凝海，寒威便折膠。", "白雲揉盡碎，黑壤勢全包。", "著袂成花唾，沉波異雨泡。", "萬方齊穢潔，一潤浹肥磽。", "比色羞鉛粉，量多誚斗筲。", "禱神休奠璧，謝佛寢鳴鐃。", "獨鶴驚羣舞，晨難誤曉嘐。", "峯巒蒙似禿，溝隴劃如抓。", "巧謝鹽相比，甘宜蜜共抄。", "戾天鳶凍跕，嘯壑虎饑虓。", "薏苡連車載，珊瑚列樹敲。", "鮫綃從剪製，火布任焚炮。", "野漫鱗鱗磧，林攢翯翯巢。", "頗思馳駿足，快意舍鳴髇。", "及遠翻銀雁，搜潜動玉蛟。", "出畋瞻翠被，入賀聽紅鞘。", "瑶席瑚玗器，珠盤璪瑮肴。", "一時簪琲蘂，相與藉瓊茅。", "莫計消并積，聊平凸與凹。", "可憐詩繫带，更有火烘骹。", "斷手超三界，堅冰工六爻。", "飛霙終見睍，素饌闕盈庖。"]'),
('690ab6b4-e010-46eb-9a69-b133fb26e967','雪中寄黎才翁','胡寅','宋','宋诗','song-poetry','','[]','寒日已無暉，饕風更擅威。',96,'全唐诗/poet.song.109000.json','["寒日已無暉，饕風更擅威。", "暝山雷虺虺，陰壑雨霏霏。", "酒綠思同酌，爐紅憶共圍。", "不辭泥徑遠，要看雪花飛。", "天與人情契，春從草樹歸。", "幻成銀世界，偷取日光輝。", "安得千金舞，來翻六出衣。", "南枝香破玉，別有好芳菲。"]'),
('79852d61-22d5-4c1a-8f81-9471d5e9c1ae','和奇父叔夏雪五首  其一','胡寅','宋','宋诗','song-poetry','','[]','不須十日照胥敖，且要仙花麗隰臯。',64,'全唐诗/poet.song.109000.json','["不須十日照胥敖，且要仙花麗隰臯。", "集霰果然歸望望，同雲因得蔽高高。", "輝山玉璞韜虹氣，亂眼烟霄隘羽毛。", "欲叩小齋拚醉賞，最憐纖玉勸持醪。"]'),
('6277ba98-8d64-4339-ac7f-ccd77e1b890e','和奇父叔夏雪五首  其二','胡寅','宋','宋诗','song-poetry','','[]','誰能逐獸搏于敖，敏捷詩才笑魯臯。',64,'全唐诗/poet.song.109000.json','["誰能逐獸搏于敖，敏捷詩才笑魯臯。", "桂魄梅花俱自好，海山銀闕兩相高。", "回風最愛翻雙袖，潤物全勝拔一毛。", "打底和成真少味，空慚清酎映甜醪。"]'),
('cc8fd493-163d-499a-8c51-29c5920ce1d8','和奇父叔夏雪五首  其三','胡寅','宋','宋诗','song-poetry','','[]','懶把冬雷問告敖，休將玉雪試方臯。',64,'全唐诗/poet.song.109000.json','["懶把冬雷問告敖，休將玉雪試方臯。", "但驚梁苑風流在，難繼陽春格調高。", "宮女妝梅皆妬色，仙山花石總泠毛。", "自慚涸思無多子，糟粕何由更取醪。"]'),
('46baf918-695d-4f3b-b4e7-659f5fbeb06c','和奇父叔夏雪五首  其四','胡寅','宋','宋诗','song-poetry','','[]','乍霽初離房與敖，又看雲氣壓神臯。',64,'全唐诗/poet.song.109000.json','["乍霽初離房與敖，又看雲氣壓神臯。", "崑岡屢得因心友，東郭真慚舉趾高。", "最愛謝兒方柳絮，可憐漢使囓氈毛。", "水晶鹽是何人得，拜賜曾同御縹醪。"]'),
('9cb30d16-0203-44fd-8522-99ad521011ea','和奇父叔夏雪五首  其五','胡寅','宋','宋诗','song-poetry','','[]','善遊不必慕閻敖，避雨休尋夏后臯。',64,'全唐诗/poet.song.109000.json','["善遊不必慕閻敖，避雨休尋夏后臯。", "共喜九天羲馭整，要登千仞祝融高。", "交情自分居龍尾，酒算何妨劇蝟毛。", "聞道雷池尚殘雪，且携茗碗罷壺醪。"]'),
('dc853e89-298d-4572-bccc-cf978a9b3b4a','和奇父竹齋小池及遊春五絕  其一','胡寅','宋','宋诗','song-poetry','','[]','虛齋要使暑天寒，移得扶疎愜靜觀。',32,'全唐诗/poet.song.109000.json','["虛齋要使暑天寒，移得扶疎愜靜觀。", "不但好風生殿角，已應春笋鬭春闌。"]'),
('381e5787-0235-483c-988f-ba9be6249efd','和奇父竹齋小池及遊春五絕  其二','胡寅','宋','宋诗','song-poetry','','[]','綠竹叢邊築小塘，泉來何處已洸洸。',32,'全唐诗/poet.song.109000.json','["綠竹叢邊築小塘，泉來何處已洸洸。", "未涵北戶星辰影，斗覺南風藻荇香。"]'),
('028e38de-bb17-4b22-887c-2207abd8698e','和奇父竹齋小池及遊春五絕  其三','胡寅','宋','宋诗','song-poetry','','[]','不瞻犀柄動經旬，忽報巾車獨輾春。',32,'全唐诗/poet.song.109000.json','["不瞻犀柄動經旬，忽報巾車獨輾春。", "曾作天津歌酒伴，此間誰是識花人。"]'),
('5dc809be-8d51-4daf-9411-82b48a767401','和奇父竹齋小池及遊春五絕  其四','胡寅','宋','宋诗','song-poetry','','[]','春事已驚飛柳絮，香醪何日釀松脂。',32,'全唐诗/poet.song.109000.json','["春事已驚飛柳絮，香醪何日釀松脂。", "要平萬點風前恨，莫遣千鍾醒後知。"]'),
('7e1cf760-d3b6-458c-abe5-3de434a6d55b','和奇父竹齋小池及遊春五絕  其五','胡寅','宋','宋诗','song-poetry','','[]','東風不放兩般春，只繫胸懷故與新。',32,'全唐诗/poet.song.109000.json','["東風不放兩般春，只繫胸懷故與新。", "爲問漆園蝴蝶夢，何如沂水舞雩人。"]'),
('33f50438-1a68-4801-87d3-b963225d57d4','和叔夏十絕一宿雲峯寺二到韓公莊三飯草衣岩四泊東禪剎五六七八遊碧玉泉九訪楊秀才十叔夏思歸  其一','胡寅','宋','宋诗','song-poetry','','[]','醉騎生馬却扶輿，雪灑春衫二月初。',32,'全唐诗/poet.song.109000.json','["醉騎生馬却扶輿，雪灑春衫二月初。", "行樂偶從山寺始，他年重到未成虛。"]'),
('ea070a63-8303-47cd-85df-0f75f4075cab','和叔夏十絕一宿雲峯寺二到韓公莊三飯草衣岩四泊東禪剎五六七八遊碧玉泉九訪楊秀才十叔夏思歸  其二','胡寅','宋','宋诗','song-poetry','','[]','久聞人境寄陶廬，深約同遊駕小車。',32,'全唐诗/poet.song.109000.json','["久聞人境寄陶廬，深約同遊駕小車。", "文舉舊傳樽有酒，馮驩寧歎食無魚。"]'),
('130995ea-a3e6-4e92-aacf-4056a29dda15','和叔夏十絕一宿雲峯寺二到韓公莊三飯草衣岩四泊東禪剎五六七八遊碧玉泉九訪楊秀才十叔夏思歸  其三','胡寅','宋','宋诗','song-poetry','','[]','前僧已著草茅培，後死猶來瘞骨灰。',32,'全唐诗/poet.song.109000.json','["前僧已著草茅培，後死猶來瘞骨灰。", "一醉劇談非爲爾，自澆胸次有崔巍。"]'),
('88329da6-63d5-4884-9f0b-f48a1cc2b7a1','和叔夏十絕一宿雲峯寺二到韓公莊三飯草衣岩四泊東禪剎五六七八遊碧玉泉九訪楊秀才十叔夏思歸  其四','胡寅','宋','宋诗','song-poetry','','[]','馬饑人困日西昏，無限歸鴉已著村。',32,'全唐诗/poet.song.109000.json','["馬饑人困日西昏，無限歸鴉已著村。", "記取東禪風雨夕，卧無床薦闔無門。"]'),
('ddfc94af-9ce9-4b6f-abab-33babed0c828','和叔夏十絕一宿雲峯寺二到韓公莊三飯草衣岩四泊東禪剎五六七八遊碧玉泉九訪楊秀才十叔夏思歸  其五','胡寅','宋','宋诗','song-poetry','','[]','不惜衝泥步步前，爲聞幽處有明川。',32,'全唐诗/poet.song.109000.json','["不惜衝泥步步前，爲聞幽處有明川。", "峯回路轉酬勞客，一派琉璃春正妍。"]'),
('68b6d7ab-4416-44bb-853e-6e55c47c3e4c','和叔夏十絕一宿雲峯寺二到韓公莊三飯草衣岩四泊東禪剎五六七八遊碧玉泉九訪楊秀才十叔夏思歸  其六','胡寅','宋','宋诗','song-poetry','','[]','跨溪臨岸各清真，上客來臨景更新。',32,'全唐诗/poet.song.109000.json','["跨溪臨岸各清真，上客來臨景更新。", "幽樹好花脩竹色，相鮮浮動鏡中春。"]'),
('526ecc41-35ed-4af1-9813-32d17270d522','和叔夏十絕一宿雲峯寺二到韓公莊三飯草衣岩四泊東禪剎五六七八遊碧玉泉九訪楊秀才十叔夏思歸  其七','胡寅','宋','宋诗','song-poetry','','[]','種竹何時匝兩垠，只今疎翠已情親。',32,'全唐诗/poet.song.109000.json','["種竹何時匝兩垠，只今疎翠已情親。", "會看染合全溪影，照映來遊碧落身。"]'),
('19376076-3976-41ce-b895-ef6f3ab489a8','和叔夏十絕一宿雲峯寺二到韓公莊三飯草衣岩四泊東禪剎五六七八遊碧玉泉九訪楊秀才十叔夏思歸  其八','胡寅','宋','宋诗','song-poetry','','[]','謔浪瀾翻間詆訶，絕勝歌貫舞婆娑。',32,'全唐诗/poet.song.109000.json','["謔浪瀾翻間詆訶，絕勝歌貫舞婆娑。", "解頤爲聽談詩妙，脫腕空傳草檄多。"]'),
('83a8da7e-f419-49a3-bd9b-b43d22dd5a37','和叔夏十絕一宿雲峯寺二到韓公莊三飯草衣岩四泊東禪剎五六七八遊碧玉泉九訪楊秀才十叔夏思歸  其九','胡寅','宋','宋诗','song-poetry','','[]','莫笑田翁不任真，好賢留客意殊親。',32,'全唐诗/poet.song.109000.json','["莫笑田翁不任真，好賢留客意殊親。", "海棠半拆山丹重，京洛何曾遠客身。"]'),
('0169bdc1-c4b9-42c2-ac18-b7354c6f8a1e','和叔夏十絕一宿雲峯寺二到韓公莊三飯草衣岩四泊東禪剎五六七八遊碧玉泉九訪楊秀才十叔夏思歸  其一○','胡寅','宋','宋诗','song-poetry','','[]','重按東臯豈自歸，曾聞歸思勇如飛。',32,'全唐诗/poet.song.109000.json','["重按東臯豈自歸，曾聞歸思勇如飛。", "只因昨夜沉香帳，蟣虱夤緣金縷衣。"]'),
('fd846a98-74bb-4a84-8f8b-223c674a2b1f','赴宣卿牡丹之集和奇父二首  其一','胡寅','宋','宋诗','song-poetry','','[]','勝業看花暖正繁，玉仙洪福且休論。',64,'全唐诗/poet.song.109000.json','["勝業看花暖正繁，玉仙洪福且休論。", "初筵愛客尊俱盡，落筆成詩水共翻。", "京洛追遊真似夢，風光流轉絕無言。", "武林亦有西池否，安得姚黄奉至尊。"]'),
('d3c05875-44a9-43a4-a71b-366361b7c599','赴宣卿牡丹之集和奇父二首  其二','胡寅','宋','宋诗','song-poetry','','[]','移得仙丹手自封，護花雲結秀陰濃。',63,'全唐诗/poet.song.109000.json','["移得仙丹手自封，護花雲結秀陰濃。", "未嫌芍藥爭時發，却有酴醿作酒供。", "喜見典型開朶，寧須緋紫計重重。", "定知禾黍勝桃李，何似犁牛問老農。"]'),
('7abdda48-1f0d-46b3-81d5-251b1a0ace5a','和子揚雲峯留題','胡寅','宋','宋诗','song-poetry','','[]','夙有水雲趣，倦遊塵土間。',24,'全唐诗/poet.song.109000.json','["夙有水雲趣，倦遊塵土間。", "衝山爲誰秀，几案我江山。"]'),
('ada35032-eba8-43fa-8c20-65c2864e6552','題能仁竹軒竹皆貓頭也','胡寅','宋','宋诗','song-poetry','','[]','負崖臨壑幾千竿，掩映虛堂繞曲欄。',64,'全唐诗/poet.song.109000.json','["負崖臨壑幾千竿，掩映虛堂繞曲欄。", "森矗翠幢參玉槊，毰毸綠鳳戲青鸞。", "三冬已見龍孫起，六月猶便虎嘯寒。", "置酒會歌貍首節，要令鼠子不相干。"]'),
('490c174f-4d79-43f5-8b63-184893ea1c65','和彥達','胡寅','宋','宋诗','song-poetry','','[]','扶藤有興即東西，不用花驄向月啼。',64,'全唐诗/poet.song.109000.json','["扶藤有興即東西，不用花驄向月啼。", "閒看浮雲倚危嶠，靜臨流水瞰寒溪。", "過頻幸樂雞豚社，歸暮何憂虎豹蹊。", "肯似世塵名利客，班荆折柳悵分携。"]'),
('d9bcfbc2-39e6-4cd7-8697-275f91dced46','上封登高','胡寅','宋','宋诗','song-poetry','','[]','今朝的的是重陽，獨步崔巍覓醉鄉。',64,'全唐诗/poet.song.109000.json','["今朝的的是重陽，獨步崔巍覓醉鄉。", "飽日山楓千樹赤，絢秋岩菊一枝黄。", "幽禪出應耶城供，倦客來迎宴寢香。", "閒讀舊題嗟歲月，功名回首鬢毛蒼。"]'),
('eabc1319-c9e0-4576-a1e9-45ab3785203e','題石頭菴','胡寅','宋','宋诗','song-poetry','','[]','剝落烟雲秋晚晴，身心無累此閒行。',32,'全唐诗/poet.song.109000.json','["剝落烟雲秋晚晴，身心無累此閒行。", "正聽萬壑松風滿，想見西南新月生。"]'),
('3518712d-0fa8-44d2-afbf-932e530b359d','送姜醫與能仁西堂印老能仁韋宙讀書之地','胡寅','宋','宋诗','song-poetry','','[]','韋公挾策漫荆榛，牧子亡羊也未真。',64,'全唐诗/poet.song.109000.json','["韋公挾策漫荆榛，牧子亡羊也未真。", "百疊亂山秋思杳，半岩脩竹歲寒親。", "不須招手遊蓮社，且可冥心舍筏津。", "山芋畦蔬正味好，餉君薑醢助芳辛。"]'),
('7026bb79-e5c7-4d67-b09d-4e6daf7200ab','和唐堅伯留題莊舍  其一','胡寅','宋','宋诗','song-poetry','','[]','無端世故若連環，獨未忘懷𤱶畝間。',64,'全唐诗/poet.song.109000.json','["無端世故若連環，獨未忘懷𤱶畝間。", "不問落花隨水遠，最憐脩竹伴人閒。", "非求垣屋須窮僻，自愛巾車得往還。", "已諭耕奴多藝秫，免教華髮變朱顔。"]'),
('4a521932-b0a1-4016-81f1-bc085b2abd22','和唐堅伯留題莊舍  其二','胡寅','宋','宋诗','song-poetry','','[]','卧看月落半瑶環，起喚清風紫翠間。',64,'全唐诗/poet.song.109000.json','["卧看月落半瑶環，起喚清風紫翠間。", "玩意詩書千古樂，放懷天地一身閒。", "幾多倦鳥歸何晚，無限浮雲去未還。", "不向此中真得趣，更論盤谷與商顔。"]'),
('150225c9-685f-45a7-9de3-562ad44f7c5d','和趙用明梅','胡寅','宋','宋诗','song-poetry','','[]','浄几寒窗日，翛然萬慮忘。',144,'全唐诗/poet.song.109000.json','["浄几寒窗日，翛然萬慮忘。", "詩筒忽到手，花信已催籹。", "茅舍斜斜彴，冰溪短短牆。", "仙膚下姑射，嬌額映昭陽。", "崔竹翻新畫，龍涎出古香。", "有金攢蘂細，無綠認條長。", "慰薦騷人寂，挑撩酒態狂。", "雪遊空泛剡，蘭佩枉沉湘。", "隔屋吹生麝，盈枝縱夜光。", "詎能煩驛使，聊自占年芳。", "渡盡鴻飛影，迎開柳带黄。", "繁華收拾後，結子又先嘗。"]'),
('ad69b66b-1bcd-477c-852c-a1e6b0dc9d73','再次前韻','胡寅','宋','宋诗','song-poetry','','[]','經年與花別，花意不相忘。',144,'全唐诗/poet.song.109000.json','["經年與花別，花意不相忘。", "綽約素情在，掃除時世籹。", "楚人輕剪伐，北客護垣牆。", "半樹竹亭亞，幾株溪水陽。", "可模非絕代，難學是生香。", "當結珠宮伴，休吹玉笛長。", "賞心甘爛醉，被惱漫顛狂。", "正當映喬岳，未應浮碧湘。", "松筠共瀟灑，雪月佐輝光。", "自保孤根暖，寧隨百草芳。", "遠天方絢白，細雨便垂黄。", "佳實收功地，君羹必可嘗。"]'),
('7b833eee-3f4e-4c64-b0d4-7940ba2e8f7f','用明有携酒賞梅之約久而未至復和以督之','胡寅','宋','宋诗','song-poetry','','[]','美酒名花並，無情即易忘。',144,'全唐诗/poet.song.109000.json','["美酒名花並，無情即易忘。", "小槽應注瀑，大樹欲殘籹。", "雖則通達道，其如隔繚牆。", "寄人慚大庾，求伴媿高陽。", "好傍枝間醉，時聞盞面香。", "已勤賡唱久，未覩肆筵長。", "月下疎疎映，風餘片片狂。", "可憐花似雪，那得酒如湘。", "夢作瑶林去，斟浮玉斚光。", "八仙當避席，百卉定羞芳。", "莫待松醪碧，休尋蜜萼黄。", "風流貴公子，火急傚原嘗。"]'),
('17bbd287-1b1f-44be-8dab-65501af821ee','和用明梅十三絕  其一','胡寅','宋','宋诗','song-poetry','','[]','的皪輕臨宋玉牆，世間顔色盡凡籹。',32,'全唐诗/poet.song.109000.json','["的皪輕臨宋玉牆，世間顔色盡凡籹。", "病夫欲作天花觀，無奈時時得暗香。"]'),
('55ee26bb-7432-4283-9eca-51c51468be77','和用明梅十三絕  其二','胡寅','宋','宋诗','song-poetry','','[]','若道南枝春信微，如何開向雪飛時。',32,'全唐诗/poet.song.109000.json','["若道南枝春信微，如何開向雪飛時。", "却堪謝女因風句，休詠楊家膩肉肥。"]'),
('1d06b38b-c20e-47f9-a355-ca1cf19bf3e1','和用明梅十三絕  其三','胡寅','宋','宋诗','song-poetry','','[]','寧須較短復論長，拖白施朱亦兩忘。',32,'全唐诗/poet.song.109000.json','["寧須較短復論長，拖白施朱亦兩忘。", "有羨廣平能草賦，病來無緒不成章。"]'),
('2f612fe3-678b-47a1-9f56-1809ceceb567','和用明梅十三絕  其四','胡寅','宋','宋诗','song-poetry','','[]','雪消天氣一番新，水際逢春淑且真。',32,'全唐诗/poet.song.109000.json','["雪消天氣一番新，水際逢春淑且真。", "未信長安多麗者，定知空谷有佳人。"]'),
('2bebdf2a-48ac-4bd5-b906-62d8ebedf8bc','和用明梅十三絕  其五','胡寅','宋','宋诗','song-poetry','','[]','綠萼全勝紅萼好，新枝爭亞舊枝長。',32,'全唐诗/poet.song.109000.json','["綠萼全勝紅萼好，新枝爭亞舊枝長。", "賞心未減春風蝶，傍蘂穿花栩栩狂。"]'),
('71747a63-d7e7-435b-895b-6d6f9a9375ee','和用明梅十三絕  其六','胡寅','宋','宋诗','song-poetry','','[]','半開何惜恣追遊，最怕風飄萬點愁。',32,'全唐诗/poet.song.109000.json','["半開何惜恣追遊，最怕風飄萬點愁。", "倘是仙山有真籍，待憑方士更遲留。"]'),
('8790cf06-f68e-4161-a1e8-e1bd213a7e6b','和用明梅十三絕  其七','胡寅','宋','宋诗','song-poetry','','[]','要寫橫斜臨水枝，應從淡墨見依稀。',32,'全唐诗/poet.song.109000.json','["要寫橫斜臨水枝，應從淡墨見依稀。", "畫師未必傳天巧，爭似西廂月影微。"]'),
('4462e3fe-a9a5-432e-b3dd-17f5423363ee','和用明梅十三絕  其八','胡寅','宋','宋诗','song-poetry','','[]','玉管吹殘滿地霜，去年遺恨不能忘。',32,'全唐诗/poet.song.109000.json','["玉管吹殘滿地霜，去年遺恨不能忘。", "還來月下呈疎影，先向風前試晚籹。"]'),
('a14ee527-a0db-43cc-81c2-8cbf68f087ea','和用明梅十三絕  其九','胡寅','宋','宋诗','song-poetry','','[]','寒梅應不是甘棠，我輩爲詩豈面牆。',32,'全唐诗/poet.song.109000.json','["寒梅應不是甘棠，我輩爲詩豈面牆。", "便對雪霜矜節操，未妨雲雨下巫陽。"]'),
('f70c4640-a60e-4701-b79d-fc237ae98bba','和用明梅十三絕  其一○','胡寅','宋','宋诗','song-poetry','','[]','漫說瓊花淮海陽，要知蘭蕙不能香。',32,'全唐诗/poet.song.109000.json','["漫說瓊花淮海陽，要知蘭蕙不能香。", "人間草木如相對，寧遣詩仙引興長。"]'),
('375cf8a6-3184-4462-9774-f46668055e49','和用明梅十三絕  其一一','胡寅','宋','宋诗','song-poetry','','[]','醉把天葩嚼蘂香，筆端翻水趁詩狂。',32,'全唐诗/poet.song.109000.json','["醉把天葩嚼蘂香，筆端翻水趁詩狂。", "結成却薦和羹鼎，妙手先從錡釜湘。"]'),
('3b94f181-68c8-41f0-9dba-bc0d9419f5f7','和用明梅十三絕  其一二','胡寅','宋','宋诗','song-poetry','','[]','公子曾遊翰墨場，詩成寒律带春光。',32,'全唐诗/poet.song.109000.json','["公子曾遊翰墨場，詩成寒律带春光。", "杯中竹葉悠悠夢，句裏梅花字字芳。"]'),
('f861e14c-0751-4a9a-a891-d89c54c93fd4','和用明梅十三絕  其一三','胡寅','宋','宋诗','song-poetry','','[]','指數春回驅歲寒，催令花落鼻先酸。',32,'全唐诗/poet.song.109000.json','["指數春回驅歲寒，催令花落鼻先酸。", "要須晴昊開芳草，亂插繁華足意看。"]'),
('7607d74a-5d02-485f-a069-6acf352163cd','和趙廟欲携尊賞殘梅二絕  其一','胡寅','宋','宋诗','song-poetry','','[]','爲惜紛紛作雪飛，忍看桃李便芳菲。',32,'全唐诗/poet.song.109000.json','["爲惜紛紛作雪飛，忍看桃李便芳菲。", "小瓶留得春風面，尚可携壺一醉歸。"]'),
('de7aa8e8-1da3-42d2-b689-afcdfe42eaa9','和趙廟欲携尊賞殘梅二絕  其二','胡寅','宋','宋诗','song-poetry','','[]','離離疎蘂抱寒條，開晚渾疑雪未消。',32,'全唐诗/poet.song.109000.json','["離離疎蘂抱寒條，開晚渾疑雪未消。", "風雨助君慳且澀，吹將詩句淡相撩。"]'),
('46f45b76-78c4-41f9-876b-c62ab5b3ccdd','出門偶成','胡寅','宋','宋诗','song-poetry','','[]','飯已柴扉手自開，杖藜三徑久徘徊。',64,'全唐诗/poet.song.109000.json','["飯已柴扉手自開，杖藜三徑久徘徊。", "忽驚無雨溪流漲，遥認他山雪浪來。", "葉暗青雲環舍竹，樹團香玉繞池梅。", "春光已近宜行樂，未怕年華冉冉催。"]'),
('eb8afbdf-264a-4cbe-90ff-009151a4c444','寄奇父','胡寅','宋','宋诗','song-poetry','','[]','似聞北舍與南隣，各向西疇答問津。',64,'全唐诗/poet.song.109000.json','["似聞北舍與南隣，各向西疇答問津。", "獨使丈人留闃寂，更無佳客奉光塵。", "思公待泛山陰雪，破悶須携麯米春。", "往行前言未多識，古來元重老成人。"]'),
('457d510e-43ef-44e5-8a9a-fdc7d312695d','携酒訪奇父小酌竹齋以詩來謝次其韻','胡寅','宋','宋诗','song-poetry','','[]','優游林麓避塵沙，杖策巾橫一幅紗。',64,'全唐诗/poet.song.109000.json','["優游林麓避塵沙，杖策巾橫一幅紗。", "却老自燒金鼎藥，醒心時進玉川茶。", "鈎窗愛日頻遷坐，蔭竹流泉屢滿漥。", "常記此歡同醉處，歈歌折柳舞傳巴。"]'),
('53c63554-b555-41c2-97d5-c7d4ce1d321e','和奇父再寄首韻奇父易用','胡寅','宋','宋诗','song-poetry','','[]','酒影何時有畫蛇，燈光不必罩紅紗。',64,'全唐诗/poet.song.109000.json','["酒影何時有畫蛇，燈光不必罩紅紗。", "幸能真率時添菜，未憶柔纖笑捧茶。", "世路風波常起伏，醉鄉田地絕隆漥。", "愛公詩句如清瑟，自比流魚感瓠巴。"]'),
('1a652df3-3113-4308-9d8a-30717966cb46','碧泉芍藥四首  其一','胡寅','宋','宋诗','song-poetry','','[]','暈紫層紅各自花，翠痕稠葉整還斜。',32,'全唐诗/poet.song.109000.json','["暈紫層紅各自花，翠痕稠葉整還斜。", "有情豈必含春泪，自是殷勤管歲華。"]'),
('1d2104d4-68ca-4811-9504-f8769963aad4','碧泉芍藥四首  其二','胡寅','宋','宋诗','song-poetry','','[]','林影溪光風力微，黄鸝隔葉囀還飛。',32,'全唐诗/poet.song.109000.json','["林影溪光風力微，黄鸝隔葉囀還飛。", "從教萬點飄浮去，頼有庭花願不違。"]'),
('c628d4d4-0985-4cea-a4b8-5b8c30c001a3','碧泉芍藥四首  其三','胡寅','宋','宋诗','song-poetry','','[]','春事紛綸去，槐陰襞積來。',48,'全唐诗/poet.song.109000.json','["春事紛綸去，槐陰襞積來。", "此花方靚麗，待我正徘徊。", "墮砌晨霞爛，凌波錦帳開。", "有懷能賦客，把酒獨登臺。"]'),
('78e46965-3860-4833-a784-b821993c7932','碧泉芍藥四首  其四','胡寅','宋','宋诗','song-poetry','','[]','樂水頻頻到，尋花特特來。',48,'全唐诗/poet.song.109000.json','["樂水頻頻到，尋花特特來。", "餘春初自媚，清賞未能回。", "雨裹仙苞重，風扶秀臉開。", "寶刀移造化，單葉變樓臺。"]'),
('6b52fec5-af3d-4015-9372-57dee9b27e11','三月晦和唐人韻詩云三月正當三十日風光別我苦吟身共君今夜不須寐未到五更猶是春','胡寅','宋','宋诗','song-poetry','','[]','一氣沖融轉大鈞，四時舒卷見全身。',32,'全唐诗/poet.song.109000.json','["一氣沖融轉大鈞，四時舒卷見全身。", "若云春向晨鐘斷，須信詩人未識春。"]'),
('f911805b-de35-44c6-ab19-b1dcee763d41','和堅伯碧泉留題','胡寅','宋','宋诗','song-poetry','','[]','欲濯冠纓塵垢侵，梁亭橫占一源深。',64,'全唐诗/poet.song.109000.json','["欲濯冠纓塵垢侵，梁亭橫占一源深。", "碧紗演漾蒼魚色，黛白因依翠木陰。", "疏沼豈惟三鳳飲，買山初聽一龍吟。", "請君莫惜來遊屢，耆舊風流尚可尋。"]'),
('f873241b-468a-43fc-80e6-d310ed29b257','和毛生瑞香','胡寅','宋','宋诗','song-poetry','','[]','久雨妨園涉，奇芬待客吹。',48,'全唐诗/poet.song.109000.json','["久雨妨園涉，奇芬待客吹。", "今朝搴翠幄，晴日麗繁枝。", "一一花相簇，翩翩蝶未知。", "薰篝蒙紫錦，香過每輕披。"]'),
('f5db12b7-b605-4964-b82b-5387d349e8f0','贈劉仲固','胡寅','宋','宋诗','song-poetry','','[]','恭惟事契逾三紀，一醉昇州十八年。',64,'全唐诗/poet.song.109000.json','["恭惟事契逾三紀，一醉昇州十八年。", "回念壯遊多契闊，欣逢情話重留連。", "珠庭骨相封侯在，金奏詩章落筆傳。", "預恐西風送離袂，莫孤南阜好林泉。"]'),
('cd811951-63de-47f5-8f58-6edfeb61f882','謝彥脩携具見過','胡寅','宋','宋诗','song-poetry','','[]','識字深慚揚子雲，載醪何以塞殷勤。',64,'全唐诗/poet.song.109000.json','["識字深慚揚子雲，載醪何以塞殷勤。", "山騰海浪兼天碧，雨薦秋聲映燭聞。", "秘藏未能窺佛界，劇談聊足張吾軍。", "浮蛆玉色人間少，判却陶然引十分。"]'),
('102e933e-12cd-4df5-8570-2aaf139881c8','和彥沖晚飲','胡寅','宋','宋诗','song-poetry','','[]','北澗霜翻浪，南山翠竹堆。',48,'全唐诗/poet.song.109000.json','["北澗霜翻浪，南山翠竹堆。", "早酣隨夢斷，晚酌傍池開。", "莫放清歡闕，從教急管催。", "精深與雄健，剩欲見天才。"]'),
('57267190-6588-4c45-aa9a-c388c18e8bfd','和彥仲長汀鋪留題','胡寅','宋','宋诗','song-poetry','','[]','瘦馬鞭猶懶，長亭室正虛。',48,'全唐诗/poet.song.109000.json','["瘦馬鞭猶懶，長亭室正虛。", "五言留敗壁，一飯飽新蔬。", "閲世但如許，浮生寧願餘。", "茅簷與藻梲，等觀是蘧廬。"]'),
('320b8a23-fdcc-41a3-9360-54aa2492e3f9','和彥沖雲際院留題','胡寅','宋','宋诗','song-poetry','','[]','久聞幽寺渺雲間，且向新詩見一斑。',64,'全唐诗/poet.song.109000.json','["久聞幽寺渺雲間，且向新詩見一斑。", "不羨寶華承白足，最憐澄水漾秋山。", "飛車要度重重嶺，繫艇還思淺淺灣。", "彈指大千何遠近，却將遊想付無還。"]'),
('3c383063-2046-47c8-9be7-86d3868f4ab3','和彥沖茉莉二首  其一','胡寅','宋','宋诗','song-poetry','','[]','易刻無瑕玉，難勻不汗籹。',48,'全唐诗/poet.song.109000.json','["易刻無瑕玉，難勻不汗籹。", "有誰同素絢，無物比生香。", "寶靨三年笑，氷肌六月凉。", "畹蘭何足佩，懷瑾枉沉湘。"]'),
('92a87015-be19-482f-8c9d-181a245b477e','和彥沖茉莉二首  其二','胡寅','宋','宋诗','song-poetry','','[]','謫墮天仙子，生憎袨服籹。',48,'全唐诗/poet.song.109000.json','["謫墮天仙子，生憎袨服籹。", "華雲油潑碧，花雪麝開香。", "曬喜金鴉熱，洗宜玉井凉。", "芳根如可乞，携取詫娥湘。"]'),
('de517b0b-8a2f-4e89-9296-e710bc8a11b5','和彥沖新凉','胡寅','宋','宋诗','song-poetry','','[]','河朔時堪擬，溟南意懶圖。',168,'全唐诗/poet.song.109000.json','["河朔時堪擬，溟南意懶圖。", "相羊逢勝地，瀟灑似精廬。", "暝翠千山合，芳紅一雨濡。", "跳金魚亦樂，爍石暑全無。", "昨夢暌神女，沉疴問鬼臾。", "無輪生四角，有憤反三隅。", "方羨溪塘滿，俄趨岸柳疎。", "共欣甘入稻，仍喜脆歸蔬。", "歌舞還縈座，盤肴不趁虛。", "放言庸喋喋，引釂願徐徐。", "有客敦農圃，多憂出賦租。", "但教魚菽具，何必囷倉餘。", "來卷千鍾盡，歸乘萬竅呼。", "御風非數數，愛酒亦如如。"]'),
('e85240ca-d2df-46ed-af5e-3c36bf09287f','小飲武夷道士吳之奇竹坡兼示章副觀','胡寅','宋','宋诗','song-poetry','','[]','福地今身到，玄天舊迹非。',48,'全唐诗/poet.song.109000.json','["福地今身到，玄天舊迹非。", "溪聲寧有謂，山意了無機。", "儼立千雲纛，同來二羽衣。", "酒新良可飲，棋妙不須圍。"]'),
('66c15de3-e6bf-4b95-a5e7-972c8acc6a54','遊武夷贈劉生','胡寅','宋','宋诗','song-poetry','','[]','六曲睎真館，千松奪秀亭。',48,'全唐诗/poet.song.109000.json','["六曲睎真館，千松奪秀亭。", "回橈失相值，載酒約重經。", "小雨裝圖畫，紅塵隔杳冥。", "更煩橫鐵笛，吹與衆仙聆。"]'),
('fe0f684a-2ceb-4166-9a67-e6cdc7ba000f','十二月二十一日見雪於籍溪','胡寅','宋','宋诗','song-poetry','','[]','何事團爐一笑譁，窮冬纔許見瓊花。',64,'全唐诗/poet.song.109000.json','["何事團爐一笑譁，窮冬纔許見瓊花。", "細論剪刻誰能解，欲鬭輕明豈易加。", "且共落梅紛沼鑑，未須融玉掛簷牙。", "知君素有陽春句，可但梁園著賦夸。"]'),
('15e0d643-8416-4533-971e-f8eb69077aab','謝道醇見和','胡寅','宋','宋诗','song-poetry','','[]','畏隹于喁處處譁，先春吹出萬林花。',64,'全唐诗/poet.song.109000.json','["畏隹于喁處處譁，先春吹出萬林花。", "要看臘瑞三番白，寧許霜威十倍加。", "瓦隴未平俄淅瀝，冰池難合漫槎牙。", "若嫌吾土山川暖，蜀客相逢尚可夸。"]'),
('abe63f6a-a2d1-4a1e-bc21-f3274e1a3f01','二十七日立春夜雪高下盡白閩中所謂大雪也','胡寅','宋','宋诗','song-poetry','','[]','曉來兒女共諠譁，喜見東風颺水花。',64,'全唐诗/poet.song.109000.json','["曉來兒女共諠譁，喜見東風颺水花。", "鶴羽賜衣方一襲，小巔冠玉已三加。", "高眠有客關蓬戶，低唱無人拍翠牙。", "白帝出遊應最樂，月旌蜺旆正豪夸。"]'),
('3b737131-3833-4884-842c-69efa7548724','二十八日快晴','胡寅','宋','宋诗','song-poetry','','[]','陰機誰使弄譁譁，摽彼無梅漫有花。',64,'全唐诗/poet.song.109000.json','["陰機誰使弄譁譁，摽彼無梅漫有花。", "銀海夜潮猶未落，火輪朝馭早相加。", "應慚餘潤歸麰麥，未怯隆寒戰齒牙。", "莫笑鬢毛輕點綴，龍鍾姦黠兩矜夸。"]'),
('247ddeeb-55e6-47ce-8bae-4964fc7333bc','讀禮至五十始衰有感示彥沖','胡寅','宋','宋诗','song-poetry','','[]','虛齋永晝玩陳編，千古昭昭尚有傳。',64,'全唐诗/poet.song.109000.json','["虛齋永晝玩陳編，千古昭昭尚有傳。", "昨夢飽經全盛日，此生俄歎始衰年。", "不須把鏡刪鬚雪，且願疏封拓酒泉。", "咫尺劉郎住仙境，桃溪應許刺魚船。"]'),
('c1ee1109-72aa-4f93-90fe-0ed71954277b','和仲固','胡寅','宋','宋诗','song-poetry','','[]','多謝春風吹雨晴，出遨今日計初程。',64,'全唐诗/poet.song.109000.json','["多謝春風吹雨晴，出遨今日計初程。", "去隨碧澗䙰褷上，歸與閒雲澹沱行。", "順理以觀皆有趣，會心之樂最難名。", "山間桃柳寧知此，斂笑舒顰亦自情。"]'),
('994a5598-55a1-4eca-9782-b1d300982e5e','春日幽居示仲固彥沖十絕  其一','胡寅','宋','宋诗','song-poetry','','[]','映空微雨不成絲，約勒桃花欲動時。',32,'全唐诗/poet.song.109000.json','["映空微雨不成絲，約勒桃花欲動時。", "爭奈東風有情思，曉紅輕笑竹邊枝。"]'),
('6857180f-9486-455d-9c73-0a6756417c94','春日幽居示仲固彥沖十絕  其二','胡寅','宋','宋诗','song-poetry','','[]','碧沙承水漾嬌春，弱柳縈烟作淺顰。',32,'全唐诗/poet.song.109000.json','["碧沙承水漾嬌春，弱柳縈烟作淺顰。", "正好追尋沂上侶，未須攀贈灞橋人。"]'),
('d9b3ad43-37fc-4e34-9cd6-92b0a706dd5b','春日幽居示仲固彥沖十絕  其三','胡寅','宋','宋诗','song-poetry','','[]','殘梅昨日尚盈盈，一夜溪橋風雨聲。',32,'全唐诗/poet.song.109000.json','["殘梅昨日尚盈盈，一夜溪橋風雨聲。", "不是微酸注香蒂，箇中幽恨即難平。"]'),
('28ee59f3-498f-4d7f-aa0e-18f56856fc72','春日幽居示仲固彥沖十絕  其四','胡寅','宋','宋诗','song-poetry','','[]','人日春愁連上元，薄寒吹雨罩花村。',32,'全唐诗/poet.song.109000.json','["人日春愁連上元，薄寒吹雨罩花村。", "傳柑說道昇平復，夢斷鼇燈放五門。"]'),
('77004ea0-31cb-4ad6-88c9-0dccf23eeb48','春日幽居示仲固彥沖十絕  其五','胡寅','宋','宋诗','song-poetry','','[]','微茫烟溆見人家，四合青山雨遍遮。',32,'全唐诗/poet.song.109000.json','["微茫烟溆見人家，四合青山雨遍遮。", "畫出江鄉二三月，河豚安得配蘆芽。"]'),
('f9530acc-6bde-41ec-861f-f7140fdd9481','春日幽居示仲固彥沖十絕  其六','胡寅','宋','宋诗','song-poetry','','[]','花事先從桃李來，海棠紅杏即相催。',32,'全唐诗/poet.song.109000.json','["花事先從桃李來，海棠紅杏即相催。", "化工節度重重好，護得山丹最後開。"]'),
('5a307664-4251-4e95-a421-c1cd3eda6b6a','春日幽居示仲固彥沖十絕  其七','胡寅','宋','宋诗','song-poetry','','[]','紅含宿雨兩三枝，浄插銅瓶浥注之。',32,'全唐诗/poet.song.109000.json','["紅含宿雨兩三枝，浄插銅瓶浥注之。", "不是靈芸初一見，也非迷路武陵時。"]'),
('cda3591a-a065-465b-ba1e-e3eab5dec4d3','春日幽居示仲固彥沖十絕  其八','胡寅','宋','宋诗','song-poetry','','[]','晚菘爭上碧瑶簪，芥也芳心苦復甘。',32,'全唐诗/poet.song.109000.json','["晚菘爭上碧瑶簪，芥也芳心苦復甘。", "未見菜頭論白黑，何人携鉢肯同參。"]'),
('c1d5e599-8e0a-42e8-9b03-e904b7d16d4d','春日幽居示仲固彥沖十絕  其九','胡寅','宋','宋诗','song-poetry','','[]','菊本離離趁雨栽，杞根成壠更深培。',32,'全唐诗/poet.song.109000.json','["菊本離離趁雨栽，杞根成壠更深培。", "詩人自古無供給，倘有敲門載酒來。"]'),
('920bef50-0cbf-4ff5-a25f-8e4d441a73de','春日幽居示仲固彥沖十絕  其一○','胡寅','宋','宋诗','song-poetry','','[]','染溪曾是竹千竿，歲久生鱗化碧灘。',32,'全唐诗/poet.song.109000.json','["染溪曾是竹千竿，歲久生鱗化碧灘。", "頼有龍孫振根撥，且須深蟄捍濤瀾。"]'),
('dc7948cc-4449-4213-b345-726a231d8129','和仲固春日村居即事十二絕  其一','胡寅','宋','宋诗','song-poetry','','[]','臨流負巘百年居，手植松楠合抱株。',32,'全唐诗/poet.song.109000.json','["臨流負巘百年居，手植松楠合抱株。", "傳寫春光入詩句，味之如對輞川圖。"]'),
('1a45178f-ce47-4f13-8b60-7609925d560f','和仲固春日村居即事十二絕  其二','胡寅','宋','宋诗','song-poetry','','[]','有興相尋即扣門，不須招致簡書繁。',32,'全唐诗/poet.song.109000.json','["有興相尋即扣門，不須招致簡書繁。", "試從大雅歌鶑谷，未羨詞人侈兔園。"]'),
('7110eefa-3591-46ef-aee8-5d91e07e324d','和仲固春日村居即事十二絕  其三','胡寅','宋','宋诗','song-poetry','','[]','欲駐長春學道家，如何白雪是黄芽。',32,'全唐诗/poet.song.109000.json','["欲駐長春學道家，如何白雪是黄芽。", "聊憑高士五株柳，爲問仙人三朶花。"]'),
('8d907d54-f8ac-4668-ab54-b0a954923c9c','和仲固春日村居即事十二絕  其四','胡寅','宋','宋诗','song-poetry','','[]','舊花一一斬新春，慰薦經行自在身。',32,'全唐诗/poet.song.109000.json','["舊花一一斬新春，慰薦經行自在身。", "且使緩開常照眼，莫教輕墮恐傷神。"]'),
('977cc5ad-c946-4d92-9811-4bda9dfb824c','和仲固春日村居即事十二絕  其五','胡寅','宋','宋诗','song-poetry','','[]','西園聞道徑封苔，落落髯仙去不回。',32,'全唐诗/poet.song.109000.json','["西園聞道徑封苔，落落髯仙去不回。", "安石中年離索意，吾徒笑口且頻開。"]'),
('c1263a4c-a85a-40b3-a06f-801a80cd1351','和仲固春日村居即事十二絕  其六','胡寅','宋','宋诗','song-poetry','','[]','春半曾無决定晴，今朝初上九天明。',32,'全唐诗/poet.song.109000.json','["春半曾無决定晴，今朝初上九天明。", "檻花莞爾窺人意，林鳥嚶然求友聲。"]'),
('23233cc9-5299-4501-96bd-590d4dbf79e2','和仲固春日村居即事十二絕  其七','胡寅','宋','宋诗','song-poetry','','[]','陶公春日事西疇，不是同羣沮溺流。',32,'全唐诗/poet.song.109000.json','["陶公春日事西疇，不是同羣沮溺流。", "君亦荷鋤貪雨足，誰知幽意在滄洲。"]'),
('211bda47-0e0f-48d2-82f3-6df422ea7eba','和仲固春日村居即事十二絕  其八','胡寅','宋','宋诗','song-poetry','','[]','仙居何異武陵溪，泛出殘紅春水肥。',32,'全唐诗/poet.song.109000.json','["仙居何異武陵溪，泛出殘紅春水肥。", "擬欲泝流兼載酒，應容艇子傍苔磯。"]'),
('4d9b0282-02dc-4e26-8309-9c89d5470c65','和仲固春日村居即事十二絕  其九','胡寅','宋','宋诗','song-poetry','','[]','籜龍本是飛天物，養鱉宜充照席珍。',32,'全唐诗/poet.song.109000.json','["籜龍本是飛天物，養鱉宜充照席珍。", "一飯午窗春睡起，羲皇而上更何人。"]'),
('41d9a43b-5eee-4fda-b807-81adefc8a5ef','和仲固春日村居即事十二絕  其一○','胡寅','宋','宋诗','song-poetry','','[]','栽培君子要添丁，護惜龍兒出錦綳。',32,'全唐诗/poet.song.109000.json','["栽培君子要添丁，護惜龍兒出錦綳。", "莫學當年饞太守，直須脫粟伴藜羹。"]'),
('02b87014-d296-4a04-8962-d36a101a1700','和仲固春日村居即事十二絕  其一一','胡寅','宋','宋诗','song-poetry','','[]','正眼如君了了明，未嘗沉醉本來醒。',32,'全唐诗/poet.song.109000.json','["正眼如君了了明，未嘗沉醉本來醒。", "自將周易規兒輩，白馬空傳一藏經。"]'),
('20ef18ee-ced7-4e40-9681-2023458a861c','和仲固春日村居即事十二絕  其一二','胡寅','宋','宋诗','song-poetry','','[]','似聞寂寂带經鋤，老圃何知莫問渠。',32,'全唐诗/poet.song.109000.json','["似聞寂寂带經鋤，老圃何知莫問渠。", "况是漢陰機事息，豈憂芳草翳嘉蔬。"]'),
('8ea1e891-29b4-4860-890e-f5c35483e530','題翁道人竹軒','胡寅','宋','宋诗','song-poetry','','[]','寄語東陽翁道人，開軒種竹意何親。',64,'全唐诗/poet.song.109000.json','["寄語東陽翁道人，開軒種竹意何親。", "經春又看龍孫上，晚歲寧憂鳳食貧。", "風月肯來聊競爽，塵囂不到獨相親。", "何時柱杖敲門去，若比王猷懶更真。"]'),
('ca80f5c7-b55d-43d2-b9e6-afbc3559d03d','題斯行厚親庵世祀閣二首  其一','胡寅','宋','宋诗','song-poetry','','[]','軒冕身猶寄，金貲意不存。',48,'全唐诗/poet.song.109000.json','["軒冕身猶寄，金貲意不存。", "永懷三釜樂，當把一經繙。", "靜室依松柏，清規遺子孫。", "里仁如長者，真使薄夫敦。"]'),
('37081719-33f0-4975-aecb-38cc40bac15b','題斯行厚親庵世祀閣二首  其二','胡寅','宋','宋诗','song-poetry','','[]','不用登臨趣，憑高心重催。',48,'全唐诗/poet.song.109000.json','["不用登臨趣，憑高心重催。", "龐公勤上冢，束晳更循陔。", "羊棗終身慕，莪蒿鞠子哀。", "年年拜寒食，豈但數雲來。"]'),
('46b14cbb-f666-43b8-bb90-a3ab240d26d9','贈李子揚','胡寅','宋','宋诗','song-poetry','','[]','洛社看花各妙年，那知關塞起狼烟。',64,'全唐诗/poet.song.109000.json','["洛社看花各妙年，那知關塞起狼烟。", "舊遊只有山川在，佳政時聞嶺嶠傳。", "對酒鮮歡吾老矣，登高能賦子依然。", "不忘雞黍平生約，更泛瀟湘下水船。"]'),
('5357ae78-92d3-44ec-a078-aea9dd221958','和彥達落梅','胡寅','宋','宋诗','song-poetry','','[]','爲問東風有底忙，吹成疏雪灑林塘。',64,'全唐诗/poet.song.109000.json','["爲問東風有底忙，吹成疏雪灑林塘。", "應知剩馥歸香骨，誰拾殘英試粉粧。", "安得反魂三折臂，漫披能賦九迴腸。", "枝間頼有青青子，不遣行人折過牆。"]'),
('1acb8317-b83a-4607-a310-72d6a2702522','簡奇父','胡寅','宋','宋诗','song-poetry','','[]','累旬不見孫夫子，聞學神農闔戶眠。',64,'全唐诗/poet.song.109000.json','["累旬不見孫夫子，聞學神農闔戶眠。", "藥物諒能收近效，精神應復類癯仙。", "欲趨丈室求高論，恐費華池溉下田。", "指日春風動花柳，也須乘興慕斜川。"]'),
('7a4b7dcf-6a2b-45e0-aec8-3a994a43d34d','從趙廟求菖蒲','胡寅','宋','宋诗','song-poetry','','[]','欲從蒲澗問安期，仙事茫茫不可知。',64,'全唐诗/poet.song.109000.json','["欲從蒲澗問安期，仙事茫茫不可知。", "何許寸根仍穊節，解教霜鬢却青絲。", "風流公子茝蘭伴，憔悴騷人香草詩。", "乞取蕭踈映窗几，蒼然常揖歲寒姿。"]'),
('5d25ec74-6d9a-468a-9bf9-306729cbf26b','和趙榮州','胡寅','宋','宋诗','song-poetry','','[]','兵戎暌隔幾春秋，又向南州話北州。',64,'全唐诗/poet.song.109000.json','["兵戎暌隔幾春秋，又向南州話北州。", "一飯識君塵外趣，三川回首夢中游。", "可堪麗藻相華寵，自斷沉疴合罷休。", "安得卜隣如二老，杖藜來往亦風流。"]'),
('818f5fbe-7a10-44bf-a1d7-1a8e938d51f5','和奇父二首  其一','胡寅','宋','宋诗','song-poetry','','[]','示病維摩體暫癯，習閒中散禮誠疏。',64,'全唐诗/poet.song.109000.json','["示病維摩體暫癯，習閒中散禮誠疏。", "已知道義能相與，故使情交得自如。", "前日又欣揮麈尾，何時重見命巾車。", "棲遲甘就衡門下，不見龍章卧草廬。"]'),
('995d5a5d-f89c-4f11-a723-7dbd3f8cfc4d','和奇父二首  其二','胡寅','宋','宋诗','song-poetry','','[]','丈室虛明了不扃，寸田蕪廢正須耕。',64,'全唐诗/poet.song.109000.json','["丈室虛明了不扃，寸田蕪廢正須耕。", "容顔半歎年華改，品目猶煩月旦評。", "洗礪子荆真可慕，中庸伯始竟何成。", "且將禮節規兒輩，不止文書記姓名。"]'),
('e0681f2a-72f7-4099-9dcc-157aa535d87b','和洪秀才八首  其一','胡寅','宋','宋诗','song-poetry','','[]','杖策紛紛是，誰能志大猷。',48,'全唐诗/poet.song.109000.json','["杖策紛紛是，誰能志大猷。", "觕衣與糲飯，長夏及清秋。", "辯論輕三耳，齋明見兩眸。", "聖門多要妙，文藝不須游。"]'),
('f344313e-a5d0-4f79-8f0a-acfb2b9fff7a','和洪秀才八首  其二','胡寅','宋','宋诗','song-poetry','','[]','自昔超羣者，無非遠大猷。',48,'全唐诗/poet.song.109000.json','["自昔超羣者，無非遠大猷。", "要令心似鏡，莫遣氣橫秋。", "末學多牆面，深窺異瞽眸。", "君看顔氏子，何以過商游。"]'),
('78c13b03-6c4a-41c3-bff8-12d37a97450f','和洪秀才八首  其三','胡寅','宋','宋诗','song-poetry','','[]','愛酒希元亮，敲門重子猷。',48,'全唐诗/poet.song.109000.json','["愛酒希元亮，敲門重子猷。", "孤松將秀嶺，萬竹已摇秋。", "懶去手搔髮，興來書映眸。", "此生當皎皎，毋作夢中游。"]'),
('db47e348-ed1f-46af-b8ca-2436ae3c3fc4','和洪秀才八首  其四','胡寅','宋','宋诗','song-poetry','','[]','于今聞議論，自昔際風猷。',48,'全唐诗/poet.song.109000.json','["于今聞議論，自昔際風猷。", "勁柏君凌雪，衰蒲我望秋。", "讀書欽滿腹，歌舞倦回眸。", "豈但人稱善，無慚馬少游。"]'),
('4900bfa1-f6cf-422f-8cdf-439603fcce46','和洪秀才八首  其五','胡寅','宋','宋诗','song-poetry','','[]','栽花爲事業，種秫是謀猷。',48,'全唐诗/poet.song.109000.json','["栽花爲事業，種秫是謀猷。", "不羨兩蝸角，從教雙鬢秋。", "登樓山抹黛，垂釣水澄眸。", "此樂應誰侶，雩風昔從游。"]'),
('b9dd887f-b52b-42c7-9b08-73c529991c66','和洪秀才八首  其六','胡寅','宋','宋诗','song-poetry','','[]','鄙人聞道晚，何以播芳猷。',48,'全唐诗/poet.song.109000.json','["鄙人聞道晚，何以播芳猷。", "未就三年刻，還驚一葉秋。", "論交無白足，對客有青眸。", "之子懷仙趣，相期汗漫游。"]'),
('06586b7c-d2a5-4626-9aec-184658e848ba','和洪秀才八首  其七','胡寅','宋','宋诗','song-poetry','','[]','有煩推後覺，未克繼先猷。',48,'全唐诗/poet.song.109000.json','["有煩推後覺，未克繼先猷。", "痼疾資醫緩，心專慕弈秋。", "遠遊方策足，參倚在凝眸。", "更仗磋磨力，時時警惰游。"]'),
('4625d3b6-620a-499e-9538-fbad75bafa85','和洪秀才八首  其八','胡寅','宋','宋诗','song-poetry','','[]','聞說頻頻黨，深遵秩秩猷。',48,'全唐诗/poet.song.109000.json','["聞說頻頻黨，深遵秩秩猷。", "題評歸月旦，裁鑑比陽秋。", "賦謝雕蟲手，詩通美盼眸。", "看君多直諒，端似漢朱游。"]'),
('520d7211-5060-4e98-a361-e59eabc49e1f','示法輪長老','胡寅','宋','宋诗','song-poetry','','[]','人間膏火日烹煎，塵外光陰可判年。',64,'全唐诗/poet.song.109000.json','["人間膏火日烹煎，塵外光陰可判年。", "路轉峯回能幾許，鳥啼花發故依然。", "同遊多病空携酒，相對忘機不話禪。", "請撤溪橋休送客，却須多種遠公蓮。"]'),
('157b84e2-7683-4386-860e-f98b118121de','題樟源嶺下老嫗井欄嫗百五歲','胡寅','宋','宋诗','song-poetry','','[]','嘻嘻呀呀三伏中，投鞭拭汗一畝宮。',64,'全唐诗/poet.song.109000.json','["嘻嘻呀呀三伏中，投鞭拭汗一畝宮。", "銅瓶擊深響鞺鞳，翠綆引重聲璫東。", "雪花下咽肌骨醒，風腋泛駕仙靈通。", "百年老嫗羽化久，名與甘井垂無窮。"]'),
('b90a73d9-d067-4f6d-b17b-49d4c7fdb164','和楊秀才二首  其一','胡寅','宋','宋诗','song-poetry','','[]','林下何所樂，放懷天地中。',48,'全唐诗/poet.song.109000.json','["林下何所樂，放懷天地中。", "青山供客眼，明月與君同。", "靜聽蕉窗雨，閒披芰沼風。", "未忘蒿目意，時一夢周公。"]'),
('734f16d3-e31b-4782-b852-0233e21342b3','和楊秀才二首  其二','胡寅','宋','宋诗','song-poetry','','[]','林下何所樂，遊心書史中。',48,'全唐诗/poet.song.109000.json','["林下何所樂，遊心書史中。", "時窺言語外，默想聖賢同。", "沂水有餘詠，舞雩多好風。", "區區守一介，未肯易三公。"]'),
('6c252184-90f4-4c71-a323-16fcfa1015f0','和仁仲','胡寅','宋','宋诗','song-poetry','','[]','岩壑風烟可寫憂，千竿筠玉凈脩脩。',64,'全唐诗/poet.song.109000.json','["岩壑風烟可寫憂，千竿筠玉凈脩脩。", "弟兄無故兼三樂，杯斚相歡第一秋。", "豈似墨卿夸楚澤，最宜從事到青州。", "胸中固自春風在，小試安能學太丘。"]'),
('2dbdd4fc-79bb-40b7-a910-bffa1e05735b','示延平日者','胡寅','宋','宋诗','song-poetry','','[]','萬物森然播大鈞，一言鈎訣妙通神。',64,'全唐诗/poet.song.109000.json','["萬物森然播大鈞，一言鈎訣妙通神。", "捲簾與客談忠孝，袖手觀時任屈伸。", "燕石勒名應有日，凌烟圖像果何人。", "且從冠蓋林中看，莫滯天涯與水濱。"]'),
('d06fb1ad-147d-4294-9e39-aeed6211a34f','紹興壬子六月先公再被掖垣之命某時侍行自清江登舟經祖印江口趨行在所未幾罷歸還憩豐城之龍澤寺明年初夏歸隠南山己巳歲予偶遊祖印留宿寺僧惠嵩能道昔寓龍澤之梗概兩寺相望蓋五十里時先公沒十有二年矣予亦衰病投紱俯仰悲慨因成兩詩以遺嵩  其一','胡寅','宋','宋诗','song-poetry','','[]','雲歸龍澤寺，風引墨池船。',48,'全唐诗/poet.song.109000.json','["雲歸龍澤寺，風引墨池船。", "誰識行藏妙，空驚歲序遷。", "從行矜壯齒，撫事嘆華顛。", "約略人間世，耆僧亦憮然。"]'),
('d948e0aa-6228-4b07-9c89-d78489a6d435','紹興壬子六月先公再被掖垣之命某時侍行自清江登舟經祖印江口趨行在所未幾罷歸還憩豐城之龍澤寺明年初夏歸隠南山己巳歲予偶遊祖印留宿寺僧惠嵩能道昔寓龍澤之梗概兩寺相望蓋五十里時先公沒十有二年矣予亦衰病投紱俯仰悲慨因成兩詩以遺嵩  其二','胡寅','宋','宋诗','song-poetry','','[]','車騎紛來去，帆檣競泝沿。',48,'全唐诗/poet.song.109000.json','["車騎紛來去，帆檣競泝沿。", "雲閒天淡淡，江靜竹娟娟。", "恥學飛騰術，慵參寂滅禪。", "春風常滿意，無處不怡然。"]'),
('bd1dd2a2-b45c-4c99-80cc-192eee6abe8b','宿餘干臨江高寺題清音寺','胡寅','宋','宋诗','song-poetry','','[]','閒身何事有塵勞，憩息欣逢一榻高。',64,'全唐诗/poet.song.109000.json','["閒身何事有塵勞，憩息欣逢一榻高。", "瀼水轉灣如玉玦，曲洲斜抱記檀槽。", "憑欄偶見飛鴻翼，對酒仍持紫蟹螯。", "疇昔未觀東匯澤，片帆聊欲駕洪濤。"]'),
('61bc712b-2781-4ebd-a6dc-f6c49b31747c','題中元觀次黎才翁韻','胡寅','宋','宋诗','song-poetry','','[]','掛了衣冠却問農，幾回欹枕聽晨鐘。',64,'全唐诗/poet.song.109000.json','["掛了衣冠却問農，幾回欹枕聽晨鐘。", "壯懷不與浮雲渺，宿疹猶資大藥功。", "想像濠梁寧有趣，追尋風馭豈無蹤。", "道人要識春臺樂，須向壺公問所從。"]'),
('982682e4-f717-4732-ba1a-a53bfbb266e5','十二月酴醾盛開','胡寅','宋','宋诗','song-poetry','','[]','不虞集霰與飛霜，可但寒梅度暗香。',64,'全唐诗/poet.song.109000.json','["不虞集霰與飛霜，可但寒梅度暗香。", "翠碧重敷秋後葉，玉明爭絢曉來粧。", "應憐高架裊清艷，誰道疎條無妙芳。", "折向清尊沾賸馥，與君冬日對春陽。"]'),
('12f625e0-d8b1-4d21-844e-f4fd338f048e','和仁仲治圃三首  其一','胡寅','宋','宋诗','song-poetry','','[]','扶持嘉樹起條枚，未覺風前齒髮頹。',64,'全唐诗/poet.song.109000.json','["扶持嘉樹起條枚，未覺風前齒髮頹。", "深鑿坐邀千澗水，縱觀如步九層臺。", "雲間秀巘濃還淡，案上陳編闔又開。", "莫似昔賢誇獨樂，與人同處首應回。"]'),
('8711812e-a19c-4042-8d65-6f93a7e3f8f9','和仁仲治圃三首  其二','胡寅','宋','宋诗','song-poetry','','[]','不遣身心同槁灰，化工隨手自量裁。',64,'全唐诗/poet.song.109000.json','["不遣身心同槁灰，化工隨手自量裁。", "一欄仙蘤端倪露，九畹崇蘭次第栽。", "生意可觀那畫得，暗香難覓偶吹來。", "柴門漫說何曾閉，俗駕經過也未猜。"]'),
('89a6f092-6032-4b9e-ade6-8e4ced175762','和仁仲治圃三首  其三','胡寅','宋','宋诗','song-poetry','','[]','憒瞀年來藥漸須，喜君猶自手抄書。',64,'全唐诗/poet.song.109000.json','["憒瞀年來藥漸須，喜君猶自手抄書。", "塵冠固合懸圬壁，羽扇何當出草廬。", "勝景但逢詩發遣，壯懷聊用酒驅除。", "寄身擾擾膠膠者，奇貨從來不可居。"]'),
('28836d13-677f-4a9f-a86b-30ec6a449f75','謫居新昌過黄羆嶺','胡寅','宋','宋诗','song-poetry','','[]','昔年曾作守，旌騎擁山頭。',48,'全唐诗/poet.song.109000.json','["昔年曾作守，旌騎擁山頭。", "省己無遺愛，投荒歷舊遊。", "妻兒相翼衛，風雨漫淹留。", "力學如何驗，仁人乃不憂。"]'),
('8c8d8168-483a-464a-aa4b-0237aca9f061','遊龍山寺六祖故居也','胡寅','宋','宋诗','song-poetry','','[]','范陽盧以仕南遷，卜宅空山不計年。',64,'全唐诗/poet.song.109000.json','["范陽盧以仕南遷，卜宅空山不計年。", "間氣有鍾超象類，美材無匠制方圓。", "誰能判斷風旛話，等是追隨粥飯緣。", "携客同來又同去，浮屠依舊插蒼烟。"]'),
('3becd46c-e947-43f2-a3e2-89712b327432','次劉坦見和','胡寅','宋','宋诗','song-poetry','','[]','君以苛留我罪遷，鄉情相值且忘年。',64,'全唐诗/poet.song.109000.json','["君以苛留我罪遷，鄉情相值且忘年。", "歸心莫共孤雲遠，定性當如皓月圓。", "沂水舞雩方有詠，曹溪尋派即無緣。", "向來策杖經行地，不礙渾如石壁烟。"]'),
('4eb98218-a314-4e33-87aa-ca4a24080cab','喜雨','胡寅','宋','宋诗','song-poetry','','[]','聞說頻年旱，先懷併日憂。',48,'全唐诗/poet.song.109000.json','["聞說頻年旱，先懷併日憂。", "家書不易到，囷米諒難求。", "一雨連三夕，千倉裕九秋。", "若爲知帝力，鼓腹聽蠻謳。"]'),
('59c48833-f0f3-49db-8240-a890dbab779e','治園二首  其一','胡寅','宋','宋诗','song-poetry','','[]','涉圃親鋤草，分畦賸種蔬。',48,'全唐诗/poet.song.109000.json','["涉圃親鋤草，分畦賸種蔬。", "潤通隣沼近，色映野雲虛。", "瘴重難求藥，心閒易看書。", "但令羹有梜，那嘆食無魚。"]'),
('aeae466e-f776-4eb6-b7bc-500eb7bf4d10','治園二首  其二','胡寅','宋','宋诗','song-poetry','','[]','萊菔瑶英體，蕪菁翠羽叢。',48,'全唐诗/poet.song.109000.json','["萊菔瑶英體，蕪菁翠羽叢。", "壓黄千葉韭，競秀一畦葱。", "渰渰金莖露，翻翻玉宇風。", "不忘藏聚力，醯醤有無同。"]'),
('c0a64ad1-9953-43c8-904d-dcb105899632','喜義卿得子端倅攝新守','胡寅','宋','宋诗','song-poetry','','[]','喜樂民宜甚，平反笑屢春。',48,'全唐诗/poet.song.109000.json','["喜樂民宜甚，平反笑屢春。", "故應熊夢協，還見鳳毛新。", "桂籍他年繼，桑弧舊俗因。", "豈無湯餠會，也合到窮賓。"]'),
('eaee7c08-b5b2-41d3-9a91-bf9bf6b43d03','和郡將勸農','胡寅','宋','宋诗','song-poetry','','[]','仁政惟敦本，躬行豈好夸。',48,'全唐诗/poet.song.109000.json','["仁政惟敦本，躬行豈好夸。", "舞停衫颺雪，盤藉綺如霞。", "童馬爭騎竹，村厖息吠花。", "向來觀饁地，和氣滿家家。"]'),
('4687c5f1-88b4-46e6-bc57-b4b3e0bea5d9','酬黄執禮見和','胡寅','宋','宋诗','song-poetry','','[]','聞從軺車出，勤農不務夸。',48,'全唐诗/poet.song.109000.json','["聞從軺車出，勤農不務夸。", "歡謠驅宿霧，飛蓋亂晨霞。", "醉偃風前草，詩裝錦上花。", "也將求二頃，輸稅補公家。"]'),
('6805a825-9398-46c8-86a9-39982215aef6','再美勸農','胡寅','宋','宋诗','song-poetry','','[]','邦本古攸重，民天辭匪夸。',48,'全唐诗/poet.song.109000.json','["邦本古攸重，民天辭匪夸。", "詎能皆辟穀，漫道獨餐霞。", "一笑爲良繭，力耕無賣花。", "信知豳七月，于耜起周家。"]'),
('6d0b35a3-710a-403d-8f8a-208042f3055b','觀諸人唱和','胡寅','宋','宋诗','song-poetry','','[]','五言雖窘步，才力競雄夸。',48,'全唐诗/poet.song.109000.json','["五言雖窘步，才力競雄夸。", "壑聳千章木，霄霏五色霞。", "聲諧金擲地，夢到筆生花。", "豈謂明珠貫，清輝照蔀家。"]'),
('c3894b38-84dc-43ed-813d-c95e4dab1585','和王維三首  其一','胡寅','宋','宋诗','song-poetry','','[]','老矣雞栖愛一廛，生涯隨分不求全。',32,'全唐诗/poet.song.109000.json','["老矣雞栖愛一廛，生涯隨分不求全。", "一杯那復思身後，三爵聊將補食前。"]'),
('55aa8e40-ff4e-4689-8864-952535715179','和王維三首  其二','胡寅','宋','宋诗','song-poetry','','[]','素不能詩復戒吟，辱君笙鶴墮清音。',32,'全唐诗/poet.song.109000.json','["素不能詩復戒吟，辱君笙鶴墮清音。", "何須風月三千首，已洗塵埃一寸心。"]'),
('41475b28-741a-4020-a7ad-90581a00757c','和王維三首  其三','胡寅','宋','宋诗','song-poetry','','[]','蓬門相直是南山，傍著丹梯尚可攀。',32,'全唐诗/poet.song.109000.json','["蓬門相直是南山，傍著丹梯尚可攀。", "野興舊同流水遠，道心今共白雲閒。"]'),
('d53f1340-a057-4828-88e3-2777b9191166','和黄執禮六首  其一','胡寅','宋','宋诗','song-poetry','','[]','稅得東家一畝宮，向來喧市馬牛風。',64,'全唐诗/poet.song.109000.json','["稅得東家一畝宮，向來喧市馬牛風。", "誓將尤悔加深省，肯爲饑寒嘆屢空。", "十里溪山愁眼外，數家梧竹畫屏中。", "惠然更感無雙子，時有高談發蔽蒙。"]'),
('14139667-289f-4af9-93a2-5fd581ef0e4b','和黄執禮六首  其二','胡寅','宋','宋诗','song-poetry','','[]','賜牆那及仲尼宮，妄意堅高立下風。',64,'全唐诗/poet.song.109000.json','["賜牆那及仲尼宮，妄意堅高立下風。", "志士有求雖汲汲，鄙夫無得漫空空。", "詩鳴寡學安能善，酒聖多愁詎敢中。", "惟頼有朋想博約，過情之譽豈宜蒙。"]'),
('7165ad8c-db7f-4c1d-8314-2918a618646b','和黄執禮六首  其三','胡寅','宋','宋诗','song-poetry','','[]','浮生均是大槐宮，永日聊便竹簟風。',64,'全唐诗/poet.song.109000.json','["浮生均是大槐宮，永日聊便竹簟風。", "若要語言求要妙，猶將筆墨畫虛空。", "一區聊寄塵囂外，萬景皆歸眺望中。", "敢似越雞孵鵠卵，正慚雲將問鴻蒙。"]'),
('dcb773f1-5431-48ea-b0b4-c115a262033a','和黄執禮六首  其四','胡寅','宋','宋诗','song-poetry','','[]','律呂旋相六十宮，聲如佳句比南風。',64,'全唐诗/poet.song.109000.json','["律呂旋相六十宮，聲如佳句比南風。", "自非詩印全提得，難使言瑕一洗空。", "已向襟靈窺致遠，更從彪炳見弸中。", "讀書有益非虛語，請看孫權與阿蒙。"]'),
('d9e4f19c-642b-4d43-b700-493a056b87bf','和黄執禮六首  其五','胡寅','宋','宋诗','song-poetry','','[]','尚德南宮勇北宮，羨君兼有古人風。',64,'全唐诗/poet.song.109000.json','["尚德南宮勇北宮，羨君兼有古人風。", "無雙自昔稱江夏，第一于今鄙解空。", "會友更求三以上，策名應簉二之中。", "須慚纇語賡黄絹，但可厨人作醤蒙。"]'),
('a137c828-b8f8-4175-a2c1-041d06a4cd0b','和黄執禮六首  其六','胡寅','宋','宋诗','song-poetry','','[]','文才久合步蟾宮，未肯爭摶九萬風。',64,'全唐诗/poet.song.109000.json','["文才久合步蟾宮，未肯爭摶九萬風。", "賸欲論詩宗典樂，故應憐我隸司空。", "高山宛在綠琴裏，白髮從多清鏡中。", "要識起予真賞意，聖門千古望龜蒙。"]'),
('f272bb44-89ba-43ff-a5a0-991977e70741','送茶與執禮以詩來謝和之','胡寅','宋','宋诗','song-poetry','','[]','簞瓢曾不飽顔回，何事新茶轉海來。',64,'全唐诗/poet.song.109000.json','["簞瓢曾不飽顔回，何事新茶轉海來。", "八餠尚懷經幄賜，一苞聊對嶺雲開。", "分君要使澆書腹，待客應須罷酒罍。", "自笑玉川空兩腋，清風無夢到蓬萊。"]'),
('32e5e5e7-5d97-4bc9-ab96-bedb00f9cedd','黄倅生日送茶壽之','胡寅','宋','宋诗','song-poetry','','[]','北苑仙芽紫玉方，年年包篚貢甘香。',32,'全唐诗/poet.song.109000.json','["北苑仙芽紫玉方，年年包篚貢甘香。", "願君飲罷風生腋，飛到蓬萊日月長。"]'),
('f885d7ce-8027-4d2a-a9b3-d72239bb32b8','和李靖','胡寅','宋','宋诗','song-poetry','','[]','三間茅屋陋無人，聊著投荒罪垢身。',64,'全唐诗/poet.song.109000.json','["三間茅屋陋無人，聊著投荒罪垢身。", "此地相逢應有數，他年重見復何因。", "雅騷我豈堪嘉贈，逸足君宜據要津。", "更把一尊當雨霽，坐看冰鑑拓秋旻。"]'),
('6ae2c7b6-d4c5-4ddb-9214-294a03b866ab','寄題趙化州清白亭','胡寅','宋','宋诗','song-poetry','','[]','聞話維城刺史尊，關西夫子是師門。',64,'全唐诗/poet.song.109000.json','["聞話維城刺史尊，關西夫子是師門。", "太清不取班超論，堅白寧同惠子言。", "棐几蕭然心似寄，銀鈎精甚勢如鶱。", "政成歸報蘧廬子，常使甘棠庇本根。"]'),
('afc45884-c292-4e40-8c49-f4055e7b1ac2','和黄倅祈求有應','胡寅','宋','宋诗','song-poetry','','[]','海山和氣四時連，太守賓僚自十仙。',64,'全唐诗/poet.song.109000.json','["海山和氣四時連，太守賓僚自十仙。", "明恕而行非苟爾，感通之效固昭然。", "萌心甘澤雲從地，舉意晴暘日麗天。", "可但南冠瓶有粟，家家酣詠太平年。"]'),
('0a6f10af-0ae7-47b1-b62a-aafb97b5f54f','又和錦阜登高','胡寅','宋','宋诗','song-poetry','','[]','久廢危亭也待時，俄然榱棟出鎡基。',64,'全唐诗/poet.song.109000.json','["久廢危亭也待時，俄然榱棟出鎡基。", "已應氣象軒城表，更覺登臨冠海湄。", "萬里秋風宜落帽，四并高會稱傳巵。", "幽人但把東籬菊，坐看南山久未移。"]'),
('cf47a7e2-797e-495d-8117-c4bc08bbf5c5','再和前韻本欲創亭以穫時而止','胡寅','宋','宋诗','song-poetry','','[]','不因修築廢農時，欲以仁心翊化基。',64,'全唐诗/poet.song.109000.json','["不因修築廢農時，欲以仁心翊化基。", "野草從來豐可藉，量陂元自渺無湄。", "登臨有愜三檛鼓，衰病多慚一斗巵。", "獨喜高秋對黄菊，風吹烏帽看雲移。"]'),
('06568a22-5e0b-4995-9471-87e01c04bf2c','和陳生三首  其一','胡寅','宋','宋诗','song-poetry','','[]','此道存亡仁不仁，遺編所載豈其真。',64,'全唐诗/poet.song.109000.json','["此道存亡仁不仁，遺編所載豈其真。", "若非象外冥心契，寧向環中得意新。", "玉麈有文堪悟道，錦囊無句不藏春。", "簞瓢倘可分留客，更欲聞君一語親。"]'),
('6afe4ce6-0a40-43dc-b0cd-534d93cc4c29','和陳生三首  其二','胡寅','宋','宋诗','song-poetry','','[]','車塵馬足兩紛綸，談叟渾如谷口真。',64,'全唐诗/poet.song.109000.json','["車塵馬足兩紛綸，談叟渾如谷口真。", "閙裏光陰渠不駐，靜中滋味我嘗新。", "高眠展轉三竿日，熟飲頻煩一甕春。", "請看夏畦勞瘁者，歲寒當與子相親。"]'),
('a84b5f07-2343-4cbb-9789-5d0c58121a47','和陳生三首  其三','胡寅','宋','宋诗','song-poetry','','[]','掛却衣冠把釣綸，那知藏拙未全真。',64,'全唐诗/poet.song.109000.json','["掛却衣冠把釣綸，那知藏拙未全真。", "餘生意態無相顧，未死工夫有自新。", "弦絕誰傳流水曲，瑟希曾對舞雩春。", "晚交况得陳丘子，不但波瀾子建親。"]'),
('8f8d1b01-f9c0-49b2-aa0f-93379b8e7ca2','示程生二首  其一','胡寅','宋','宋诗','song-poetry','','[]','利域名途較少多，人生那用學燈蛾。',64,'全唐诗/poet.song.109000.json','["利域名途較少多，人生那用學燈蛾。", "如君甘作長貧士，視古寧慚獨行科。", "雀可羅時煩寵顧，鳶嘗跕處重經過。", "扁舟又指閩山隠，奈此蒼凉別意何。"]'),
('ad0d1ddf-5928-4d1f-9386-4be787c49358','示程生二首  其二','胡寅','宋','宋诗','song-poetry','','[]','柴桑風度極清真，地位當齊古逸民。',64,'全唐诗/poet.song.109000.json','["柴桑風度極清真，地位當齊古逸民。", "不爲兒曹營飽暖，聊將詩句寫經綸。", "喜君自得超遥趣，與世相忘寂寞濱。", "正欲細論嗟遽別，空慙祖謝響然臻。"]'),
('1ca80511-202f-40c9-9a98-0196b6fad105','和單普二首  其一','胡寅','宋','宋诗','song-poetry','','[]','能向詞江挹彼清，愛君詩句早知名。',64,'全唐诗/poet.song.109000.json','["能向詞江挹彼清，愛君詩句早知名。", "百家懸鏡知妍醜，一字提衡有重輕。", "畫話豈淹三友益，簡才方廓四聰明。", "肯臨蔀屋相輝映，自愧常談只老生。"]'),
('1590c1cb-ff96-4681-bdc8-cba75915cf1b','和單普二首  其二','胡寅','宋','宋诗','song-poetry','','[]','棄捐孤陋與誰隣，插棘誅茅漫隠淪。',64,'全唐诗/poet.song.109000.json','["棄捐孤陋與誰隣，插棘誅茅漫隠淪。", "亂思詩書隨手揭，慰懷風月逐時新。", "慚無用舍行藏道，有愧東西南北人。", "久矣筆端塵土暗，因君聊復擬心神。"]'),
('f41ea81e-a34e-4675-a564-77196fb5d4b6','謝朱推梅栽','胡寅','宋','宋诗','song-poetry','','[]','南國雖云有學堂，了無松菊徑徒荒。',64,'全唐诗/poet.song.109000.json','["南國雖云有學堂，了無松菊徑徒荒。", "瘴痕元愛冰花洗，衰鬢聊依玉樹芳。", "便覺小池招秀影，更令寒月映新粧。", "從今賸醖萸香酒，指擬春風摘子嘗。"]'),
('719d8b60-78e4-4b0f-8f3d-4a526f06f766','示臨川曾革','胡寅','宋','宋诗','song-poetry','','[]','闕里三千盛，參乎一唯優。',168,'全唐诗/poet.song.109000.json','["闕里三千盛，參乎一唯優。", "古來宗德業，誰復繼風猷。", "晚派南豐衍，賢名內相尤。", "高文推大手，奧學擅前修。", "有美清江彥，胡爲瘴嶺陬。", "宗盟標姓望，海若富源流。", "侯館甘魚食，賓筵聽鹿呦。", "會須題雁塔，聊爾敝貂裘。", "美玉宜深韞，明珠謝暗投。", "自嗟鳶跕墮，空羨鶴夷猶。", "三釜古云樂，一簞今漫憂。", "但令心了了，那畏力仇仇。", "繫馬竹雲凈，飛觴梅雪稠。", "愧君相屬厚，弱水詎勝舟。"]'),
('7d12ccc7-a3b1-48fe-ab5f-1e79b344b228','寄陳生','胡寅','宋','宋诗','song-poetry','','[]','窮冬纔得雨梢梢，梅已無餘柳漸包。',64,'全唐诗/poet.song.109000.json','["窮冬纔得雨梢梢，梅已無餘柳漸包。", "且把簡編遮病眼，時拖衾絮擁寒骹。", "譏訶駁雜懷張籍，聯續詩章憶孟郊。", "歸卧蕭齋諒安穩，可無消息到衡茅。"]'),
('a320b270-1605-4873-9f90-cfc40991794c','謝趙戎惠白菘甚腴且再求之','胡寅','宋','宋诗','song-poetry','','[]','已是居無竹，那堪食一簞。',48,'全唐诗/poet.song.109000.json','["已是居無竹，那堪食一簞。", "煩君餉園茹，使我助盤餐。", "秀色春風早，甘肥曉露漙。", "美材今又闕，小摘更相寬。"]'),
('1d82a420-71ac-4e3a-9f6d-bd598280a21e','送黄熙赴韶推','胡寅','宋','宋诗','song-poetry','','[]','籯金不取義方嚴，孝友家庭嶺海瞻。',64,'全唐诗/poet.song.109000.json','["籯金不取義方嚴，孝友家庭嶺海瞻。", "力古共推經笥富，决科爭看筆鋒銛。", "才非俗契心難展，清畏人知德尚潛。", "鵬翼垂天終九萬，固應鳬舄未能淹。"]'),
('aba35895-7dac-4c2c-9a71-6f697d620f01','送黄權守歸八桂三首  其一','胡寅','宋','宋诗','song-poetry','','[]','展驥官良是，憑熊職未專。',48,'全唐诗/poet.song.109000.json','["展驥官良是，憑熊職未專。", "中和已成頌，清浄豈無傳。", "樓雘環新堞，丁黄溢舊編。", "聖朝方考績，華寵定頒宣。"]'),
('74d05f0d-e49c-4717-af18-7c46e4ac5572','送黄權守歸八桂三首  其二','胡寅','宋','宋诗','song-poetry','','[]','樂物羈栖伴，筋骸放逐餘。',48,'全唐诗/poet.song.109000.json','["樂物羈栖伴，筋骸放逐餘。", "自甘門有雀，寧嘆食無魚。", "傾蓋情文腆，投醪笑語舒。", "晚途多感慨，頼此得時祛。"]'),
('76f9f487-d03e-4176-9c03-5c9649f18c1a','送黄權守歸八桂三首  其三','胡寅','宋','宋诗','song-poetry','','[]','雨岸溪紋蹙，風亭柳带縈。',48,'全唐诗/poet.song.109000.json','["雨岸溪紋蹙，風亭柳带縈。", "借留無上策，送別有兼程。", "望杳雲間旆，班餘野外荆。", "路從簪玉去，增我故山情。"]'),
('0d984434-c403-4402-ae83-328e4cf4f885','迓黄守再來二首  其一','胡寅','宋','宋诗','song-poetry','','[]','舊治重臨寵渥新，聖朝因任慰斯民。',64,'全唐诗/poet.song.109000.json','["舊治重臨寵渥新，聖朝因任慰斯民。", "芾棠不拜陰如幄，騎竹爭迎氣似春。", "金重百斤兼賜爵，車高一丈更施茵。", "能名籍甚宜蒙此，潁水盧溪共演深。"]'),
('0bd8cabe-af64-4d6b-95cb-f79d55d45495','迓黄守再來二首  其二','胡寅','宋','宋诗','song-poetry','','[]','柴扉雖設悄無隣，聽說君來氣又振。',64,'全唐诗/poet.song.109000.json','["柴扉雖設悄無隣，聽說君來氣又振。", "鷗鷺點開愁意思，詩書吟起病精神。", "也知憔悴嫌杯酒，可尚談諧對席珍。", "旌旆悠悠將入眼，爭除三徑待朱輪。"]'),
('869bb678-ffec-4406-b2e4-79b8485d8084','和黄秀才','胡寅','宋','宋诗','song-poetry','','[]','羹藜飯糗自無餘，身世蕭條亦自如。',64,'全唐诗/poet.song.109000.json','["羹藜飯糗自無餘，身世蕭條亦自如。", "十里溪山連枕席，一堂風月伴琴書。", "畹蘭幸襲仙人佩，徑草欣承長者車。", "四海弟兄非浪語，先生何恨九夷居。"]'),
('55d5be38-7b6b-4eed-aff6-b53d0c65b0c6','寒食日約蔡生以雨不至','胡寅','宋','宋诗','song-poetry','','[]','細雨斜風惱弄春，荒郊不見踏青人。',64,'全唐诗/poet.song.109000.json','["細雨斜風惱弄春，荒郊不見踏青人。", "傷心湖外松楸域，弔影天涯露電身。", "楊柳杏花何處好，石泉槐火一時新。", "舉杯幸有君相屬，更待泥乾步屧勻。"]'),
('3396400e-1088-4a05-9ec0-c0f3d5fb02de','謝蔡生見和','胡寅','宋','宋诗','song-poetry','','[]','三分已過二分春，尚想綿田一善人。',64,'全唐诗/poet.song.109000.json','["三分已過二分春，尚想綿田一善人。", "冷食未平千載恨，浮雲何與百年身。", "從教對雨携壺阻，自愛觀風得句新。", "芍藥酴醾無復見，花林芳草翠初勻。"]'),
('dc95a3e4-fa33-4ee6-8499-7f7ca552adb9','二弟在遠經年無書張倩忽來相看蔡生以詩見慶次其韻','胡寅','宋','宋诗','song-poetry','','[]','鴻雁分飛接翼難，稻粱謀隔水雲寒。',64,'全唐诗/poet.song.109000.json','["鴻雁分飛接翼難，稻粱謀隔水雲寒。", "千山路遠勞魂夢，一紙書來强笑歡。", "東榻人材慚潤玉，西崑詩韻勝芳蘭。", "從今更勵男兒操，金鐵爲心石作肝。"]'),
('e81beef8-8562-433a-b898-534fc3da8281','病中有感','胡寅','宋','宋诗','song-poetry','','[]','武侯輔世侔伊尹，明道傳心繼孟軻。',32,'全唐诗/poet.song.109000.json','["武侯輔世侔伊尹，明道傳心繼孟軻。", "五十四年而已矣，小儒如此豈非多。"]'),
('f14efd4d-4622-482e-9452-0dfe3a221684','送英州推官','胡寅','宋','宋诗','song-poetry','','[]','素業平生筆硯交，粗官何事管榜敲。',64,'全唐诗/poet.song.109000.json','["素業平生筆硯交，粗官何事管榜敲。", "自傷放逐生中熱，時對清風解外膠。", "掞藻更窺青玉案，分甘常記綠羅袍。", "扁舟北上英州幕，卜吉應逢泰拔茅。"]'),
('05f18a79-b0c6-449c-b684-29c778120821','和單令','胡寅','宋','宋诗','song-poetry','','[]','炎州暑令比烝炊，茅屋深更未掩扉。',64,'全唐诗/poet.song.109000.json','["炎州暑令比烝炊，茅屋深更未掩扉。", "倦鵲繞林飛又上，流螢照水亂還稀。", "寡尤正爾三緘口，新浴又思一振衣。", "獨怯詩壇把麾將，欲摩堅壘費攻圍。"]'),
('8b921a64-ac0b-4108-8fb1-8b1f207ea980','和周尉遊簡園','胡寅','宋','宋诗','song-poetry','','[]','敝屣稀行故不穿，荒陬何處賞芳妍。',64,'全唐诗/poet.song.109000.json','["敝屣稀行故不穿，荒陬何處賞芳妍。", "詩人邂逅能乘興，野客勤劬便肆筵。", "滿壁畫圖俱儼若，一川風物更蕭然。", "攀翻百樹梨花雪，醉擬春風二月天。"]'),
('540ff78b-1ddc-4ef7-bbc4-1221598ff0b2','簡單令','胡寅','宋','宋诗','song-poetry','','[]','十月絺無斁，中冬木尚榮。',192,'全唐诗/poet.song.109000.json','["十月絺無斁，中冬木尚榮。", "願爲寒玉佩，思灌閬風清。", "之子牛刀暇，尋餘兔徑行。", "已携從事至，旋覺大庖盈。", "荒郡書雲節，虛簷寫雨聲。", "寂寥無一事，浩蕩有閒情。", "草樹環居密，雲山極望平。", "羈愁添繡線，鄉味得金橙。", "獨酌臨空迥，高歌徹晦明。", "醉惟憑曲几，窮不念方兄。", "詩怕吟來拙，書便讀後精。", "紋楸忘勝負，綠綺混虧成。", "忽見江梅蕊，如披瑞雪英。", "旅中相慰薦，箇裏自分明。", "更待塗茨了，仍看藝竹生。", "茅柴如可壓，爲吾糝藜羹。"]'),
('1afe5449-1e97-4344-b7db-3795a43af802','周尉以詩致霅鱠次韻爲謝','胡寅','宋','宋诗','song-poetry','','[]','新興何事憶吳興，因話鱸魚割素鱗。',80,'全唐诗/poet.song.109000.json','["新興何事憶吳興，因話鱸魚割素鱗。", "不是南烹無口實，要看西子授厨人。", "堆盤雪縷開花面，泛艇秋風想釣綸。", "玉醴浮來爲鄉導，金橙研破助芳辛。", "老饕難繼蘇公賦，一飽鮮腴敢更頻。"]'),
('233c36af-bb92-4ea4-b962-ca2245b17a0b','再謝見寄','胡寅','宋','宋诗','song-poetry','','[]','非關糧盡不能興，自嘆車中蹭蹬鱗。',80,'全唐诗/poet.song.109000.json','["非關糧盡不能興，自嘆車中蹭蹬鱗。", "詩客頗能憐逐客，饔人知復受鮫人。", "爲憐飛箸千條玉，不忘牽潭百尺綸。", "腹似鼓鼙無塌處，詩如薑蒜有餘辛。", "閿鄉少府新權爾，爭比周郎美味頻。"]'),
('7f99af13-35f7-44fd-b8a6-b1777b39c388','周尉丹砂次其韻','胡寅','宋','宋诗','song-poetry','','[]','日鑷蒼浪鬢，還童意未賒。',48,'全唐诗/poet.song.109000.json','["日鑷蒼浪鬢，還童意未賒。", "易衰如下阪，難熟似烝砂。", "不信三峯妄，曾聞九轉誇。", "刀圭何太少，薏苡舊盈車。"]'),
('a4c40944-3d8a-444d-8650-336a25bbd2ec','和周尉立春二首  其一','胡寅','宋','宋诗','song-poetry','','[]','筮易欣逢天地交，送殘寒晷石光敲。',64,'全唐诗/poet.song.109000.json','["筮易欣逢天地交，送殘寒晷石光敲。", "化工造物初施手，天仗迎春已在郊。", "一飯及辰堆細菜，千花從此放香苞。", "欲賡妙句無餘味，久矣庖人不治庖。"]'),
('d4d12827-3a1a-4a2b-88e1-4efc31ca575c','和周尉立春二首  其二','胡寅','宋','宋诗','song-poetry','','[]','新年仍復得詩交，和氣排門不待敲。',64,'全唐诗/poet.song.109000.json','["新年仍復得詩交，和氣排門不待敲。", "藏谷寒冰猶北陸，應時甘雨背西郊。", "松筠挺挺浮烟色，桃杏紛紛拆繡苞。", "準擬尋春多酒肆，芳羶何必費良庖。"]'),
('57bcdce0-6184-446e-96f6-b574ec27a33a','用前韻簡單令','胡寅','宋','宋诗','song-poetry','','[]','斑白欣逢子墨交，懸知琴化息榜敲。',64,'全唐诗/poet.song.109000.json','["斑白欣逢子墨交，懸知琴化息榜敲。", "不從凍竽窺侯喜，端向長松倚孟郊。", "竄逐自甘藜不糝，太平還見葦方苞。", "全牛妙割須君手，笑我鉛刀似族庖。"]'),
('c8456c29-a92f-4f3f-a6b9-14545b4810f0','謝周尉用前韻致丹砂且見勸葆真','胡寅','宋','宋诗','song-poetry','','[]','寒衾未暖睫先交，曉漏那聞促點敲。',64,'全唐诗/poet.song.109000.json','["寒衾未暖睫先交，曉漏那聞促點敲。", "非有真丹存下海，詎同和氣滿春郊。", "王弘頗亦知陶令，仲達何勞誚石苞。", "爲報邇來幽意愜，籜龍拳鱉漸充庖。"]'),
('a0f3c492-322a-46f3-8743-647335d04fc6','李簿携具用前韻和之','胡寅','宋','宋诗','song-poetry','','[]','春禽遭凍息交交，不及風箏迭遞敲。',64,'全唐诗/poet.song.109000.json','["春禽遭凍息交交，不及風箏迭遞敲。", "睡起依然開白屋，客來仍是俯青郊。", "方兄無勢寧能熱，窮鬼多羞祗自苞。", "載酒刲羊煩厚意，當年莘野尚烹庖。"]'),
('b1316aec-c7b3-4934-aae7-79b47059dc16','和單令春日','胡寅','宋','宋诗','song-poetry','','[]','新歷自披展，故交誰與歡。',48,'全唐诗/poet.song.109000.json','["新歷自披展，故交誰與歡。", "顔容羞把鏡，菘韭强登盤。", "袖手籠東老，侵肌料峭寒。", "大鈞方播物，吾道豈艱難。"]'),
('bea9b0f5-9d88-4b37-b2c9-deb41da89a50','金沙','胡寅','宋','宋诗','song-poetry','','[]','海棠開後數金沙，誰料炎荒有此花。',64,'全唐诗/poet.song.109000.json','["海棠開後數金沙，誰料炎荒有此花。", "青玉案頭張重錦，碧雲堆裏漏彤霞。", "高枝已寫清尊照，嫩蘂猶須翠幕遮。", "未信東風肯吹謝，且教遊客看繁華。"]'),
('5df94bd7-ca76-4a70-b339-c4a1f9c22531','簡單周二子  其一','胡寅','宋','宋诗','song-poetry','','[]','回首清明遠矣哉，和風還挾禊辰來。',64,'全唐诗/poet.song.109000.json','["回首清明遠矣哉，和風還挾禊辰來。", "麗人空憶行歌樂，曲水難追翰墨才。", "鬢髮飄蕭吾自祓，形骸放蕩孰相開。", "早知勝集荷塘上，何不飛觴看恥罍。"]'),
('6e8cdec8-e74d-46fb-b33e-5dfa5cdd6256','簡單周二子  其二','胡寅','宋','宋诗','song-poetry','','[]','音塵疎闊思悠哉，有底匆匆不我來。',64,'全唐诗/poet.song.109000.json','["音塵疎闊思悠哉，有底匆匆不我來。", "陣合鸛鵝須敵手，詩成珠玉要奇才。", "新荷雨定如蘭馥，曲沼風閒作鏡開。", "况是凉蟾方半璧，清光應欲照金罍。"]'),
('07e346d1-40d7-4652-8b1a-04d9cd8e75b0','簡單令','胡寅','宋','宋诗','song-poetry','','[]','烝炊不奈瘴氛侵，一霎微凉屬晚陰。',64,'全唐诗/poet.song.109000.json','["烝炊不奈瘴氛侵，一霎微凉屬晚陰。", "自軸疎簷掃階砌，却憑安几看雲林。", "風中梧竹旌幢亂，雨外江山水墨深。", "來日小槽篘釃白，眷言騷客肯相臨。"]'),
('1029ce50-ab17-4e15-afa8-0ab8351737c0','楊尉見招朱推單令與焉月色甚佳','胡寅','宋','宋诗','song-poetry','','[]','南郭無緣到北城，却因招喚得同行。',64,'全唐诗/poet.song.109000.json','["南郭無緣到北城，却因招喚得同行。", "四郊禾黍未全熟，滿眼雲山何限情。", "幸有好風能灑袂，况無閒事稱揮觥。", "籃輿欲去留還住，愛此月凉河漢明。"]'),
('72c2aa82-17f0-44d2-af9a-c4e7b85e37d5','七月十八日與諸人集真于燕譽堂','胡寅','宋','宋诗','song-poetry','','[]','盍簪相與記春芳，落去爭如桂影香。',64,'全唐诗/poet.song.109000.json','["盍簪相與記春芳，落去爭如桂影香。", "故覓層臺延曠望，可無尊酒泛寒光。", "交揮玉麈傾懷盡，半仄冰輪耿夜長。", "坐到銀河分曉色，彤霞金暈更蒼凉。"]'),
('2f7d1980-5655-4ab8-bb9a-27a4c23359bc','吳守祈雨有應','胡寅','宋','宋诗','song-poetry','','[]','延陵宿望冠三吳，又見熙朝老大夫。',64,'全唐诗/poet.song.109000.json','["延陵宿望冠三吳，又見熙朝老大夫。", "善政舊聞風偃草，清規今信浦還珠。", "山川每應精神禱，禾稼全憑潤澤蘇。", "可但邦人歌五袴，也知還客慰焦枯。"]'),
('f623236d-1067-4562-addc-b805a58215c0','和單令自龍山迎月而歸','胡寅','宋','宋诗','song-poetry','','[]','招提爐上寶香氳，問信浮屠作祖人。',64,'全唐诗/poet.song.109000.json','["招提爐上寶香氳，問信浮屠作祖人。", "想得妙心同水鏡，故應歸路見冰輪。", "清輝萬里無窮雪，浄觀千山不隔塵。", "欲識新詩惟累句，頗慚曹植與君親。"]'),
('61409b6e-c23f-41cc-bbb1-2fb4b6d09669','重九簡單令','胡寅','宋','宋诗','song-poetry','','[]','殊方令節也堪憐，可詠江涵雁影篇。',64,'全唐诗/poet.song.109000.json','["殊方令節也堪憐，可詠江涵雁影篇。", "買得紫萸虛市裏，種成黄菊小池邊。", "相逢便是華胥國，一醉寧慚玳瑁筵。", "何必登臨追舊俗，南山秋氣自超然。"]'),
('95f35ee1-8845-4219-a208-437f1359bb09','和單令','胡寅','宋','宋诗','song-poetry','','[]','朝雨催寒細似毛，賓鴻带影朔雲高。',64,'全唐诗/poet.song.109000.json','["朝雨催寒細似毛，賓鴻带影朔雲高。", "菊萸不分簪華髮，糕酒無因拜赭袍。", "笑我功名如墮甑，愛君情義比投膠。", "病衰阻趁芙蓉約，木末搴翻獨詠騷。"]'),
('af5fa93f-7e6e-4b9a-9ab0-fc736f02e753','吳守生朝','胡寅','宋','宋诗','song-poetry','','[]','梅信初傳冬未深，高門熊夢慶相尋。',64,'全唐诗/poet.song.109000.json','["梅信初傳冬未深，高門熊夢慶相尋。", "三朝耆舊人皆仰，一德純全衆所欽。", "難老椿齡方演迤，後凋松色正陰森。", "願公常記茱萸釀，每歲茲辰細細斟。"]'),
('3f7ddac6-fb6c-4db2-9520-c49f404d63a4','和蔡生遷居二首蔡學佛故用杜老與贊公故事蔡常令一嫗持簡來  其一','胡寅','宋','宋诗','song-poetry','','[]','浮生何處不蘧廬，且喜飄然乍卜居。',64,'全唐诗/poet.song.109000.json','["浮生何處不蘧廬，且喜飄然乍卜居。", "一室未應忘灑掃，四隣聊復認親疎。", "荔蕉餉客還堪飽，笋蕨登盤莫願餘。", "有意相尋即扶杖，無煩赤足致雙魚。"]'),
('70180bdc-5c48-401e-b659-a7c66ba1dda6','和蔡生遷居二首蔡學佛故用杜老與贊公故事蔡常令一嫗持簡來  其二','胡寅','宋','宋诗','song-poetry','','[]','一壺村酒要同嘗，脯醢葅肴取次將。',64,'全唐诗/poet.song.109000.json','["一壺村酒要同嘗，脯醢葅肴取次將。", "談話翠微修竹徑，追隨斜照晚風岡。", "梅花淡淡傳春意，柳色依依作歲陽。", "只麽往來成樂土，豈知身世落南荒。"]'),
('18164cf0-81aa-4eea-a1fe-2231e4f2b3b6','和單令除夕二首  其一','胡寅','宋','宋诗','song-poetry','','[]','又聞幽谷有鶑遷，况復山晴花向然。',64,'全唐诗/poet.song.109000.json','["又聞幽谷有鶑遷，况復山晴花向然。", "泥犢戒耕呈歲歲，戶靈呵鬼換年年。", "茅簷賸有三竿日，秫地曾無二頃田。", "且買東江百花酒，與君同棹十分船。"]'),
('6c859099-c786-43b4-b18e-ea3170fc0696','和單令除夕二首  其二','胡寅','宋','宋诗','song-poetry','','[]','坐閲流年同擲梭，未曾聞道合如何。',64,'全唐诗/poet.song.109000.json','["坐閲流年同擲梭，未曾聞道合如何。", "擊壺安用鐵如意，愛酒猶須金叵羅。", "重讀豳詩賡節物，還師魯聖對鄉儺。", "東風漸次開桃李，之子寧能不我過。"]'),
('7e896638-9244-457e-b117-4a1a78ef27b1','新春即事二首  其一','胡寅','宋','宋诗','song-poetry','','[]','竹爆臘寒盡，桃符春事來。',48,'全唐诗/poet.song.109000.json','["竹爆臘寒盡，桃符春事來。", "和風已披拂，暖日便徘徊。", "曳杖閒挑菜，攀枝齼摘梅。", "太牢雖有味，豈必勝登臺。"]'),
('fa786f87-a2b9-408f-8951-9cf9c3d40c4c','新春即事二首  其二','胡寅','宋','宋诗','song-poetry','','[]','恰賦春還柳，俄聞地出雷。',48,'全唐诗/poet.song.109000.json','["恰賦春還柳，俄聞地出雷。", "雨絲分織作，風籟急喧豗。", "寂寂爐無火，欣欣甕有醅。", "臨寒插羔袖，雪觀亦悠哉。"]'),
('f77a3dab-a857-451b-9f81-f3a9714b183f','同蔣教授單令訪竹里','胡寅','宋','宋诗','song-poetry','','[]','遲日芳郊路，寒暄氣已分。',48,'全唐诗/poet.song.109000.json','["遲日芳郊路，寒暄氣已分。", "共尋茅屋趣，一醉竹光雲。", "藴藉潘懷縣，清修鄭廣文。", "衰遲亦何幸，併得友多聞。"]'),
('0050074f-1d6a-4643-8e8d-2b46cb5be953','即事','胡寅','宋','宋诗','song-poetry','','[]','梧葉經冬不識霜，杞茅蒙潤已宜湯。',64,'全唐诗/poet.song.109000.json','["梧葉經冬不識霜，杞茅蒙潤已宜湯。", "夜除愛日太和境，衣袂輕風單薄裝。", "盤綰翠絲春意近，盞浮清艷臘容光。", "東君又試芳菲手，行樂寧嗟鬢轉蒼。"]'),
('47c56f2f-25b8-4742-836c-0e495a7ba826','次德施見和','胡寅','宋','宋诗','song-poetry','','[]','頭如衰葆更加霜，身似陳茶不奈湯。',64,'全唐诗/poet.song.109000.json','["頭如衰葆更加霜，身似陳茶不奈湯。", "春服又陪曾點詠，歸心尤美陸生裝。", "山川浮動風雲氣，草木欣榮日月光。", "賸種雞頭剝溫軟，不教無齒愧張蒼。"]'),
('c2cc1513-93bc-455c-9c4d-fd254ef4283a','和單令','胡寅','宋','宋诗','song-poetry','','[]','曾步雩風詠晚春，肯教清鏡受纖塵。',64,'全唐诗/poet.song.109000.json','["曾步雩風詠晚春，肯教清鏡受纖塵。", "詩書漸與心爲一，文字終慚筆有神。", "弈局不爭先後手，醉鄉常值聖賢人。", "得時花卉千千狀，須倩能詩爲寫真。"]'),
('17d7a693-d360-4547-a440-ecfa17aec32b','送朱推于水東口','胡寅','宋','宋诗','song-poetry','','[]','送客水東口，散襟城北頭。',48,'全唐诗/poet.song.109000.json','["送客水東口，散襟城北頭。", "清風正駘蕩，細雨忽飛浮。", "荒傳少來燕，平田多乳鳩。", "何時理歸棹，橫笛下滄洲。"]'),
('12d96b03-d1b3-449c-aa6f-70f5b939e622','和德施賞金沙','胡寅','宋','宋诗','song-poetry','','[]','籠紗未暗塵，錦幄又經春。',48,'全唐诗/poet.song.109000.json','["籠紗未暗塵，錦幄又經春。", "有艷曉酣酒，無言時惱人。", "後先爭絢倩，開落自仍頻。", "相對長松樹，香心結蘂新。"]'),
('2c52f30d-7667-4339-b766-6fe77d210e8c','令節即事簡睎仲德施','胡寅','宋','宋诗','song-poetry','','[]','寒食清明節令佳，禁烟遺俗渺天涯。',64,'全唐诗/poet.song.109000.json','["寒食清明節令佳，禁烟遺俗渺天涯。", "清醇只向丹田暖，料峭猶煩翠幕遮。", "長短驟看森雨笋，高低難覓旋風花。", "小齋寂寂誰爲伴，水底初聞兩部蛙。"]'),
('fbb2e29b-d3a6-4a34-8f4e-20a273bee0fa','同單令遊延明寺','胡寅','宋','宋诗','song-poetry','','[]','下馬敲門扁蝠飛，亂鴉啼晚客還歸。',64,'全唐诗/poet.song.109000.json','["下馬敲門扁蝠飛，亂鴉啼晚客還歸。", "村江淺可褰裳涉，美酒清宜滿斚揮。", "獨樹高花紅啄玉，繁叢嫩蘂細編璣。", "追隨冠者皆行樂，借問何人鼓瑟希。"]'),
('851667c2-8308-4f79-a5d9-b52ce7ad2600','和單令簡園梨花四絕  其一','胡寅','宋','宋诗','song-poetry','','[]','梅花如夢李成塵，却伴酴醾過晚春。',32,'全唐诗/poet.song.109000.json','["梅花如夢李成塵，却伴酴醾過晚春。", "未要烘晴千樹白，且看带雨一枝新。"]'),
('04aa97a8-b6b3-4073-86d0-4ee5ae601197','和單令簡園梨花四絕  其二','胡寅','宋','宋诗','song-poetry','','[]','野老山園未省開，今朝何事客俱來。',32,'全唐诗/poet.song.109000.json','["野老山園未省開，今朝何事客俱來。", "炎荒有此清凉地，剪水裝林絕點埃。"]'),
('8d1453f1-790c-400a-bf02-d71eb390ae2d','和單令簡園梨花四絕  其三','胡寅','宋','宋诗','song-poetry','','[]','共傳嘉樹鎖山陰，冰彩瑶光自一林。',32,'全唐诗/poet.song.109000.json','["共傳嘉樹鎖山陰，冰彩瑶光自一林。", "未必甘滋追大谷，照人風韻故能深。"]'),
('ec8d2cdd-624f-4821-8342-31d55073c647','和單令簡園梨花四絕  其四','胡寅','宋','宋诗','song-poetry','','[]','清遊當日興怡融，無奈如絲雨映空。',32,'全唐诗/poet.song.109000.json','["清遊當日興怡融，無奈如絲雨映空。", "聞道只今方爛漫，莫教飛趁楝花風。"]'),
('b39f6ab2-cb54-436e-b02a-406f478c93fe','和單令九日二絕  其一','胡寅','宋','宋诗','song-poetry','','[]','爽氣深秋徹九霄，憑高眼界迥寥寥。',32,'全唐诗/poet.song.109000.json','["爽氣深秋徹九霄，憑高眼界迥寥寥。", "凄風但可開黄菊，零露行應到蓼蕭。"]'),
('3cd16d91-7734-4fd7-91a0-7e7a814ffed6','和單令九日二絕  其二','胡寅','宋','宋诗','song-poetry','','[]','行樂從來貴及辰，况逢節物一番新。',32,'全唐诗/poet.song.109000.json','["行樂從來貴及辰，况逢節物一番新。", "病夫久矣捐杯酌，悵望臨風落帽人。"]'),
('455d09b3-a5f6-48e9-9b11-4ad3c34a2755','題清遠峽山寺','胡寅','宋','宋诗','song-poetry','','[]','清遠峽山寺，幾年聞汝名。',96,'全唐诗/poet.song.109000.json','["清遠峽山寺，幾年聞汝名。", "維舟得眺望，滿目慰經行。", "壁立巉天秀，溪閒寫鏡清。", "嶺雲方北上，濤雪漫南傾。", "罪垢三熏凈，歸風兩腋輕。", "皇慈天共大，睿知日同明。", "重起闕廷戀，敢懷山水情。", "生綃無畫手，聊此寄真形。"]'),
('cd0f7e09-f688-4112-b181-e81e9bdae6a7','歸次義彬老人廖康吉惠靈壽杖以二十八字謝之','胡寅','宋','宋诗','song-poetry','','[]','綠鬢投荒白髮歸，瘴餘渾欲不勝衣。',32,'全唐诗/poet.song.109000.json','["綠鬢投荒白髮歸，瘴餘渾欲不勝衣。", "煩將扶老殷勤贈，未怕登高足力微。"]'),
('517a4805-ef65-43e4-8df7-90d7e9c0e812','魏漕彥成昔宰弋陽政續上聞召對改秩予適當詞命後自臺郎出守滁墾荒田千二百頃柄國者挾妻家私憾以爲罔功將漕襄陽修築大堤禦水患又以爲妄作與洪興祖爲程伯禹刊論語解至周公謂魯公有太息流涕之言彥成遂被竄于欽州柄國者死例逢赦宥歸道南嶽以大篇侑酒十尊見遺因成七絕以謝之  其一','胡寅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','紹興乙卯選賢時，弋水鳴琴有去思。',32,'全唐诗/poet.song.109000.json','["紹興乙卯選賢時，弋水鳴琴有去思。", "文石對敭言動聽，演綸無愧改官詞。"]'),
