('957c49f2-ef44-4f9a-9b61-ebcda0b90474','魏漕彥成昔宰弋陽政續上聞召對改秩予適當詞命後自臺郎出守滁墾荒田千二百頃柄國者挾妻家私憾以爲罔功將漕襄陽修築大堤禦水患又以爲妄作與洪興祖爲程伯禹刊論語解至周公謂魯公有太息流涕之言彥成遂被竄于欽州柄國者死例逢赦宥歸道南嶽以大篇侑酒十尊見遺因成七絕以謝之  其三','胡寅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','漢水縈州北且南，大堤花映府潭潭。',32,'全唐诗/poet.song.109000.json','["漢水縈州北且南，大堤花映府潭潭。", "若非刺史裨頹缺，鴨綠澆成幾醉酣。"]'),
('f4fcf0f1-523f-4ca5-9e05-f4a1878ede02','魏漕彥成昔宰弋陽政續上聞召對改秩予適當詞命後自臺郎出守滁墾荒田千二百頃柄國者挾妻家私憾以爲罔功將漕襄陽修築大堤禦水患又以爲妄作與洪興祖爲程伯禹刊論語解至周公謂魯公有太息流涕之言彥成遂被竄于欽州柄國者死例逢赦宥歸道南嶽以大篇侑酒十尊見遺因成七絕以謝之  其四','胡寅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','解到周公謂魯公，尚書深見古人風。',32,'全唐诗/poet.song.109000.json','["解到周公謂魯公，尚書深見古人風。", "流傳頓廣誰之力，千古須知魏與洪。"]'),
('0262a8c6-94db-4e5a-a435-9670abc36b58','魏漕彥成昔宰弋陽政續上聞召對改秩予適當詞命後自臺郎出守滁墾荒田千二百頃柄國者挾妻家私憾以爲罔功將漕襄陽修築大堤禦水患又以爲妄作與洪興祖爲程伯禹刊論語解至周公謂魯公有太息流涕之言彥成遂被竄于欽州柄國者死例逢赦宥歸道南嶽以大篇侑酒十尊見遺因成七絕以謝之  其五','胡寅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','天涯羈枕看三山，一日皇恩詔使還。',32,'全唐诗/poet.song.109000.json','["天涯羈枕看三山，一日皇恩詔使還。", "君子但知爲善樂，豈同餘臭滿人間。"]'),
('1f6e03d7-8b15-4a9f-9286-108e4fb2ba8c','魏漕彥成昔宰弋陽政續上聞召對改秩予適當詞命後自臺郎出守滁墾荒田千二百頃柄國者挾妻家私憾以爲罔功將漕襄陽修築大堤禦水患又以爲妄作與洪興祖爲程伯禹刊論語解至周公謂魯公有太息流涕之言彥成遂被竄于欽州柄國者死例逢赦宥歸道南嶽以大篇侑酒十尊見遺因成七絕以謝之  其六','胡寅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','名酒煩將一斛來，瘴餘衰病不勝杯。',32,'全唐诗/poet.song.109000.json','["名酒煩將一斛來，瘴餘衰病不勝杯。", "醉中獨愛舂容奏，恰似春潮卷海迴。"]'),
('c760b743-5d1c-40d1-a454-44ba8170a73c','魏漕彥成昔宰弋陽政續上聞召對改秩予適當詞命後自臺郎出守滁墾荒田千二百頃柄國者挾妻家私憾以爲罔功將漕襄陽修築大堤禦水患又以爲妄作與洪興祖爲程伯禹刊論語解至周公謂魯公有太息流涕之言彥成遂被竄于欽州柄國者死例逢赦宥歸道南嶽以大篇侑酒十尊見遺因成七絕以謝之  其七','胡寅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','聞說仙居窈復寬，湖山全似畫圖看。',32,'全唐诗/poet.song.109000.json','["聞說仙居窈復寬，湖山全似畫圖看。", "謫歸正值皇綱整，莫向斯時詠考槃。"]'),
('2f92ea8d-1e69-4748-a76d-9700b7e9a84b','簡彥達','胡寅','宋','宋诗','song-poetry','','[]','別來魚雁半浮湛，一日掀杯酒便深。',64,'全唐诗/poet.song.109000.json','["別來魚雁半浮湛，一日掀杯酒便深。", "照水顔容皆欲老，蔭門槐竹盡成陰。", "驅山塞海成何事，飯糗羹藜只此心。", "但願歲豐人共樂，扶筇有興即相尋。"]'),
('5ea501f9-2ea3-4f32-9ade-a08eee672aa9','將歸南嶽黎才翁命蕭復來相迎且以二詩見貺因作一絕謝之','胡寅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','涑水分携首重回，南山指日可徘徊。',32,'全唐诗/poet.song.109000.json','["涑水分携首重回，南山指日可徘徊。", "殷勤問訊煩甥友，更遣新詩兩詠來。"]'),
('f38cc187-d120-4c79-a596-751b14dfe6e8','挽吳丞相  其一','胡寅','宋','宋诗','song-poetry','','[]','妙齡一月了群書，未壯聲華衆已孚。',64,'全唐诗/poet.song.109000.json','["妙齡一月了群書，未壯聲華衆已孚。", "器遠况曾師舊德，時來俄看獻嘉謨。", "親扶日轂升天路，不許金戈入帝都。", "大節已全名自永，詎同姦慝苟全軀。"]'),
('54c1c8ee-3852-47b1-8927-755a7f397c52','挽吳丞相  其二','胡寅','宋','宋诗','song-poetry','','[]','追念宣和國勢孤，上公元宰導人諛。',64,'全唐诗/poet.song.109000.json','["追念宣和國勢孤，上公元宰導人諛。", "妖氛已覺前星暗，皇澤寧論少海枯。", "誰謂玉華傳玉座，共知青瑣伏青蒲。", "讒言一發堪流涕，禍在同升有鄙夫。"]'),
('f444bf82-c754-4522-b3f9-4e5326ae02e7','挽吳丞相  其三','胡寅','宋','宋诗','song-poetry','','[]','黄扉清啟帝之初，俊乂招徠念遠圖。',64,'全唐诗/poet.song.109000.json','["黄扉清啟帝之初，俊乂招徠念遠圖。", "桃李舒華方雨露，鴛鴻戢翼又江湖。", "當年舉國蒙休烈，至死無人雪厚誣。", "圓覺妙明何計此，獨疑遺恨遶蒼梧。"]'),
('dee3aed8-8a15-4993-80bb-1c8fd0cf63a8','挽劉忠顯  其一','胡寅','宋','宋诗','song-poetry','','[]','念昔京都晝掩關，黑雲黄霧塞人寰。',64,'全唐诗/poet.song.109000.json','["念昔京都晝掩關，黑雲黄霧塞人寰。", "南城掃雪迎耶律，北道聞風拜祿山。", "不爲身謀心皎皎，已終臣事意閑閑。", "何人得與高名並，千古常山諒可班。"]'),
('6aa524c1-6785-41b0-a97d-1a5472942e34','挽劉忠顯  其二','胡寅','宋','宋诗','song-poetry','','[]','未識堂堂玉立姿，已傳薤露滿山悲。',64,'全唐诗/poet.song.109000.json','["未識堂堂玉立姿，已傳薤露滿山悲。", "空餘父執修恭意，謾繼詞流紀德詩。", "諸子盡賢門益大，萬家餘地冢初纍。", "紛然盡奪三軍帥，誰識公心死不移。"]'),
('05a35a6f-d5c7-4021-80e3-5d0c8172eb79','挽陳幾叟','胡寅','宋','宋诗','song-poetry','','[]','妙質曾揮匠石斤，久於其道更超群。',64,'全唐诗/poet.song.109000.json','["妙質曾揮匠石斤，久於其道更超群。", "皂貂破敝頭蒙雪，黔突凄凉氣吐雲。", "忽上諫坡規帝德，又陪經殿勸皇墳。", "事功難必清名在，未辱先賢付託勤。"]'),
('2c5209e6-61af-4df9-ad76-36e6d40d7189','挽楊訓母莢氏','胡寅','宋','宋诗','song-poetry','','[]','戚戚秋風颭旐旌，送車千輛咽佳城。',64,'全唐诗/poet.song.109000.json','["戚戚秋風颭旐旌，送車千輛咽佳城。", "令妻壽母名兼美，孝子慈孫禮備成。", "望士有詩歌紼綍，梵坊無侶獻鐃鉦。", "更慚朴語書銘石，萬一幽光久更明。"]'),
('97cc3517-3b08-4ddf-89ac-0f2ba1838eed','挽某氏','胡寅','宋','宋诗','song-poetry','','[]','慈祥令淑稟於天，宗族閨門共仰賢。',64,'全唐诗/poet.song.109000.json','["慈祥令淑稟於天，宗族閨門共仰賢。", "中饋克脩惟六二，義方能教亦三遷。", "藝萱無復忘憂日，種柏行看合抱年。", "舊欲升堂今已矣，大招成些重凄然。"]'),
('c294a4f0-e44b-4198-855f-94f8fd57bd69','挽李太孺人','胡寅','宋','宋诗','song-poetry','','[]','桂水無情日夜東，空餘丹旐泝西風。',64,'全唐诗/poet.song.109000.json','["桂水無情日夜東，空餘丹旐泝西風。", "一經不負門閭望，五鼎端宜饋祀豐。", "茂渥出綸觀有煒，芳徽勒石播何窮。", "遥知祖送詩千首，挽鐸聲悲大隊中。"]'),
('af01ecdb-0a9f-4d10-ae39-dfa18c7e3f3f','挽端州黄大用大用喜讀書有志行數過予講討雖未詣宗本要自佳士可尚也心爲形役遂以病死作二詩哭之  其一','胡寅','宋','宋诗','song-poetry','','[]','每惜南冠懶讀書，欣逢之子富三餘。',64,'全唐诗/poet.song.109000.json','["每惜南冠懶讀書，欣逢之子富三餘。", "文章戶牖雖頻闖，師友源流或未疏。", "底事箇中紛侘傺，坐教淫末費驅除。", "昭昭奄作冥冥去，悼爾能無一束芻。"]'),
('421629d6-5d99-4877-a55f-488697b280af','挽端州黄大用大用喜讀書有志行數過予講討雖未詣宗本要自佳士可尚也心爲形役遂以病死作二詩哭之  其二','胡寅','宋','宋诗','song-poetry','','[]','鋸屑霏談涉往今，濡毫灑紙掞詞林。',64,'全唐诗/poet.song.109000.json','["鋸屑霏談涉往今，濡毫灑紙掞詞林。", "聽歌鹿野三章後，帳下龍門九曲深。", "十口西疇貧索莫，一官南選晚侵尋。", "早知大易無思慮，應悔生前未洗心。"]'),
('5d239376-62d5-42f5-9a63-68966d3bdc16','挽黎承事  其一','胡寅','宋','宋诗','song-poetry','','[]','北正黎司地，南來得姓繁。',48,'全唐诗/poet.song.109000.json','["北正黎司地，南來得姓繁。", "清時能教子，餘潤必高門。", "珠蚌他年譽，金籝晚歲溫。", "王師勤佐餽，鄉鬭待平反。"]'),
('3d2dd2f8-86e0-4602-b349-493d9d5ea69a','挽黎承事  其二','胡寅','宋','宋诗','song-poetry','','[]','援手遺嫠難，酬心樂泮恩。',48,'全唐诗/poet.song.109000.json','["援手遺嫠難，酬心樂泮恩。", "凄凉投轄井，慨歎給孤園。", "藝檟平居近，攀松永慕敦。", "流年駒過隙，不辱付諸昆。"]'),
('2e2d9992-25fb-4528-ae3a-d435b00e2b4c','挽譚邦鑑  其一','胡寅','宋','宋诗','song-poetry','','[]','忠烈延康子，期頤致政孫。',48,'全唐诗/poet.song.109000.json','["忠烈延康子，期頤致政孫。", "文詞金震蕩，行治玉純溫。", "夢熟黄粱早，名餘絳旐騫。", "傷哉九京路，白日閟泉門。"]'),
('dc063a8b-c3ac-48a1-97fe-c4b40233e53b','挽譚邦鑑  其二','胡寅','宋','宋诗','song-poetry','','[]','契好聯三世，交情晚更深。',48,'全唐诗/poet.song.109000.json','["契好聯三世，交情晚更深。", "宦遊乖握手，書到豈論心。", "歎失超勝願，愁聞相挽音。", "平生一尊酒，已矣不同斟。"]'),
('4617eb49-6119-4652-b3f2-bef435b5be3d','挽楊子川','胡寅','宋','宋诗','song-poetry','','[]','傾蓋小冠市，論文喬岳陽。',48,'全唐诗/poet.song.109000.json','["傾蓋小冠市，論文喬岳陽。", "一生能幾屐，兩鬢忽成霜。", "我尚棲南嶺，君俄赴北邙。", "無因澆絮酒，回首重呻傷。"]'),
('c0b24786-01f8-4ae2-92a0-90129f910be0','永州天申節錫宴致語口號','胡寅','宋','宋诗','song-poetry','','[]','門開閶闔曉霞鮮，劍佩稱觴玉座前。',64,'全唐诗/poet.song.109000.json','["門開閶闔曉霞鮮，劍佩稱觴玉座前。", "五福惠心敷下土，三呼稽首望層天。", "龍旂已盪淮濆祲，狼燧行清朔塞烟。", "復會東都臨四海，衆星環拱萬斯年。"]'),
('c7f19464-380d-4b13-8976-06df0a396bd3','新州鹿鳴宴致語口號','胡寅','宋','宋诗','song-poetry','','[]','秋氣清高肅雁行，賢侯勸駕會黄堂。',64,'全唐诗/poet.song.109000.json','["秋氣清高肅雁行，賢侯勸駕會黄堂。", "賓朋滿座曳珠履，鼓吹喧天飛羽觴。", "題柱棄繻俱有志，班荆折桂正相望。", "明年春色催行李，衣錦榮歸耀故鄉。"]'),
('8a57c3b6-856b-4c46-9caf-d05e1f206aff','句  其一','胡寅','宋','宋诗','song-poetry','','[]','更煩橫鐵笛，吹與衆山聽。',12,'全唐诗/poet.song.109000.json','["更煩橫鐵笛，吹與衆山聽。"]'),
('b129f187-835a-49e1-95e7-aab3387a4ab6','句  其二','胡寅','宋','宋诗','song-poetry','','[]','更於何處覓桃源，此地端疑小洞天。',16,'全唐诗/poet.song.109000.json','["更於何處覓桃源，此地端疑小洞天。"]'),
('7d2f92eb-c5a0-465f-9c63-bf7389b5b008','題智永上人瀟湘夜雨圖','邵博','宋','宋诗','song-poetry','','[]','曾擬扁舟湘水西，夜窗聽雨數歸期。',32,'全唐诗/poet.song.109000.json','["曾擬扁舟湘水西，夜窗聽雨數歸期。", "歸來偶對高人畫，却憶當年夜雨時。"]'),
('c81847c1-a7b6-487a-b3fb-39009eca861c','題司馬相如琴臺','邵博','宋','宋诗','song-poetry','','[]','長卿本豪傑，禮法安可處。',144,'全唐诗/poet.song.109000.json','["長卿本豪傑，禮法安可處。", "手彈南風琴，心調東鄰女。", "雜身傭保中，初不忌笑侮。", "大者固已立，下此皆可補。", "三賦爭日星，一書起今古。", "其餘不自祕，輒爲人所取。", "何當盡見之，真是文章祖。", "凜然千載下，英氣猶可睹。", "兒曹爾何知，杯酒那可汙。", "故臺已丘墟，勝絕誰敢據。", "我來訪遺跡，低回不忍去。", "詩成欲叫君，雲車隔煙霧。"]'),
('a7fac223-b2ed-4c5c-9de2-06b45e2c781a','寄潼川漕虞齊年','邵博','宋','宋诗','song-poetry','','[]','盡略威嚴拊困窮，使車三出未論功。',64,'全唐诗/poet.song.109000.json','["盡略威嚴拊困窮，使車三出未論功。", "交遊善者疑多可，節義臨之凜不同。", "惜我已生前輩後，求君須向古人中。", "北堂老監歸何晚，四海今還貞觀風。"]'),
('078215e9-22db-47b2-995b-a37b3976c7cc','春晚登郡樓','邵博','宋','宋诗','song-poetry','','[]','久客無歡意，經時只倦遊。',48,'全唐诗/poet.song.109000.json','["久客無歡意，經時只倦遊。", "落花猶解舞，飛絮太侵愁。", "日暮聞吹角，春歸獨倚樓。", "平生湖海願，幽興滿扁舟。"]'),
('c2da8ee9-2a16-46d1-b1da-579ef42a339f','雲安下偶成','邵博','宋','宋诗','song-poetry','','[]','輕波颭鴨頭，小艇翔燕尾。',120,'全唐诗/poet.song.109000.json','["輕波颭鴨頭，小艇翔燕尾。", "風沙三十程，雲水一千里。", "雪盡晚寒輕，日長春睡美。", "汀蕪翹碧茅，岸樹裹紅蘂。", "江浮清鏡中，山入翠屏裏。", "蜀鳥已驚心，巴猿猶惻耳。", "竹節數名灘，桃花驗新水。", "谷鶑歌尚慵，檣燕舞何喜。", "落日浪鎔金，殘花風翦綺。", "斯遊興最多，了不知行止。"]'),
('d54c8d40-611f-4d32-b29b-4df39a006c40','泊雲安下大風驟雨作柏梁體一篇','邵博','宋','宋诗','song-poetry','','[]','晴空赤日飛丹霞，扁舟春熱汗且呀。',240,'全唐诗/poet.song.109000.json','["晴空赤日飛丹霞，扁舟春熱汗且呀。", "寒溫之候無乃差，朝猶挾纊莫著紗。", "祝融暴橫勢莫加，驟將炎赫移韶華。", "東皇遊冶窮豪奢，未終節序還其家。", "忽驚猛吹揚白沙，煙雲四起相邀遮。", "空中轣轆鳴雷車，樅樅白雨懸亂麻。", "風師雨將相矜夸，千刃萬槊爭囂譁。", "玄旌皂纛何紛葩，勢摇兩蜀掀三巴。", "須臾雨止雷停撾，蒼雲掃盡天無瑕。", "恍如脫兔離輕罝，回頭已見羲輪斜。", "山開水靜風色嘉，喜翔燕雀嬉魚蝦。", "紅顛白倒紛殘花，披張林葉舒草芽。", "陰陽變化誰咄嗟，風雲乃爾相喧拏。", "大哉一氣通幽遐，彼蒼高遠安能涯。", "倚峯吟望心目賒，碧雲千里號歸鴉。"]'),
('d2c0e642-2af4-4700-b8ec-5228ef076223','句  其一','邵博','宋','宋诗','song-poetry','','[]','平浪勢粘天。',6,'全唐诗/poet.song.109000.json','["平浪勢粘天。"]'),
('de6b2c5b-d5cc-4599-a1e7-b91edbfaf436','句  其二','邵博','宋','宋诗','song-poetry','','[]','只道和戎功第一，不知上策在親征。',16,'全唐诗/poet.song.109000.json','["只道和戎功第一，不知上策在親征。"]'),
('6527aeff-8faf-4bc0-aff6-18b78f67215b','句  其三','邵博','宋','宋诗','song-poetry','','[]','如何老作簡州守，只對江山賦好詩。',16,'全唐诗/poet.song.109000.json','["如何老作簡州守，只對江山賦好詩。"]'),
('b43227b0-8409-442c-a71c-cfb2667437b2','句  其四','邵博','宋','宋诗','song-poetry','','[]','洲渚千奴熟，旌旗五馬來。',12,'全唐诗/poet.song.109000.json','["洲渚千奴熟，旌旗五馬來。"]'),
('1fdf2a07-e0bb-4457-a5ca-19c7eb2829d9','句  其五','邵博','宋','宋诗','song-poetry','','[]','池邊詩覓鄭都官。',8,'全唐诗/poet.song.109000.json','["池邊詩覓鄭都官。"]'),
('a5927629-7aab-4b59-b946-d2f1d05e3baf','賦燈','宋翔','宋','宋诗','song-poetry','','[]','景景照幽房，熒熒吐焰長。',24,'全唐诗/poet.song.109000.json','["景景照幽房，熒熒吐焰長。", "昔年江上女，曾向乞餘光。"]'),
('d028b7bf-0e48-4467-abad-0039b808947c','紹興樂府','宋翔','宋','宋诗','song-poetry','','[]','天意回，皇母歸。',92,'全唐诗/poet.song.109000.json','["天意回，皇母歸。", "戢烽燧，敞宮闈，朝陽赫奕明鞠衣。", "惟皇之孝，惟母之慈。", "陳仙仗，薦壽巵。", "從之冢后與庶妃，奏之九成與咸池。", "沓珍瑞，駢福祺，山陬水裔咸熙熙。", "惟天之象，與帝之宜。", "千萬年，無窮期。"]'),
('249b468d-7824-497b-ae0a-f5478187917c','李伯紀丞相挽詩  其一','趙令衿','宋','宋诗','song-poetry','','[]','道大終爲累，功高反被疑。',48,'全唐诗/poet.song.109000.json','["道大終爲累，功高反被疑。", "恨無長日月，寶此大蓍龜。", "鼓咽空山暮，風酸落木悲。", "弔喪哀不及，頼有哭公詩。"]'),
('7a93bfe8-52dc-47b7-bb1e-4df809a451ba','李伯紀丞相挽詩  其二','趙令衿','宋','宋诗','song-poetry','','[]','相位期三入，人心望一新。',48,'全唐诗/poet.song.109000.json','["相位期三入，人心望一新。", "名稱高世表，器識自天真。", "孰謂仁人壽，空憐吾道貧。", "彼蒼如有意，應百贖其身。"]'),
('b8ca0ebd-2ac7-44ed-8214-15470d307e78','李伯紀丞相挽詩  其三','趙令衿','宋','宋诗','song-poetry','','[]','氣量吞雲夢，風流冠習池。',48,'全唐诗/poet.song.109000.json','["氣量吞雲夢，風流冠習池。", "致君雖素定，濟衆未全釐。", "傒望金甌詔，俄摧玉樹枝。", "天心殊莫曉，神物失扶持。"]'),
('f5f1b1b6-4017-4525-96b1-499eb7e6316b','李伯紀丞相挽詩  其四','趙令衿','宋','宋诗','song-poetry','','[]','鯨路心猶望，龍門迹已荒。',48,'全唐诗/poet.song.109000.json','["鯨路心猶望，龍門迹已荒。", "樓成上霄漢，書擬奏明光。", "賤子無賢譽，先生獨薦揚。", "凜然生氣在，誰謂哲人亡。"]'),
('b7cebf82-b38e-4edb-b88c-5f402d71adae','泉南花木','趙令衿','宋','宋诗','song-poetry','','[]','偶然遊宦刺桐城，兩見南薰荔子生。',32,'全唐诗/poet.song.109000.json','["偶然遊宦刺桐城，兩見南薰荔子生。", "欲別北樓還小立，留題雲榭豈無情。"]'),
('4646ab14-0f82-4f85-bd39-6f3cc00ac814','贈鵝湖上人','趙令衿','宋','宋诗','song-poetry','','[]','三年四度到鵝湖，山水娛人道不孤。',32,'全唐诗/poet.song.109000.json','["三年四度到鵝湖，山水娛人道不孤。", "最是可人快心目，曉風殘月弄菰蒲。"]'),
('3c0584af-f5e3-4322-815a-46edbec6059e','舟泊太湖','李顒','宋','宋诗','song-poetry','','["\u592a\u6e56"]','旋經義興境，頓棹石蘭渚。',108,'全唐诗/poet.song.109000.json','["旋經義興境，頓棹石蘭渚。", "震澤爲何在，今惟太湖浦。", "圓經縈五百，盼目眇無覩。", "高天淼著岸，長津雜如縷。", "窈窕尋灣碕，迢遞望巒嶼。", "驚飆揚飛湍，浮霄漾懸岨。", "輕禽翔雲漢，游鱗憩中滸。", "暗靄天時陰，嶢岧舟航舞。", "馮河安可狥，靜觀戒行旅。"]'),
('1c89a031-564c-433a-87c0-bec3c5e7a1da','句','李顒','宋','宋诗','song-poetry','','[]','黯䨴重雲陰，碎稜震雷咤。',12,'全唐诗/poet.song.109000.json','["黯䨴重雲陰，碎稜震雷咤。"]'),
('28d9abb4-7ed4-4e9e-a00c-e835155709f4','偈二首  其一','釋證悟','宋','宋诗','song-poetry','','[]','東坡居士太饒舌，聲色關中欲透身。',32,'全唐诗/poet.song.109000.json','["東坡居士太饒舌，聲色關中欲透身。", "溪若是聲山是色，無山無水好愁人。"]'),
('bda58c71-9e66-4a1d-be8f-ec529f0671f2','偈二首  其二','釋證悟','宋','宋诗','song-poetry','','[]','寄語江西老古錐，從教日炙與風吹。',32,'全唐诗/poet.song.109000.json','["寄語江西老古錐，從教日炙與風吹。", "兒孫不是無料理，要見冰消瓦解時。"]'),
('654fdf05-3486-4145-b416-412f260cdec0','題昭陵','劉錡','宋','宋诗','song-poetry','','[]','□□□□歲農登，邊將無功吏不能。',32,'全唐诗/poet.song.109000.json','["□□□□歲農登，邊將無功吏不能。", "四十二年那忍說，西風吹淚過昭陵。"]'),
('30f0bbbd-0138-4a92-baa0-42769bc8d2d3','用前韻呈德瞻','劉錡','宋','宋诗','song-poetry','','[]','門外蹄輪任迹疎，一廛深稱水雲居。',32,'全唐诗/poet.song.109000.json','["門外蹄輪任迹疎，一廛深稱水雲居。", "平生事業將何用，歎括空能讀父書。"]'),
('c33279fd-b0df-48b1-a672-cac2cabcb063','題村舍呈德瞻友  其一','劉錡','宋','宋诗','song-poetry','','[]','一徑縈紆山更深，滿川烟靄夕沉沉。',32,'全唐诗/poet.song.109000.json','["一徑縈紆山更深，滿川烟靄夕沉沉。", "從來不問榮華事，自有沙鷗信此心。"]'),
('723fbd77-dd0d-44f4-91c4-335b496c6737','題村舍呈德瞻友  其二','劉錡','宋','宋诗','song-poetry','','[]','二月陽和花正繁，軟風輕扇筍斑斑。',32,'全唐诗/poet.song.109000.json','["二月陽和花正繁，軟風輕扇筍斑斑。", "揚鞭江路心無事，問舍求田過淺山。"]'),
('898b55ab-b7c9-4aa2-8b77-104bff73d446','題村舍呈德瞻友  其三','劉錡','宋','宋诗','song-poetry','','[]','清風葉葉映黄鸝，綠暗紅稀半掩扉。',32,'全唐诗/poet.song.109000.json','["清風葉葉映黄鸝，綠暗紅稀半掩扉。", "我以忘言靜思慮，子規猶道不如歸。"]'),
('927f5118-da3a-4e96-b30f-4c351edb6c27','午寢','劉錡','宋','宋诗','song-poetry','','[]','寓蹟唐興寺，幽窗得晝眠。',48,'全唐诗/poet.song.109000.json','["寓蹟唐興寺，幽窗得晝眠。", "西風縈破夢，落日亂殘蟬。", "歲月俄如此，功名豈偶然。", "五湖秋欲好，誰在釣魚船。"]'),
('ace70c3c-0fc8-4a0a-bf0f-f38cfeafd569','資福寺','劉錡','宋','宋诗','song-poetry','','[]','汛掃妖氛六合清，匣中寶劍氣猶橫。',64,'全唐诗/poet.song.109000.json','["汛掃妖氛六合清，匣中寶劍氣猶橫。", "夜觀星斗鬼神泣，晝會風雲龍虎驚。", "重整山河歸北地，兩扶聖主到南京。", "山僧不識英雄漢，只管滔滔問姓名。"]'),
('767f00e4-15ec-4465-ba81-9e629e779b00','補樂府十篇 帝宓犠氏之樂歌','曹勛','宋','宋诗','song-poetry','','[]','罔兮罟兮惟田漁，時兮食兮民之須，以享以祀兮燔祭有餘。',26,'全唐诗/poet.song.109000.json','["罔兮罟兮惟田漁，時兮食兮民之須，以享以祀兮燔祭有餘。"]'),
('585b13f1-8cf0-44f5-933f-dfc38afee172','補樂府十篇 帝神農氏之樂歌','曹勛','宋','宋诗','song-poetry','','[]','豐年告成，百穀用登。',25,'全唐诗/poet.song.109000.json','["豐年告成，百穀用登。", "匏籩既盈，黍稷既馨，昭假是膺。"]'),
('0fbe3f48-081e-4044-ae5a-e9e8bb59b3c3','補樂府十篇 帝有熊氏之樂歌','曹勛','宋','宋诗','song-poetry','','[]','於昭上帝，靈命有赫。',60,'全唐诗/poet.song.109000.json','["於昭上帝，靈命有赫。", "其命維何，卿雲五色。", "翩如游龍，萃如山崇。", "來臨來止，惕然有顒。", "惟欽惟畏，廼祗廼庸。", "肇建官師，神民肅雍。"]'),
('68cdfda4-eaa0-45a5-84b9-de8a1c825f83','補樂府十篇 帝少昊氏之樂歌','曹勛','宋','宋诗','song-poetry','','[]','鳥飛于天，魚躍于淵。',60,'全唐诗/poet.song.109000.json','["鳥飛于天，魚躍于淵。", "侯其尸之，其然而然。", "物之生矣，時其殖矣。", "職其宜矣，安其居矣。", "神之降依，昭假左右。", "霜露所霑，罔不在宥。"]'),
('12319b71-518d-47df-80dd-197b27c4f071','補樂府十篇 帝高陽氏之樂歌','曹勛','宋','宋诗','song-poetry','','[]','悠悠上天，罔不覆護兮。',51,'全唐诗/poet.song.109000.json','["悠悠上天，罔不覆護兮。", "芸芸動殖，靡不康阜兮。", "三光全兮，五穀熟兮，神顧歆兮，吾人昌兮，維上帝之功兮疇依。"]'),
('7ce8d1a0-0fa1-438e-8a26-c53defdda92e','補樂府十篇 帝高辛氏之樂歌','曹勛','宋','宋诗','song-poetry','','[]','時雨濛濛，自西及東。',60,'全唐诗/poet.song.109000.json','["時雨濛濛，自西及東。", "日月所至，罔不率從。", "田有黍稷，原有榛栗。", "尊卑秩秩，民有家室。", "惟川沖沖，惟山崇崇。", "允執厥中，臻於大同。"]'),
('07f00e9c-6e85-4e57-bd15-275375dd998e','補樂府十篇 帝陶唐氏之樂歌','曹勛','宋','宋诗','song-poetry','','[]','鴻惟烈祖，啟迪後人。',78,'全唐诗/poet.song.109000.json','["鴻惟烈祖，啟迪後人。", "皇皇上帝，俾予字民。", "民協平康，帝命式臧。", "宅彼陶唐，光于萬方。", "萬方億寧，亦莫我敢承。", "如天之運，如日之升。", "孰知其極兮，不可得而名不可得而稱。"]'),
('3aabb356-4210-4388-8e24-6d07817168ae','補樂府十篇 帝有虞氏之樂歌','曹勛','宋','宋诗','song-poetry','','[]','草木繁蕪兮陰雨膏之，百穀豐衍兮寒暑成之。',82,'全唐诗/poet.song.109000.json','["草木繁蕪兮陰雨膏之，百穀豐衍兮寒暑成之。", "萬物護理兮元凱馴之，顧否德之弗類兮敢不允躬以承之。", "庶揖讓以敉寧兮傳諸罔極，世不乏聖兮惟皇與直。", "俾帝堯之至公兮，終維斗之不忒。"]'),
('2d4000a9-3c45-4d3d-b44c-c9182dbaa045','補樂府十篇 夏后氏之樂歌','曹勛','宋','宋诗','song-poetry','','[]','於皇上聖，臨御有赫。',80,'全唐诗/poet.song.109000.json','["於皇上聖，臨御有赫。", "洪流湯湯，弗降弗辟。", "命於帝庭，纂服是膺。", "隨山濬川，海宇攸寧。", "五服既宅，貢有常職。", "恩覃遐荒，惟帝之力。", "元圭告功，敢不承式。", "地平天成，垂休罔極。"]'),
('073963f4-2a13-4814-a1af-bf1937349d4b','補樂府十篇 有商氏之樂歌','曹勛','宋','宋诗','song-poetry','','[]','維天有光，式彼大商，俾正以爾萬方。',63,'全唐诗/poet.song.109000.json','["維天有光，式彼大商，俾正以爾萬方。", "萬方其乂，易亂爲治。", "至于上下，鳥獸草木罔不安遂。", "帝命是膺，聖政日新。", "佑我烈祖，以克相爾後人。"]'),
('e614ee09-7065-467a-a754-42724cc0d859','琴操 將歸操','曹勛','宋','宋诗','song-poetry','','[]','水之深兮，可以方舟。',31,'全唐诗/poet.song.109000.json','["水之深兮，可以方舟。", "人之非兮，不可以同游。", "斯人斯游，吾心之憂。"]'),
('9d7e0b29-31a6-4ea6-a468-36740f6849b2','琴操 猗蘭操','曹勛','宋','宋诗','song-poetry','','[]','猗嗟蘭兮，其葉萋萋兮。',58,'全唐诗/poet.song.109000.json','["猗嗟蘭兮，其葉萋萋兮。", "猗嗟蘭兮，其香披披兮。", "胡爲乎生茲幽谷兮，不同雲雨之施。", "紛霜雪之委集兮，其茂茂而自持。", "猗嗟蘭兮。"]'),
('5ae218d0-9b36-4fa5-abf7-8e1ea75460a1','琴操 龜山操','曹勛','宋','宋诗','song-poetry','','[]','龜之卉兮萋萋，龜之雲兮霏霏，余之行兮遲遲。',52,'全唐诗/poet.song.109000.json','["龜之卉兮萋萋，龜之雲兮霏霏，余之行兮遲遲。", "龜兮龜兮，魯之所依。", "匪顛匪危兮，靡扶靡持。", "余之行兮，余心其悲。"]'),
('7b5e9f4d-7464-4df5-bf49-d37874b7dd5d','琴操 越裳操','曹勛','宋','宋诗','song-poetry','','[]','彼雲雨兮，曾莫之私。',54,'全唐诗/poet.song.109000.json','["彼雲雨兮，曾莫之私。", "黍稷繁蕪兮，草木其宜。", "田野不辟兮，其誰荒之。", "遠人之思兮，其誰來之。", "其勤其施，惟先君之思。"]'),
('9f0a1881-35f3-49d9-a4b9-c3edc5056568','琴操 拘幽操','曹勛','宋','宋诗','song-poetry','','[]','風入我室兮，霜入我衣。',46,'全唐诗/poet.song.109000.json','["風入我室兮，霜入我衣。", "言不敢發兮，聲不敢悲。", "惟皇考有訓兮，余罪之歸。", "余心耿耿兮，其知者爲誰。"]'),
('3a840b90-c0b3-45ef-901d-168b1152a1df','琴操 岐山操','曹勛','宋','宋诗','song-poetry','','[]','豳之土兮，民之所宜。',71,'全唐诗/poet.song.109000.json','["豳之土兮，民之所宜。", "豳之居兮，民之所依。", "予何爲兮尸之。", "我將全汝兮，之岐之陽。", "汝其保寧兮，無越汝疆。", "斯歸斯徂兮，其誰之將。", "嗟今之人兮，何思何傷。"]'),
('3b6ed431-7408-4566-bd6e-faa782177d98','琴操 履霜操','曹勛','宋','宋诗','song-poetry','','[]','皇之車兮，僕夫馳之。',72,'全唐诗/poet.song.109000.json','["皇之車兮，僕夫馳之。", "皇之輿兮，僕夫乘之。", "沉沉廣宇兮，燕雀安之。", "晨羞夕膳，誰其眎之。", "親不我思兮，我寧不悲。", "皚皚繁霜，兒則履之。", "父兮母兮，兒知兒非。"]'),
('fd12b311-7644-408b-b1ff-a8fac22f817a','琴操 雉朝飛操','曹勛','宋','宋诗','song-poetry','','[]','雉兮朝飛，鳴聲相隨。',43,'全唐诗/poet.song.109000.json','["雉兮朝飛，鳴聲相隨。", "朝刷其羽兮，夕哺其兒。", "雖有風雨兮，莫或仳離。", "嗟余之人兮，曾莫汝爲。"]'),
('365165d9-82f2-4d6f-913e-9ab01c79b341','琴操 別鶴操','曹勛','宋','宋诗','song-poetry','','[]','明月皎皎兮，霜風凄凄，摧雲翼兮天之涯。',51,'全唐诗/poet.song.109000.json','["明月皎皎兮，霜風凄凄，摧雲翼兮天之涯。", "望昆丘之路兮，不可以同歸。", "子其棄予兮，予將疇依。", "月皎皎兮風凄凄。"]'),
('e28b5f39-8a1e-4078-9eca-3acf4c225ce2','琴操 殘形操','曹勛','宋','宋诗','song-poetry','','[]','狸之文兮，蔚乎其成章。',60,'全唐诗/poet.song.109000.json','["狸之文兮，蔚乎其成章。", "身之孔昭兮，而其智之不揚。", "維元首之昧昧兮，而股肱孰爲其良。", "吁嗟乎，狸之祥兮。", "非吾之傷兮，其誰爲傷。"]'),
('7e7340ee-cd78-4192-ae6e-0aac411787e5','吳歌爲吳季子作','曹勛','宋','宋诗','song-poetry','','[]','佳人一往兮不來，國爲墟兮莫知。',36,'全唐诗/poet.song.109000.json','["佳人一往兮不來，國爲墟兮莫知。", "儂自守兮誰依，俟河清兮幾時。", "悵姑蘇之崔嵬。"]'),
('7cec7ad0-6e08-4e4e-8e4f-19d38998c50f','楚語爲屈平作','曹勛','宋','宋诗','song-poetry','','[]','瞻荆潁兮盤盤，悲淮流兮潺湲。',43,'全唐诗/poet.song.109000.json','["瞻荆潁兮盤盤，悲淮流兮潺湲。", "彼何人兮獨安，此何人兮獨難。", "悼哲人之不反兮，抗靈轡于江干。"]'),
('9e926d68-548b-48eb-9648-dbb7d676041b','孔子泣顔回','曹勛','宋','宋诗','song-poetry','','[]','噫嘻吁，天歟人歟，回也抑亦子之命歟，而其或者天實使之喪予。',59,'全唐诗/poet.song.109000.json','["噫嘻吁，天歟人歟，回也抑亦子之命歟，而其或者天實使之喪予。", "何仁者之不壽，而中道之棄兮。", "噫嘻吁，回歟回歟，其吾道之窮歟。"]'),
('2e1564b8-ce5e-414d-84ca-003950f819e7','孔子泣麟歌','曹勛','宋','宋诗','song-poetry','','[]','吁嗟乎麟兮麟兮，汝曷來之遲兮。',55,'全唐诗/poet.song.109000.json','["吁嗟乎麟兮麟兮，汝曷來之遲兮。", "唐虞不作兮湯武非，來者不可見兮而往者不可追。", "吁嗟乎麟兮，非吾之傷兮，而其誰汝爲。"]'),
('5b94061f-f31b-4f70-a0d1-873c3f000e2a','隴頭吟  其一','曹勛','宋','宋诗','song-poetry','','[]','烏落黄雲塞草秋，隴頭之水東西流，水聲嗚咽鳴啾啾。',56,'全唐诗/poet.song.109000.json','["烏落黄雲塞草秋，隴頭之水東西流，水聲嗚咽鳴啾啾。", "馬聞思舊櫪，人聞思舊丘，年年征戰無時休。", "無時休，誰能到此求封侯。"]'),
('67c5d27f-3a88-49f8-b1ed-ae1fb00eb0c1','隴頭吟  其二','曹勛','宋','宋诗','song-poetry','','[]','兵滿天山雪滿衣，漢家都護擁旌旗。',64,'全唐诗/poet.song.109000.json','["兵滿天山雪滿衣，漢家都護擁旌旗。", "銜枚一夜襲疎勒，度隴生兵盡潛出。", "不得戎王誓不歸，歸時楊柳正依依。", "正依依，占春色，與君同醉花陰側。"]'),
('6d694da2-7967-472a-abbc-13d71829a7ab','澤畔吟','曹勛','宋','宋诗','song-poetry','','[]','駕文螭兮翔九天，天路遠兮中道還。',284,'全唐诗/poet.song.109000.json','["駕文螭兮翔九天，天路遠兮中道還。", "邈故國兮懷所安，心耿耿兮循江干。", "紉秋蘭以爲裳兮，採杞菊以爲餐。", "望佳人之不來兮，暗修途之莫前。", "瞰江流之無垠兮，仰蒼蒼而漫漫。", "想荆門之遐阻兮，壽春杳隔于大淵。", "痛靈修之獨處兮，誰復與之寤言。", "氣填膺以拂鬰兮，淚承睫而漣漣。", "悼已往之修繫兮，欲易道而改轅。", "顧和璧之三獻兮，冀識者之一觀。", "阻風雨之慘慘兮，而夜不得明。", "哀時運之若此兮，余又何默默於久生。", "寧懷沙抱石以自沉兮，庶齎志而下信。", "雖世人之不吾悲兮，吾容能不悲夫若人。", "吾願託夷齊以爲紹介兮，修請謁于黄虞。", "弔巫咸于帝閽兮，友陽侯於子胥。", "幾江神之不我瀆兮，吾容委質於淵魚。", "已乎已乎，其靈修終不得而見乎。"]'),
('33ddb0ef-9639-4e0f-8a37-ffcd14b954e3','白頭吟','曹勛','宋','宋诗','song-poetry','','[]','相如素貧賤，羽翼依文君。',124,'全唐诗/poet.song.109000.json','["相如素貧賤，羽翼依文君。", "一朝富貴擅名價，文君見棄如束薪。", "五羖自傭賃，釋褐歸强秦。", "鳴鐘列華屋，膳羞羅八珍。", "厭此糟糠妻，悅彼新美人。", "二子既失意，瑶瑟流埃塵。", "促軫不成曲，未唱先眉顰。", "一發動三歎，淚下霑羅巾。", "通宵坐披衣，夙昔誰與陳。", "愁歎不復道，平明白髮新。"]'),
('4b1205da-313b-4085-8c6f-e2ef89243fff','梁甫吟','曹勛','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','晨行泰山下，興懷念梁甫。',88,'全唐诗/poet.song.109000.json','["晨行泰山下，興懷念梁甫。", "欲往失所從，荒途亙今古。", "却立空踟躕，憂來與誰語。", "日暮遵歸途，冥冥暗風雨。", "錯漠傷懷抱，僅得依門戶。", "幡然賡長謠，培塿隘齊魯。", "何當執策從鑾旗，翼贊登封繼三五。"]'),
('b36657cd-27af-4448-9e22-5d8f22c88b1c','待旦吟二首  其一','曹勛','宋','宋诗','song-poetry','','[]','彼幽人兮何所思，憂耿耿兮天一涯。',80,'全唐诗/poet.song.109000.json','["彼幽人兮何所思，憂耿耿兮天一涯。", "舉家親屬散百草，關山萬里難追隨。", "更長不寐聽鳴柝，寒風蕭瑟如凄悲。", "安得此身有羽翼，脫然避地能孤飛。", "中宵起坐待明發，悄悄側身聽晨雞。"]'),
('d11630a5-1940-483d-aa81-88db2d6d6c39','待旦吟二首  其二','曹勛','宋','宋诗','song-poetry','','[]','纏綿氷雪陰風寒，松竹半死相摧殘。',96,'全唐诗/poet.song.109000.json','["纏綿氷雪陰風寒，松竹半死相摧殘。", "嚴居谷飲蔽荆棘，藤蘿委地難躋攀。", "猛虎志大自羈束，易飽不及狐兔安。", "鷄鳴起舞亦漫興，扣角辛苦真可歎。", "堯禹既往小白死，烏乎吾道何由還。", "幽憂展轉不成卧，安得日出開重關。"]'),
('45ddd4f7-556e-47de-a3a9-9a465913559c','靜夜吟','曹勛','宋','宋诗','song-poetry','','[]','靜夜何所爲，坐對一枝燭。',96,'全唐诗/poet.song.109000.json','["靜夜何所爲，坐對一枝燭。", "俯仰徒四隅，歲宴靡儲粟。", "春耕乏良疇，秋穫罔芻菽。", "念至輒自營，一飯常不足。", "晚食已多幸，况敢望粱肉。", "上無官守累，下無征歛促。", "燕坐樂有餘，自足無多欲。", "寄語當塗士，吾腰未能曲。"]'),
('d01b598d-64e8-430c-9486-a8d87806299e','除夜吟','曹勛','宋','宋诗','song-poetry','','[]','鼕鼕夜漏嚴軍鼓，鼓聲入雲雲欲舞。',64,'全唐诗/poet.song.109000.json','["鼕鼕夜漏嚴軍鼓，鼓聲入雲雲欲舞。", "寒風奰屭頑無聲，野色埋光暗塵土。", "梅花隨臘散胡笳，胡笳曉色明春圃。", "春風直莫媚新聲，聲斷梅花還作主。"]'),
('7361ce31-1a51-43ca-8329-7904f3effccb','夜坐吟','曹勛','宋','宋诗','song-poetry','','[]','空階夜滴秋宵雨，雨入芭蕉動窗戶。',80,'全唐诗/poet.song.109000.json','["空階夜滴秋宵雨，雨入芭蕉動窗戶。", "佳人愁絕坐幽閨，良人萬里勤征戍。", "勤征戍，在何處，五載乘邊守當路。", "漢家新築受降城，戍卒還家免租賦。", "歸來直莫歎白頭，濁酒狂歌醉朝暮。"]'),
('c071be7a-e48a-4d03-9d7f-6d7ca0ad030a','長夜吟  其一','曹勛','宋','宋诗','song-poetry','','[]','舜枯槁，堯瘠癯，益稷播藝躬耕鋤，神禹勤瘁勞體膚。',172,'全唐诗/poet.song.109000.json','["舜枯槁，堯瘠癯，益稷播藝躬耕鋤，神禹勤瘁勞體膚。", "子孫放廢等庸奴，一身辛苦踰匹夫。", "孔子稱大聖，顔子稱大儒。", "寢席不暇暖，簞瓢困窮廬。", "盜跖飽人肉，列鼎吹笙竽。", "莊蹻肆淫虐，玉食驅華車。", "人生貴得意，孰識賢與愚。", "白日沉西山，烟藹低平蕪。", "悲風攪原隰，勁氣摧高梧。", "歌鐘滿前庭，賓客羅簪裾。", "侍女艷流景，芳澤揚通衢。", "珍肴如丘山，美酒如江湖。", "賢聖苟如此，不醉將何如。"]'),
('3e5a5b4e-01a4-4abd-ad63-feb7476eb772','長夜吟  其二','曹勛','宋','宋诗','song-poetry','','[]','智士名不足，愚夫樂有餘。',96,'全唐诗/poet.song.109000.json','["智士名不足，愚夫樂有餘。", "况復冬夜長，風雪迷通衢。", "美人邀我飲，清酒開玉壺。", "明眸艷紅燭，流盻光四隅。", "縈風轉修袂，逸響緣綺疏。", "龍香滿珠閣，蘭氣生羅襦。", "遺簪復墮珥，笑語相迎扶。", "回頭問公子，不醉將何如。"]'),
('d8e8f961-f536-45f5-a3d5-1f2169fe5ebb','苦雨吟','曹勛','宋','宋诗','song-poetry','','[]','巫山埋空曉光沒，寒入風聲散蕭瑟。',199,'全唐诗/poet.song.109000.json','["巫山埋空曉光沒，寒入風聲散蕭瑟。", "滴瀝深摧十二峯，峽江漲白洗青壁。", "羣陰寂寂蔽陽烏，摇蕩春愁滿南國。", "何當羲御駐中天，爲我驅除風雨黑。", "蜚廉先驅走寰宇，列缺揮鞭起龍虎。", "鬰儀頓轡潛海隅，九野冥冥暗風雨。", "饑鳶跕翅墮曾穹，軍鼓無聲如擊缶。", "青苔綠砌上高堂，簷溜侵窗入煙霧。", "南山山叟桂爲薪，四海橫流阻行路。", "安有王春四百八十時，蕭蕭風雨迷朝暮。", "我願得媧皇煉石補此破漏天，令三光繼明，萬物可睹，免使百萬億蒼生憔悴困泥土。"]'),
('49bdb378-f1d2-4988-b4aa-e4deccad4d00','空謠吟','曹勛','宋','宋诗','song-poetry','','[]','抗轡躡飛景，携手仰員羅。',96,'全唐诗/poet.song.109000.json','["抗轡躡飛景，携手仰員羅。", "空謠發新聲，羣響隨節和。", "瓊音動虛籟，神宇凌高歌。", "偃蓋滄浪宮，整襟翔玉華。", "流目厭塵袂，軒冕卑泥沙。", "咄咄樊籠子，胡不餐朝霞。", "他年一抔土，得失奚足誇。", "舍生失天爵，擾擾真蓬麻。"]'),
('f06242c9-a9cb-4b75-9e22-790cd79f7ffa','長吟續短吟','曹勛','宋','宋诗','song-poetry','','[]','桐花葉密春風老，長門路暗迷芳草。',80,'全唐诗/poet.song.109000.json','["桐花葉密春風老，長門路暗迷芳草。", "螢燭流輝露濕光，蟾蜍景落莎鷄曉。", "金烏出谷上蟠桃，別院笙簫歌未了。", "九華烟滿醉楊妃，樊姬靜聽雞聲悄。", "舊人直莫妬新人，別有蛾眉更妍巧。"]'),
('34c4b0f9-ba09-4ec9-86c7-19ee60b20180','續巴東三峽歌','曹勛','宋','宋诗','song-poetry','','[]','巴東三峽巫峽長，猿鳴三聲淚霑裳。',48,'全唐诗/poet.song.109000.json','["巴東三峽巫峽長，猿鳴三聲淚霑裳。", "月明夜寒寒雨霜，相望各在天一方。", "安得身有羽翼如鴛鴦，千里同相將。"]'),
('792c0e44-1106-4e14-bb6b-30baf0283728','三峽流泉歌','曹勛','宋','宋诗','song-poetry','','[]','草木摇落兮露爲霜，三峽之水兮流湯湯。',46,'全唐诗/poet.song.109000.json','["草木摇落兮露爲霜，三峽之水兮流湯湯。", "我欲絕之兮恨無梁，邈佳人兮天一方。", "明月皎皎兮，泉流湯湯。"]'),
('99afdca0-76ab-40bb-9a21-ac11523df7db','櫂歌','曹勛','宋','宋诗','song-poetry','','[]','謫仙醉揖金陵月，浩歌目送飛鴻絕。',144,'全唐诗/poet.song.109000.json','["謫仙醉揖金陵月，浩歌目送飛鴻絕。", "江城樽俎照清輝，樓臺忽作烟霞宅。", "長杯引竭北斗空，吳歈楚舞無顔色。", "行行倒著紫綺裘，徑上蘭舟岸紗幘。", "笑談欬唾驚魚龍，歷塊羣山看滅沒。", "石頭水底度冰輪，迢迢碾破澄空碧。", "左回右盼生英風，聯袂招邀盡狂客。", "相將醉卧綠蘿烟，三山不動鼇無力。", "秦淮寂寂江月空，人物風流難再得。"]'),
('a6a45e8f-5024-4723-a65a-feab6cff0412','陽春歌二首  其一','曹勛','宋','宋诗','song-poetry','','[]','草木榮兮春歸，桃李芳兮菲菲。',71,'全唐诗/poet.song.109000.json','["草木榮兮春歸，桃李芳兮菲菲。", "彼日月兮如馳，人生行樂兮能幾時。", "上林池館變荆棘，姑蘇臺榭游狐狸，人生行樂兮能幾時。", "能幾時兮可奈何，當歌莫惜朱顔酡。"]'),
('3c0bdd6b-8ab3-45c7-8663-3cc492a942db','陽春歌二首  其二','曹勛','宋','宋诗','song-poetry','','[]','漢家離宮三百所，高捲珠簾沸簫鼓。',112,'全唐诗/poet.song.109000.json','["漢家離宮三百所，高捲珠簾沸簫鼓。", "車如流水馬如龍，蘭麝飄香入煙雨。", "通衢夾道起青樓，金馬銅駝對公府。", "五侯同日拜新恩，七貴分封列茅土。", "玉窗朱戶盡嬋娟，絲竹聲中喧笑語。", "玳筵珠翠照樽罍，繼燭臨芳醉歌舞。", "醉歌舞，醉歌舞，天長地久無今古。"]'),
('553101a1-731a-4803-97ff-f8ab5c5eda5f','白雪歌','曹勛','宋','宋诗','song-poetry','','[]','白雪如玉，皇人壽穀。',34,'全唐诗/poet.song.109000.json','["白雪如玉，皇人壽穀。", "白雪如霜，皇人樂康。", "還余駕兮歸來，覃威德於八荒。"]'),
('c1caef98-7846-4819-bb6f-f80441964dd9','秋風歌','曹勛','宋','宋诗','song-poetry','','[]','蕭蕭兮寂寥，勞心兮忉忉。',44,'全唐诗/poet.song.109000.json','["蕭蕭兮寂寥，勞心兮忉忉。", "交河水冷胡馬驕，良人萬里從嫖姚。", "羅衣寬盡慵梳掠，翡翠無光香自消。"]'),
('a22043a0-7fdb-482a-956f-28fdf138d813','迷樓歌二首  其一','曹勛','宋','宋诗','song-poetry','','[]','項昇出南國，技巧多淫思。',180,'全唐诗/poet.song.109000.json','["項昇出南國，技巧多淫思。", "草圖獻天子，賞激嘉宏規。", "瑰材蔽江海，斤斧成風雷。", "千人扶一棟，萬棟高巍巍。", "飛鴻歷層簷，雲雨生階墀。", "五彩間金玉，百和雜塗泥。", "仙葩粲楹栱，七寶裝雲楣。", "一房百家産，萬戶羅東西。", "龍綃開寶幄，簾幕垂珠璣。", "光景艷流日，樓閣低天維。", "笙簫動虛籟，絃管明歌姬。", "撞鐘擊鼓恣行樂，牙檣錦纜環江隄。", "天長地久有時盡，君王此樂無時衰。", "詎知變故起倉卒，不悟人迷樓不迷。"]'),
('9cd84278-3d99-4cce-9ea1-2ffed3c0b7ee','迷樓歌二首  其二','曹勛','宋','宋诗','song-poetry','','[]','君不見秦皇愛阿房，死葬驪山側。',63,'全唐诗/poet.song.109000.json','["君不見秦皇愛阿房，死葬驪山側。", "煬帝愛迷樓，死葬迷樓北。", "乃知生者魂，即是死者魄。", "生死在迷樓，一死良自得。", "只應來夢兒，夜夜猶相憶。"]'),
('66ddffbf-0d7d-4e0e-9785-2f6bddb33e57','宛轉歌','曹勛','宋','宋诗','song-poetry','','[]','明月皎皎兮江水清，促瑶軫兮寫余情。',86,'全唐诗/poet.song.109000.json','["明月皎皎兮江水清，促瑶軫兮寫余情。", "有若人兮鏘珮瓊，申婉約兮揚新聲。", "託明君之幽怨兮，留遲風以掩抑。", "借餘音于宛轉兮，韵繁諧以周密。", "悵流月之西傾兮，恨彌襟而歎息。", "歌宛轉兮情無極。"]'),
('f99ef71d-534c-4e8c-bb02-b76f3eda661e','吳歌','曹勛','宋','宋诗','song-poetry','','[]','水滿長洲月滿樓，姑蘇臺榭鎖深秋。',32,'全唐诗/poet.song.109000.json','["水滿長洲月滿樓，姑蘇臺榭鎖深秋。", "君王不見春花老，響靸廊中有勝游。"]'),
('c75889e7-13f4-41f3-ac6f-42fbc726f232','楚狂接輿歌','曹勛','宋','宋诗','song-poetry','','[]','世謂夷齊以爲溷兮，指箕子而爲愚。',82,'全唐诗/poet.song.109000.json','["世謂夷齊以爲溷兮，指箕子而爲愚。", "既採薇以餓死兮，又被髮而爲奴。", "鏌鋣見棄於鉛刀兮，魚目寶於隋珠。", "彼蜂蛭之隠微兮，安能語神岳而觀清都。", "已乎已乎，無爲察察而辨璠璵與碔砆。"]'),
('567d5b05-9d82-41f2-bdf8-b397ee55acd4','項王歌','曹勛','宋','宋诗','song-poetry','','[]','提三尺兮臣諸侯，爭天下兮裂九州。',41,'全唐诗/poet.song.109000.json','["提三尺兮臣諸侯，爭天下兮裂九州。", "時不利兮絕淮流，江雖可渡兮吾何求，寧鬭死兮羞漢囚。"]'),
('50103ad0-cd99-4f7a-b27f-adad901016b2','碧玉歌','曹勛','宋','宋诗','song-poetry','','[]','南山有桂樹，上與浮雲齊。',36,'全唐诗/poet.song.109000.json','["南山有桂樹，上與浮雲齊。", "上巢雙鴛鴦，下合連理枝。", "不夭亦不傷，千載當若斯。"]'),
('f3a7fa4b-718e-45cc-be28-10908ae299e5','三婦艷歌  其一','曹勛','宋','宋诗','song-poetry','','[]','大婦雙綺襦，中婦紅羅裾。',36,'全唐诗/poet.song.109000.json','["大婦雙綺襦，中婦紅羅裾。", "小婦服翡翠，理曲調笙竽。", "良人幸安坐，美酒傾玉壺。"]'),
('894b05ea-85a2-481f-976e-69cc8a954ec2','三婦艷歌  其二','曹勛','宋','宋诗','song-poetry','','[]','大婦織雲錦，中婦繡鴛鴦。',36,'全唐诗/poet.song.109000.json','["大婦織雲錦，中婦繡鴛鴦。", "小婦獨無事，對鏡理紅粧。", "良人幸安坐，帳暖自添香。"]'),
('81321993-e77f-4695-807b-85e5257ebb5e','團扇歌','曹勛','宋','宋诗','song-poetry','','[]','白露團玉階，秋風動羅幕。',48,'全唐诗/poet.song.109000.json','["白露團玉階，秋風動羅幕。", "御幸各有宜，非爲君恩薄。", "紫殿香風暖，珠簾璧月斜。", "閤中調寶瑟，門外駐羊車。"]'),
('683e6717-c026-4974-81b9-8f9a8c8d8882','嘉游歌','曹勛','宋','宋诗','song-poetry','','[]','紫殿香風暖，珠簾璧月斜。',24,'全唐诗/poet.song.109000.json','["紫殿香風暖，珠簾璧月斜。", "閣中調寶瑟，門外駐羊車。"]'),
('ac149115-87aa-4b5c-a0d1-76cc543318bf','元丹歌贈會稽陳處士','曹勛','宋','宋诗','song-poetry','','[]','塵波溢目深溟渤，往古來今空出沒。',144,'全唐诗/poet.song.109000.json','["塵波溢目深溟渤，往古來今空出沒。", "喜君相見話丹經，起我凌雲惡阡陌。", "我生素乏兒女姿，面上巉巖聳山骨。", "少年避地東海隅，架竹編茅剪荆棘。", "白雲爲我開山容，清風爲我翔真域。", "旋屬羣寇迫敺攘，淬出青萍閉丹室。", "風塵澒洞十餘年，靈府芝田漸蕪沒。", "逢君蹤跡類秋蓬，遺我刀圭延歲月。", "何當橫槊靜寰區，同子山居論丹訣。"]'),
('1845c5d6-3dfa-4ee0-b20e-ef43b4c09cb4','薄暮動弦歌','曹勛','宋','宋诗','song-poetry','','[]','凉風生晚渚，碧草羅夕陰。',96,'全唐诗/poet.song.109000.json','["凉風生晚渚，碧草羅夕陰。", "置酒高樓上，延月開靈襟。", "穠粧映桃李，楚舞流清音。", "金石間絲竹，逸響飛華林。", "賓朋盡俊彥，然諾輕千金。", "游俠事遐覽，倜儻卑陸沉。", "常恐芳菲歇，行樂乖寸心。", "良時難再得，有酒須頻斟。"]'),
('2354ac85-ca9a-4704-9b66-4a767b8d1664','聖人出','曹勛','宋','宋诗','song-poetry','','[]','升太微，法璇璣。',64,'全唐诗/poet.song.109000.json','["升太微，法璇璣。", "闢紫宮，清九圍。", "甄符命以膺曆，廓氛祲而建靈旗。", "同車書之文軌兮，納民物於雍熙。", "噫嘻，惟仁惟義，則吾知其能所以保持。"]'),
('ad5f002a-c1b1-49c8-916c-7ebbae4dfa1d','飛龍引','曹勛','宋','宋诗','song-poetry','','[]','炎精應運開真籙，神母嗷嗷夜潛哭。',80,'全唐诗/poet.song.109000.json','["炎精應運開真籙，神母嗷嗷夜潛哭。", "五星同軌蒞秦雍，十二真人翔水曲。", "斷蛇約法授天人，項籍叱咤徒驅逐。", "蕭曹翼翼冠元功，三十一君兆開國。", "君兮臣兮俱會同，灑掃乾坤開壽域。"]'),
('366eae15-4c25-4c13-b520-a01a5cc15d93','上雲樂','曹勛','宋','宋诗','song-poetry','','[]','真王嚴仗衛，清道表前旌。',156,'全唐诗/poet.song.109000.json','["真王嚴仗衛，清道表前旌。", "翠輦浮龍藻，霜戈麗虎兵。", "哀笳鳴廣路，警蹕過曾城。", "後乘超王屋，前驅上玉京。", "諸天觀鼓節，列聖肅儀刑。", "朝謁虛皇罷，麾幢下始青。", "蒐兵寧紫戶，閲籍按黄庭。", "十洲皆承事，九宇仰裁成。", "暇豫迎春宴，還宮召百靈。", "綠室陳歌舞，陽臺煥日星。", "玉酒浮樽滿，天花覆坐馨。", "空謠洞真唱，遐覽悲劫齡。", "俯盼紅塵子，起滅輕浮萍。"]'),
('29d5b731-3e32-4112-a0b9-3a14b4c305c0','君馬黄','曹勛','宋','宋诗','song-poetry','','[]','君馬黄，臣馬蒼。',64,'全唐诗/poet.song.109000.json','["君馬黄，臣馬蒼。", "君馬短，臣馬長。", "馳驅不敢先騰驤，左右先後惟其良。", "臣馬勞悴君馬康。", "君馬康，無相忘。", "一勞一逸固所當，君馬無逐臣馬强。"]'),
('de7d7dc5-c215-4f7d-81f6-bd4fdf1a16b4','春風引','曹勛','宋','宋诗','song-poetry','','[]','憶昔上國宣和初，時平比屋驩唐虞。',256,'全唐诗/poet.song.109000.json','["憶昔上國宣和初，時平比屋驩唐虞。", "天王愷樂縱游豫，翔風和氣凌天衢。", "蒼龍頒春動時輅，晴光彩錯明金鋪。", "扶晨官師會朝請，雜沓劍珮諸侯趨。", "仗移走馬退東掖，闐闐車騎喧傳呼。", "笙簫合沓送歌酒，游人買笑捐金珠。", "太平一百六十載，四夷面內無征誅。", "歌聲未斷霓裳舞，胡兵直指隳神都。", "蒼茫萬乘扣軍壘，六龍不御驚鏷𨬟。", "陰虹當天變白晝，中原化作羊犬區。", "黄旗悠悠渡江漢，百僚竄伏天一隅。", "南極三吳北燕薊，西秦東魯殘羌胡。", "至今甲曆遍三四，生民散盡悲巢烏。", "我每思家限淮水，摇摇心與飛雲孤。", "江城春風漲白浪，雞聲可數屋可踰。", "兵纏九宇無花木，憔悴春風空綠蕪。"]'),
('fbdb1cce-bcaf-4d86-8b30-337c71a6e542','日出引','曹勛','宋','宋诗','song-poetry','','[]','雲冥冥，風凄凄。',48,'全唐诗/poet.song.109000.json','["雲冥冥，風凄凄。", "綺疏未白雞已啼，角聲纔斷闢朱扉。", "闢朱扉，款朝日。", "君王劍珮朝諸侯，赫赫明明光萬國。"]'),
('61d72a23-ea8c-4999-8afe-eab15e5ea773','思歸引','曹勛','宋','宋诗','song-poetry','','[]','歲崢嶸以高逝兮，辰一往而不返。',77,'全唐诗/poet.song.109000.json','["歲崢嶸以高逝兮，辰一往而不返。", "夫君胡爲乎，伏幽陵而連蹇。", "邈佳人之懷余兮，策予馬之不前。", "亙川塗之修阻以紛錯兮，積雪漫漫而蔽天。", "期百舍之不息兮，命予駕而勉旃。"]'),
('a4379958-fea3-402d-9d30-0db3b0609ea8','箜篌引','曹勛','宋','宋诗','song-poetry','','[]','行天莫乘龍，行地莫乘馬。',108,'全唐诗/poet.song.109000.json','["行天莫乘龍，行地莫乘馬。", "龍馬各有待，牽連一時假。", "至人運獨照，八表周神化。", "結交當結心，勢利徒夸咤。", "兔絲倚喬松，纏綿不相舍。", "秋風飛嚴霜，榮枯何所藉。", "富貴人所慕，貧賤人所鄙。", "妻嫂薄蘇秦，人事古如此。", "游子歸去來，勞生良可恥。"]'),
('872230ab-e232-4829-9504-0bd7a047bd92','日出行','曹勛','宋','宋诗','song-poetry','','[]','日出東海隅，照我草屋東。',105,'全唐诗/poet.song.109000.json','["日出東海隅，照我草屋東。", "屋東有榮木，光彩生曈矓。", "春草凝碧色，春水生芙蓉。", "江山發深秀，和氣翔春風。", "六龍儼靈轡，萬物咸昭融。", "羲和羲和，無曠爾職，無替爾功。", "使吾兩目常明，兩耳常聰。", "則吾將薦汝於上帝，而復子以重黎之封。"]'),
('19d86fe0-4850-40d9-8a83-fcd910102250','升天行','曹勛','宋','宋诗','song-poetry','','[]','上智保沖淡，練氣固形質。',156,'全唐诗/poet.song.109000.json','["上智保沖淡，練氣固形質。", "精神藏杳冥，獨照出寂默。", "三氣俱混同，求死不復得。", "其次崇真功，立言與立德。", "軒后御飛龍，旌幢煥晴碧。", "楊許奉丹書，凌空佐天職。", "董奉乘雲輿，秦女跨文翼。", "茅山與荆山，遺蹤宛如昔。", "旌陽與劉安，雞犬翔真域。", "清虛王陵孫，巍巍膺九錫。", "雲表鳴簫笳，仗衛嚴霄極。", "即事非荒唐，粲然若白黑。", "揮手謝時人，緱山有仙迹。"]'),
('5a100931-e318-4998-be9c-c96d1f3b74df','結客少年場行二首  其一','曹勛','宋','宋诗','song-poetry','','[]','結客少年場，驊騮從驌驦。',96,'全唐诗/poet.song.109000.json','["結客少年場，驊騮從驌驦。", "鬭雞橫大道，獵騎卷平岡。", "婚姻聯衛霍，賓客紛金張。", "報仇通姓字，排難匿行藏。", "功名看寶劍，富貴珥貂璫。", "逸氣凌秋鶚，清才負錦囊。", "詼諧驚四坐，議論駭諸郎。", "日暮平康裏，花陰醉滿牀。"]'),
('71c00682-b0a5-4752-a14d-bfeb30af246b','結客少年場行二首  其二','曹勛','宋','宋诗','song-poetry','','[]','結客少年場，橫行靜朔方。',96,'全唐诗/poet.song.109000.json','["結客少年場，橫行靜朔方。", "嫖姚新拜將，親選羽林郎。", "百寶裝犀甲，千金飾箭房。", "笑談看匕首，博戲賭香囊。", "聚飲胡姬酒，同升射雉堂。", "聯騎絕沙漠，分麾入范陽。", "陳前俘黠虜，馬首拜降王。", "歸來辭厚賞，小閣醉紅粧。"]'),
('11eeac1e-57b0-49d3-91be-cc5e40734f94','涇溪行','曹勛','宋','宋诗','song-poetry','','[]','涇溪之水兮，猶可以方舟。',71,'全唐诗/poet.song.109000.json','["涇溪之水兮，猶可以方舟。", "涇溪之人兮，不可以同游。", "涇溪之阻兮，猶可以爲梁。", "涇溪之險兮，石齧吾廧。", "涇溪之水兮，猶可以徒涉。", "涇溪之人兮，不可以相接。"]'),
('40ab1e33-6a12-48f4-b954-bfc088ebf6b3','長安有狹斜行二首  其一','曹勛','宋','宋诗','song-poetry','','[]','長安有狹斜，劣劣通香轂。',132,'全唐诗/poet.song.109000.json','["長安有狹斜，劣劣通香轂。", "道逢二少童，問君住何曲。", "我家本神京，住近濯龍北。", "長子爵執圭，次子爲相國。", "小生無高位，校讐在天祿。", "三子俱下來，游人住行足。", "三子俱入門，金紫照華屋。", "三子俱升堂，戲綵弄絲竹。", "大婦縫羅襦，中婦裁冰縠。", "小婦調鳴箏，切切聲相續。", "丈人幸安坐，置酒奏新曲。"]'),
('7c9f7c90-8ef4-45e4-8e16-0236b7560605','長安有狹斜行二首  其二','曹勛','宋','宋诗','song-poetry','','[]','長安有狹斜，狹斜難方軌。',120,'全唐诗/poet.song.109000.json','["長安有狹斜，狹斜難方軌。", "道逢兩青衣，問君住何里。", "我家銅駝陌，高閣通朱邸。", "長子爵通侯，次子聯端揆。", "小子事游俠，倜儻卑豪貴。", "三子俱入門，軒車羅甲第。", "三子俱升堂，光彩動階陛。", "大婦理珍裘，中婦曳雲帔。", "小婦弄笙簧，明粧擁歌妓。", "丈人幸留連，雅舞揚清吹。"]'),
('43865f01-f26a-4c01-8be7-ec1b2613d9d4','飲馬長城窟行','曹勛','宋','宋诗','song-poetry','','[]','漢馬飲長城，匈奴空塞北。',120,'全唐诗/poet.song.109000.json','["漢馬飲長城，匈奴空塞北。", "東胡與烏丸，先驅出絕域。", "月氏合康居，受詔發疎勒。", "右校羅天山，左出林胡國。", "嫖姚登狼居，旌旗照穹碧。", "號令明秋霜，虜帳餘空壁。", "瀚海無驚波，獻捷走重譯。", "大將朝甘泉，後部騰沙磧。", "九宇動聲容，功烈光篇籍。", "將軍拜通侯，歌舞連朝夕。"]'),
('e88d78ed-be57-4c0b-992a-b8d8088eac14','胡無人行二首  其一','曹勛','宋','宋诗','song-poetry','','[]','漢地山河遠，邊城草木長。',108,'全唐诗/poet.song.109000.json','["漢地山河遠，邊城草木長。", "西戎空大夏，北虜送君王。", "禮樂兼三統，車書混八荒。", "征伐司衛霍，奉使遣蘇張。", "號令知無外，衣冠入夜郎。", "蒐兵臨瀚海，郡縣裂姑臧。", "郵傳通族障，奚奴識憲章。", "華夷同正朔，天子坐明堂。", "西極奉龍馬，何用贄白狼。"]'),
('31e329d8-c927-4705-b765-4b32d7ed2677','胡無人行二首  其二','曹勛','宋','宋诗','song-poetry','','[]','胡無人，胡無人，嫖姚十八爲將軍。',96,'全唐诗/poet.song.109000.json','["胡無人，胡無人，嫖姚十八爲將軍。", "酒酣耳熱氣益振，胡兒百萬空成羣。", "兵車轔轔動雷轂，漢軍霆擊崩屯雲。", "登封居胥轉瀚海，波澄萬里無纖塵。", "胡無人，胡無人，六驘夜遁徒苦辛。", "當時足雪平城恥，猶恨逋誅尚有人。"]'),
('9f493096-4c40-4a8b-9cc6-0d52e756672f','釣竿行','曹勛','宋','宋诗','song-poetry','','[]','臨北坂，望南山，山長水遠心慱慱。',40,'全唐诗/poet.song.109000.json','["臨北坂，望南山，山長水遠心慱慱。", "鈎有餌兮緡有竿，魚深潛兮秋水寒，念王孫兮何時還。"]'),
('869a84a4-e603-4e9c-9898-4bfaf27d7433','春江行','曹勛','宋','宋诗','song-poetry','','[]','浦嶼連芳草，夭桃間柳堤。',60,'全唐诗/poet.song.109000.json','["浦嶼連芳草，夭桃間柳堤。", "征鴻下天際，游女過前溪。", "魚沒驚帆影，林疎見鳥啼。", "王孫聯繡騎，童子解香觿。", "吳姬笑留飲，同指畫橋西。"]'),
('cc9fb3a8-386f-499e-a4e4-c822619e3c1d','艷歌行','曹勛','宋','宋诗','song-poetry','','[]','陽春麗華旦，杲日延清暉。',48,'全唐诗/poet.song.109000.json','["陽春麗華旦，杲日延清暉。", "庭前夭桃花，灼灼流芳菲。", "佳人惜良辰，游子行不歸。", "君看夭桃花，芳菲能幾時。"]'),
('169cb06a-cdfb-4011-8c56-bddd06beff51','塞北行','曹勛','宋','宋诗','song-poetry','','[]','五月無芳草，經年不見花。',48,'全唐诗/poet.song.109000.json','["五月無芳草，經年不見花。", "蒼烟埋古木，朔吹卷龍沙。", "猶逢阿母海，愁看白博叉。", "彷彿南箕下，遥遥望漢家。"]'),
('f1454af8-4f6e-4b3d-b8c8-fb010b3f0b94','淮南行二首  其一','曹勛','宋','宋诗','song-poetry','','[]','人去宮門寂，丹成寶鼎空。',36,'全唐诗/poet.song.109000.json','["人去宮門寂，丹成寶鼎空。", "砌下苔錢紫，庭中霜葉紅。", "思君聽松籟，精魄上高穹。"]'),
('d49d4478-79b0-4c73-8198-b2ac7b1a862d','淮南行二首  其二','曹勛','宋','宋诗','song-poetry','','[]','月冷桐陰靜，霜紅桂影寒。',36,'全唐诗/poet.song.109000.json','["月冷桐陰靜，霜紅桂影寒。", "碧蘚封丹室，青松覆玉壇。", "如何後雞犬，不得厠驂鸞。"]'),
('5c451106-2f85-4732-b354-1b69000d372e','青漢謠','曹勛','宋','宋诗','song-poetry','','[]','鼓策飛晨華，翹轡玄景阿。',168,'全唐诗/poet.song.109000.json','["鼓策飛晨華，翹轡玄景阿。", "雲裾動星漢，流彩鳴玉珂。", "苕苕拂青靄，俛仰窺員羅。", "羣真儼龍駕，拊節揚空歌。", "靈風翔玉京，音響生雲和。", "飛軒出閶闔，紫霄高峨峨。", "覽極不知疲，垂足濯天河。", "抵掌談羲黄，歷世由經過。", "下盼塵波中，穢濁真棄帑。", "胡爲戀浮境，出沒相纏紆。", "秦陵一抔土，神室生葭蘆。", "商山高崔嵬，名與四皓俱。", "歸來邈雲漢，璧月流綺疏。", "悠然動清興，何必騎鯨魚。"]'),
('ae932ccb-1c52-4e67-8d7b-cf9de143c8d7','夢仙謠','曹勛','宋','宋诗','song-poetry','','[]','夢入蓬萊宮，岧嶤聳朱閣。',184,'全唐诗/poet.song.109000.json','["夢入蓬萊宮，岧嶤聳朱閣。", "靈風翔紫烟，靄鬰生羅幕。", "鸞鳳棲瑶林，咀嚼瑶華萼。", "老龍戲滄洲，噴濤盪鱗角。", "朱戶翳霄暉，翠殿開晴廓。", "中有神仙人，緩步鏘金鐸。", "顔貌盛芙蓉，舉止何綽約。", "引我丹霞房，玉漿金罍酌。", "更賜琅玕膏，笑談同飲啄。", "仙童供蟠桃，盛以朱雲絡。", "坐看移三山，驚波沸五岳。", "下顧塵埃徒，奔走赴陵壑。", "真人執我手，殷勤相付托。", "若到紅塵中，莫染紅塵濁。", "他年須是早歸來，奉迎當遣遼東鶴。"]'),
('e826c2d9-53ab-4f8e-a443-5fbae4140056','步月謠','曹勛','宋','宋诗','song-poetry','','[]','太清天宇清且高，皎然冰鑑懸層霄。',80,'全唐诗/poet.song.109000.json','["太清天宇清且高，皎然冰鑑懸層霄。", "絳河水淺閬風息，蟾光度景摇金鰲。", "仙人縱駕游八極，鳳簫歌吹鳴嘈嘈。", "星宮月殿風馬遠，珠華露濕旌旄冷。", "還虛按轡窺塵寰，波裏三山銀浪卷。"]'),
('514b5b04-d26c-416b-af2b-0159bf36075d','游仙謠','曹勛','宋','宋诗','song-poetry','','[]','羽蓋承流景，飆輪泛紫霞。',72,'全唐诗/poet.song.109000.json','["羽蓋承流景，飆輪泛紫霞。", "前旌絳霄隊，駐節王母家。", "真童發清謠，雲表翔哀笳。", "樓臺上清漢，服綵明朱華。", "萬春若朝菌，歡樂庸可涯。", "瑶席未終醼，零落蟠桃花。"]'),
('28bb64e7-a957-4278-be7d-584f4353ba4c','清晨謠','曹勛','宋','宋诗','song-poetry','','[]','通夕袌寒衾，冥冥暗風雨。',156,'全唐诗/poet.song.109000.json','["通夕袌寒衾，冥冥暗風雨。", "披衣待平明，起履步庭蕪。", "遥遥望扶桑，延目上洲渚。", "陰風驅層雲，屯積亙山阜。", "草木纏凄悲，杲日霾天步。", "林鳥雜亂飛，修塗限商賈。", "松竹互摧折，鴟鴞肆翔舞。", "四海揚驚濤，鯨鯢竟吞吐。", "誰云天地寬，宛足隘環堵。", "殊乖夙昔心，塊坐闃無語。", "遲遲覽衿带，櫛沐正冠屨。", "姑以勤余生，疏剔治園圃。", "清晨勞寤歌，無乃思湯武。"]'),
('a81627d5-6cdd-4dd5-9c14-12b1012947e4','獨酌謠二首  其一','曹勛','宋','宋诗','song-poetry','','[]','我有一樽酒，來自故人家。',126,'全唐诗/poet.song.109000.json','["我有一樽酒，來自故人家。", "故人久相別，十載隔天涯。", "相思不相見，對月開流霞。", "一酌延清風，清風爲我開靈襟。", "再酌勸明月，明光徘徊冷光發。", "三酌望故人，明月清風見顔色。", "高歌起舞賡長謠，聲裂金石貫曾碧。", "伯倫已死淵明殂，蜾蠃螟蛉漫充塞。", "須臾歌罷玉壺空，醉覺長天不盈尺。"]'),
('87b48cb4-c934-4843-aa20-4cfccd65f69d','獨酌謠二首  其二','曹勛','宋','宋诗','song-poetry','','[]','春風著意憐芳草，芳草榮時春自老。',48,'全唐诗/poet.song.109000.json','["春風著意憐芳草，芳草榮時春自老。", "人生歡少別離多，有酒當歌自傾倒。", "莫教憔悴損容光，白髮蒼顔爲誰好。"]'),
('ffa195ed-f351-4761-8c1d-d779009be414','陽春謠','曹勛','宋','宋诗','song-poetry','','[]','臨東皇，萬物昌。',65,'全唐诗/poet.song.109000.json','["臨東皇，萬物昌。", "君陶唐，宣重光。", "臣臯夔，熙元良。", "協三辰，撫萬方，物無夭札人無傷。", "人無傷，繄元良。", "錫以景福滋瀼瀼，吾君欣欣兮臻樂康。"]'),
('db756531-14cc-4cf7-88ac-16f1aba989a6','深夜謠二首  其一','曹勛','宋','宋诗','song-poetry','','[]','月影移鳷鵲，鑪香滿建章。',48,'全唐诗/poet.song.109000.json','["月影移鳷鵲，鑪香滿建章。", "君王駐琱輦，宮女出彤房。", "仙樂浮雲漢，笙歌遶畫梁。", "按圖皆國色，何處是高唐。"]'),
('e58d8671-dd44-49a5-8699-a9204b4bf0eb','深夜謠二首  其二','曹勛','宋','宋诗','song-poetry','','[]','花落春猶在，人存事已非。',48,'全唐诗/poet.song.109000.json','["花落春猶在，人存事已非。", "草侵迎仗路，塵滿舊熏衣。", "獨立空憐影，當歌但歛眉。", "羞見長門月，曾同步輦歸。"]'),
('a34b8b72-0f21-4cde-81dd-9adb11851a79','步月謠','曹勛','宋','宋诗','song-poetry','','[]','琅玕轉景蒼虯立，露脚斜飛冷光濕。',64,'全唐诗/poet.song.109000.json','["琅玕轉景蒼虯立，露脚斜飛冷光濕。", "人歸芳草恨苕苕，劍珮生寒秋水澀。", "離離箕斗正相望，交流帳合金波入。", "風前摇袂思沉沉，雷雲不動蛟龍蟄。"]'),
('0daf14ea-c5f6-4165-a297-7ea04c12c4f9','清晨謠','曹勛','宋','宋诗','song-poetry','','[]','陽烏出谷升蟠木，冪冪寒烟歛修竹。',64,'全唐诗/poet.song.109000.json','["陽烏出谷升蟠木，冪冪寒烟歛修竹。", "狐狸竄伏不敢鳴，魑魅深潛翳林麓。", "荷鋤田父下東臯，金馬門開轉華轂。", "何當羲御駐中天，赫赫明明光萬國。"]'),
('00596f57-b397-428e-a0e9-9caeb904420e','山中謠','曹勛','宋','宋诗','song-poetry','','[]','山中之樂何由說，知者不言言者拙。',32,'全唐诗/poet.song.109000.json','["山中之樂何由說，知者不言言者拙。", "紅塵飛盡散松風，獨酌寒泉弄明月。"]'),
('01c3ee5f-199b-4e8c-b6da-b026080e2700','秋風引','曹勛','宋','宋诗','song-poetry','','[]','閶闔天門開九重，金莖肅蕭摇霜風。',48,'全唐诗/poet.song.109000.json','["閶闔天門開九重，金莖肅蕭摇霜風。", "吳江木落龍庭空，雞鳴起舞何匆匆。", "胡塵高翳山□東，邊聲夜入烏號弓。"]'),
('3c740a89-adde-47b5-9c75-ba86373df90f','青苔篇','曹勛','宋','宋诗','song-poetry','','[]','陵陸變滄海，復作清淺流。',171,'全唐诗/poet.song.109000.json','["陵陸變滄海，復作清淺流。", "扶疎蘂淵桂，先驚蒲柳秋。", "姑蘇臺未乾，坐見麋鹿游。", "秦皇正游覽，黄屋指沙丘。", "乃知晞朝露，不必潛蛟虯。", "桀跖豈庸陋，比德慚蜉蝣。", "夷齊苦葵藿，垂譽賢伊周。", "貧賤未必汙，邪辟深可羞。", "愚智混生死，善惡觀其由。", "昧死尚役役，身外滋旁求。", "君不見當年梨園歌舞人，歌聲未歇生白頭。", "及時游衍且行樂，莫教日入辭高樓。", "請君試誦青苔篇，令君一誦忘百憂。"]'),
('c92bdba4-09fe-4652-87f6-f01c63914fe2','白馬篇','曹勛','宋','宋诗','song-poetry','','[]','白馬何翩翩，况復值神武。',120,'全唐诗/poet.song.109000.json','["白馬何翩翩，况復值神武。", "逸足看夷猶，四蹄入風雨。", "右盼空流沙，左歷無全虜。", "中夜視房心，趣目翻霞舉。", "朝飲崑崙池，夕秣龍川渚。", "毛族空成羣，斑駁亦何數。", "神物不虛生，寄托遇明主。", "所適無險難，要知同彼此。", "歸來脫羈束，飽食芻與粟。", "主人已封侯，安步驅華轂。"]'),
('fefef417-f1a2-4ff7-8692-e45d36b40cf4','美女篇','曹勛','宋','宋诗','song-poetry','','[]','芙蓉開綠水，青松映海棠。',144,'全唐诗/poet.song.109000.json','["芙蓉開綠水，青松映海棠。", "新晴沐膏雨，艷色明朝陽。", "綽約彼姝子，轉盼流輝光。", "被服妖且妍，細浥薔薇香。", "下有合歡带，繡作雙鴛鴦。", "上有雙同心，結作明月璫。", "珠環垂兩耳，翠鳳翹釵梁。", "瓊鈎約雙袖，提籠學採桑。", "採桑城南隅，五馬停路傍。", "調笑不一顧，但見桑條長。", "歸來候蠶眠，靜坐調笙簧。", "結髮事夫壻，誰羨東家王。"]'),
('07611869-161f-41e6-93b9-ecfb8b2225e7','遠游篇','曹勛','宋','宋诗','song-poetry','','[]','少年重意氣，辭家遠行游。',132,'全唐诗/poet.song.109000.json','["少年重意氣，辭家遠行游。", "高談蔑卿相，峻節凌九秋。", "仗劍謁明主，挾策干諸侯。", "衆目寶康瓠，明月難暗投。", "驊騮困短步，翻爲駑馬羞。", "虛名不足慕，抗迹追浮丘。", "至言發深省，遐覽隘九州。", "書功佐天政，美惡無不籌。", "麾幢周四表，騎衛羅天騶。", "簫鼓鳴清歌，解駕滄浪洲。", "金石易消朽，生死真蜉蝣。"]'),
('83635d5f-532a-4652-baf1-ea12e676049e','浮萍篇','曹勛','宋','宋诗','song-poetry','','[]','昔作章臺柳，今爲清水萍。',96,'全唐诗/poet.song.109000.json','["昔作章臺柳，今爲清水萍。", "寄托一失所，誰分渭與涇。", "王孫事游冶，蘭麝徒芳馨。", "清晨夭桃花，灼灼鮮且榮。", "隨風易零落，不及糞上英。", "萍生八九子，滋育常盈盈。", "芙蓉飾高蓋，文藻疏繁纓。", "寧復事攀折，中心無不平。"]'),
('7b38b948-7c2d-4daa-8c7c-1462caab0504','攀龍引','曹勛','宋','宋诗','song-poetry','','[]','鑄神鼎兮荆之陽，鼎成兮賓帝鄉。',83,'全唐诗/poet.song.109000.json','["鑄神鼎兮荆之陽，鼎成兮賓帝鄉。", "君乘龍兮龍高翔，臣攀龍兮龍髯短。", "龍髯短，接君之衣兮，臣不敢以手挽。", "君棄臣兮臣將疇依，臣慟哭兮君不知。", "君不知兮可奈何，風雨慘慘兮荆山之阿。"]'),
('2dda739f-fd18-4baa-aeef-cfbf6d7080c8','方諸曲二首  其一','曹勛','宋','宋诗','song-poetry','','[]','方諸限弱水，高出扶桑東。',120,'全唐诗/poet.song.109000.json','["方諸限弱水，高出扶桑東。", "霞波環玉壘，雲幄護青宮。", "珠臺錦複道，寶閣亙飛虹。", "翠節迎琱輦，瓊車駕彩龍。", "羣真瞻日御，列聖從青童。", "朝退聯旌旆，杯行奏鼓鐘。", "靈璈激虛籟，雅舞流神風。", "真王拊節和，清響流絕空。", "哀歌悲五濁，胡爲棲樊籠。", "長生有真訣，劫齡安可終。"]'),
('659e5e65-be58-42e5-a5ab-c3f2c3ea5247','方諸曲二首  其二','曹勛','宋','宋诗','song-poetry','','[]','迢迢方諸宮，玉闕排霄起。',132,'全唐诗/poet.song.109000.json','["迢迢方諸宮，玉闕排霄起。", "扶桑高扶疎，森聳數千里。", "碧椹雜青葱，蟠桃映瑶水。", "離離間朱實，鳳鳥護丹蘂。", "靈風灑蘭林，空歌洞霄紫。", "青童會羣真，趣節召揚許。", "安妃從元君，鸞旗翳滄渚。", "翩翩八景輿，鳴珂下容與。", "拊手揚玉音，妙響翔天宇。", "真氣凄金石，聆之廓丹府。", "靈波濯曜羅，朝元道笳鼓。"]'),
('b781d28b-8d3d-4189-b1e5-a6201d940559','蕭史曲','曹勛','宋','宋诗','song-poetry','','[]','玉簫散奇響，真氣凄金石。',72,'全唐诗/poet.song.109000.json','["玉簫散奇響，真氣凄金石。", "招携偶冥會，理愜心自適。", "富貴如朝華，况復多得失。", "胡不希長年，練氣固形質。", "高舉凌仙翰，雙飛上層碧。", "揮手謝時人，去來空役役。"]'),
('8d2faaa6-869a-4db6-9664-11097320d29e','秦王卷衣曲','曹勛','宋','宋诗','song-poetry','','[]','六國歛袵朝秦王，秦王宮闕高相望。',80,'全唐诗/poet.song.109000.json','["六國歛袵朝秦王，秦王宮闕高相望。", "美人充積盈椒房，金珠鉛粉輝煌煌。", "昔爲花與玉，今爲糟與糠。", "感時悲舊事，無意惜年光。", "晝苦短，夜苦長。", "朝朝暮暮卷衣裳，誰復正爾恃紅粧。"]'),
('e6b6bd30-d7fe-428e-87ba-ca0d0e3b7db3','胡笳曲二首  其一','曹勛','宋','宋诗','song-poetry','','[]','江南春草綠，江北未開花。',24,'全唐诗/poet.song.109000.json','["江南春草綠，江北未開花。", "佳人在何處，遷謫寄長沙。"]'),
('eb878c04-e633-4135-9cf1-04d576ea7157','胡笳曲二首  其二','曹勛','宋','宋诗','song-poetry','','[]','漢使通沙漠，胡人過渭橋。',24,'全唐诗/poet.song.109000.json','["漢使通沙漠，胡人過渭橋。", "春風吹客恨，千里去迢迢。"]'),
('e861545e-63fa-4897-aef8-2c92b3462553','鼓吹曲','曹勛','宋','宋诗','song-poetry','','[]','按節臨瀚海，舒軍耀朔方。',72,'全唐诗/poet.song.109000.json','["按節臨瀚海，舒軍耀朔方。", "幕中延揖客，馬首繫降王。", "封君行負弩，天子賜干將。", "後乘騰沙漠，前驅過渭陽。", "簫鼓通平樂，旌旗屬建章。", "明堂獻捷罷，甲矛自生光。"]'),
('91d2129a-892e-4ca9-bb36-49edb29291c6','採桑曲','曹勛','宋','宋诗','song-poetry','','[]','鳴鳩初拂羽，桑葉破新萌。',60,'全唐诗/poet.song.109000.json','["鳴鳩初拂羽，桑葉破新萌。", "采采不盈匊，攀多力未生。", "春服浥朝露，曉日映粧明。", "語學流鶑巧，身同飛燕輕。", "使君勞借問，夫婿自專城。"]'),
('b8410e83-10a5-4194-92b9-da83addd445b','江皋曲','曹勛','宋','宋诗','song-poetry','','[]','漪漣带修渚，遠水明朝暉。',60,'全唐诗/poet.song.109000.json','["漪漣带修渚，遠水明朝暉。", "青山橫倒景，畫鷁掩斜扉。", "游女逢交甫，陳思值洛妃。", "菱歌隨棹遠，鷗鳥背人飛。", "別有嘉游處，芳樽照舞衣。"]'),
('c8c9d34c-e29d-4ccd-8a15-d18f8644efed','泛水曲','曹勛','宋','宋诗','song-poetry','','[]','春服僅能試，荷小未成蓮。',72,'全唐诗/poet.song.109000.json','["春服僅能試，荷小未成蓮。", "畫舫維青幄，平波冪素烟。", "暖日薰花氣，新萍點翠鈿。", "歌吹浮天上，旌旗轉座前。", "促粧留晚景，續酒載歸船。", "前驅戒津吏，除道候江壖。"]'),
('f805fab5-1ce5-43dc-ae44-561818590596','楊花曲','曹勛','宋','宋诗','song-poetry','','[]','千里萬里長安道，送君思君爲君老。',32,'全唐诗/poet.song.109000.json','["千里萬里長安道，送君思君爲君老。", "願爲水底石菖蒲，不教零落同百草。"]'),
('33c34490-6653-4bd0-af71-e09024e486fa','採菱曲','曹勛','宋','宋诗','song-poetry','','[]','修渚通阿閣，蘭舟飾翠旗。',48,'全唐诗/poet.song.109000.json','["修渚通阿閣，蘭舟飾翠旗。", "吳姬年十五，乘舟泛綠池。", "菱花羞寶靨，皓腕發斜暉。", "行歌櫂船去，不覺白鷗飛。"]'),
('4e23252e-7b6a-437b-a562-682a86f50c5d','龍笛曲','曹勛','宋','宋诗','song-poetry','','[]','美人滿酌金屈巵，勸我行樂當及時。',40,'全唐诗/poet.song.109000.json','["美人滿酌金屈巵，勸我行樂當及時。", "艷歌流舞揚光輝。", "揚光輝，照春日。", "壽萬春，歡未畢。"]'),
('ac0305dc-188b-4dee-a089-ce054b7347d4','登山曲','曹勛','宋','宋诗','song-poetry','','[]','禮崇丘，陟重巘。',55,'全唐诗/poet.song.109000.json','["禮崇丘，陟重巘。", "省風俗，緜宇縣。", "集紛埃，鬰葱倩。", "顧秦雍，審伊洛。", "惟前人，肇經度。", "保鴻名兮隆德聲，陋崇高於羣岳。"]'),
('4b6e6184-ff18-46b7-b97d-3e16b92bd746','夜夜曲','曹勛','宋','宋诗','song-poetry','','[]','舞衣疊翡翠，海月掛珊瑚。',24,'全唐诗/poet.song.109000.json','["舞衣疊翡翠，海月掛珊瑚。", "香滿流蘇幄，相迎問醉無。"]'),
('66005100-6ea7-4cb5-9bfc-2a8ca57bf199','鳳凰曲','曹勛','宋','宋诗','song-poetry','','[]','帝子學鳳吹，逸響縈回風。',36,'全唐诗/poet.song.109000.json','["帝子學鳳吹，逸響縈回風。", "雙飛翔紫霞，駕景凌輕虹。", "戢影入青靄，聲斷彩雲空。"]'),
('ed1fbfb4-7063-4970-887e-24ff04e7d888','綠水曲','曹勛','宋','宋诗','song-poetry','','[]','春光有餘輝，入水可攬結。',24,'全唐诗/poet.song.109000.json','["春光有餘輝，入水可攬結。", "予亦淡蕩人，照影空明滅。"]'),
('1b55c33c-a6bb-4bfa-b3cb-b44d2d87b115','塞下曲二首  其一','曹勛','宋','宋诗','song-poetry','','[]','天聲未暢威窮髮，將軍已過長城窟。',32,'全唐诗/poet.song.109000.json','["天聲未暢威窮髮，將軍已過長城窟。", "紅旗半捲夜歸來，馬蹄踏碎天山月。"]'),
('d45c2b5e-dd4d-4c41-b6a3-8974700406ae','塞下曲二首  其二','曹勛','宋','宋诗','song-poetry','','[]','秋草黄雲塞馬肥，漢家驃騎擁旌旗。',32,'全唐诗/poet.song.109000.json','["秋草黄雲塞馬肥，漢家驃騎擁旌旗。", "可能衛霍年年出，不及燕然一片碑。"]'),
('cfbefc6a-0322-4cca-890b-e8ab32fa9adf','入塞曲','曹勛','宋','宋诗','song-poetry','','[]','黑水迢迢黑山暮，馬鳴蕭蕭夜爭度。',48,'全唐诗/poet.song.109000.json','["黑水迢迢黑山暮，馬鳴蕭蕭夜爭度。", "胡笳四起黄雲愁，角聲嗚咽何悠悠。", "隴山行斷不回首，一番回首添白頭。"]'),
('3f3091b9-55f0-403b-809e-a91faa0fedf0','出塞曲','曹勛','宋','宋诗','song-poetry','','[]','來時長驅五千里，滿目胡塵漲天起。',48,'全唐诗/poet.song.109000.json','["來時長驅五千里，滿目胡塵漲天起。", "胡塵已息遼海空，班師來謁明光宮。", "漢家天子耀神武，不知戰士常辛苦。"]'),
('a8469993-83f6-4ab4-b3e9-5b2689af2b0b','楚宮詞三首  其一','曹勛','宋','宋诗','song-poetry','','[]','憶昔君王初選時，侍兒邀寵學蛾眉。',32,'全唐诗/poet.song.109000.json','["憶昔君王初選時，侍兒邀寵學蛾眉。", "而今棄置同衰草，不及章臺楊柳枝。"]'),
('41f35d13-0ca7-493f-9acc-9b1973b24034','楚宮詞三首  其二','曹勛','宋','宋诗','song-poetry','','[]','坐待雞鳴報早朝，那知別殿困笙簫。',32,'全唐诗/poet.song.109000.json','["坐待雞鳴報早朝，那知別殿困笙簫。", "妾身恨不爲鸚鵡，猶恃君王顧盼驕。"]'),
('e41a26e6-ef01-4049-80bd-dfa8f7185db1','楚宮詞三首  其三','曹勛','宋','宋诗','song-poetry','','[]','庭下茸茸碧草齊，不知桃李竟芳菲。',32,'全唐诗/poet.song.109000.json','["庭下茸茸碧草齊，不知桃李竟芳菲。", "自從侍妾承恩後，忘著迎春金縷衣。"]'),
('abc9e017-ce3b-4f4a-9a3f-e27686a7d11c','漢宮詞三首  其一','曹勛','宋','宋诗','song-poetry','','[]','夜漏沉沉度建章，千門萬戶鎖深房。',32,'全唐诗/poet.song.109000.json','["夜漏沉沉度建章，千門萬戶鎖深房。", "入宮不識君王面，猶被傍人妬曉粧。"]'),
('496f618b-59f0-4384-834d-cfa95efaedd8','漢宮詞三首  其二','曹勛','宋','宋诗','song-poetry','','[]','鳷鵲樓高百尺牆，牆高元不礙笙簧。',32,'全唐诗/poet.song.109000.json','["鳷鵲樓高百尺牆，牆高元不礙笙簧。", "君王對面如天遠，可笑梅娘不自量。"]'),
('8ba9742e-9f81-4d55-8f8a-e3c5d7e94cbc','漢宮詞三首  其三','曹勛','宋','宋诗','song-poetry','','[]','費盡千金寫玉容，冀承恩幸寵深宮。',32,'全唐诗/poet.song.109000.json','["費盡千金寫玉容，冀承恩幸寵深宮。", "妾心未改君心改，不及夭桃媚曉風。"]'),
('e6080db0-48b3-4fa3-8254-dbd24234598a','春江花月詞','曹勛','宋','宋诗','song-poetry','','[]','群芳珠箔映青樓，樓上珠簾捲玉鈎。',32,'全唐诗/poet.song.109000.json','["群芳珠箔映青樓，樓上珠簾捲玉鈎。", "十二香衢遍羅綺，青樓和月爲君愁。"]'),
('b60c2249-5082-4d8b-9502-0046ad953fd3','花月詞','曹勛','宋','宋诗','song-poetry','','[]','花光露重春烟濕，鶴去瑶臺人竚立。',48,'全唐诗/poet.song.109000.json','["花光露重春烟濕，鶴去瑶臺人竚立。", "坐見欄干月脚西，景入長門金鎖澀。", "花開直莫媚春風，春風代謝如呼吸。"]'),
('861eaab6-d09a-423f-80c0-55dad561ab11','明月詞','曹勛','宋','宋诗','song-poetry','','[]','明月，明月。',165,'全唐诗/poet.song.109000.json','["明月，明月。", "出滄溟，歷丹闕。", "飛蓋念西園，笙歌想南國。", "靈波如電瀉高丘，雲幄和烟鎖空碧。", "人間何事怨別離，自昔循環有今昔。", "今昔雖同事不同，昔時宮館今荆棘。", "漢家陵闕變池塘，吳楚江山異南北。", "明月那知古與今，治亂昏明有通塞。", "我願三綱不愆，四時不忒。", "天地清寧，人物獲職。", "白兔不見辱于蝦蟆，黄髮蒙照臨之大德。", "非明月之宣功兮，則吾何知其爲順帝之則。"]'),
('ae9cd6c5-5720-406c-892a-afd0ca24d31e','湘妃怨  其一','曹勛','宋','宋诗','song-poetry','','[]','委瓊珮兮重淵，稅鸞車兮深山。',28,'全唐诗/poet.song.109000.json','["委瓊珮兮重淵，稅鸞車兮深山。", "望蒼梧兮不極，與流水而潺湲。"]'),
('39d67e54-0dc7-4dbe-8a0d-43bee65d0757','湘妃怨  其二','曹勛','宋','宋诗','song-poetry','','[]','風凄凄兮山之阻，雲溟溟兮湘之浦。',32,'全唐诗/poet.song.109000.json','["風凄凄兮山之阻，雲溟溟兮湘之浦。", "落日黄兮明月輝，古木蒼烟號兕虎。"]'),
('9517e7d3-992f-45ee-8cc0-53f8f7ec0fb1','湘妃怨  其三','曹勛','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雨瀟瀟兮洞庭，烟霏霏兮黄陵。',28,'全唐诗/poet.song.109000.json','["雨瀟瀟兮洞庭，烟霏霏兮黄陵。", "望夫君兮不來，波渺渺而難升。"]'),
('8747a2ee-8ce7-48ce-8b8f-62c647be2363','昭君怨四首  其一','曹勛','宋','宋诗','song-poetry','','[]','人生無定端，萬事固難料。',112,'全唐诗/poet.song.109000.json','["人生無定端，萬事固難料。", "美好招世患，讒謟過忠告。", "正淑不自媚，私謁事妍笑。", "入宮踰十年，嫉妬掩稱道。", "疎賤難爲容，况復昧傾巧。", "一朝見排棄，衆笑蛾眉好。", "驅車臨出門，盛飾舒懷抱。", "不怨君王遠，不怨父兄老。", "唯怨蛾眉悞一生，榮枯不得同百草。"]'),
('5d266247-09f1-4779-b530-2837af795a17','昭君怨四首  其二','曹勛','宋','宋诗','song-poetry','','[]','再拜升車望已過，却教紅粉保山河。',32,'全唐诗/poet.song.109000.json','["再拜升車望已過，却教紅粉保山河。", "當時豈止毛延壽，對面欺君事更多。"]'),
('f3bc3ae6-40f3-4ca3-b669-a738516e50a9','昭君怨四首  其三','曹勛','宋','宋诗','song-poetry','','[]','從來貧賤少先容，况復嬌癡入漢宮。',32,'全唐诗/poet.song.109000.json','["從來貧賤少先容，况復嬌癡入漢宮。", "一朝掩面辭君去，始悔無金買畫工。"]'),
('46312de0-71f5-4d7a-b11d-c3b532ee28f0','昭君怨四首  其四','曹勛','宋','宋诗','song-poetry','','[]','盛飾容儀舍掖庭，豈知妍醜悞丹青。',32,'全唐诗/poet.song.109000.json','["盛飾容儀舍掖庭，豈知妍醜悞丹青。", "不羞見辱單于室，羞見年名作竟寧。"]'),
('6738df65-a057-4b54-8f3a-fc674c0fa0c9','婕妤怨','曹勛','宋','宋诗','song-poetry','','[]','素媿河洲德，寧忘卷耳規。',48,'全唐诗/poet.song.109000.json','["素媿河洲德，寧忘卷耳規。", "中闈知奉順，外戚敢營私。", "辭輦翻成妬，能歌復見知。", "自慚乖嫵媚，不及舞腰兒。"]'),
('4c3e5a68-a7ff-40b7-a7bb-de21307f2443','春閨怨','曹勛','宋','宋诗','song-poetry','','[]','著意繡鴛鴦，雙雙戲小塘。',24,'全唐诗/poet.song.109000.json','["著意繡鴛鴦，雙雙戲小塘。", "繡罷無心看，楊花滿繡牀。"]'),
('ca39fe25-099d-4f3b-9ab7-2b75567775af','秋閨怨','曹勛','宋','宋诗','song-poetry','','[]','憂勤番作妬，險詖自爲才。',60,'全唐诗/poet.song.109000.json','["憂勤番作妬，險詖自爲才。", "趙瑟絃初絕，秦箏曲更哀。", "蛛網羅粧鑑，庭蕪暗玉階。", "聽雞雖自誤，辭輦却成非。", "猶謝昭陽月，時來照寢衣。"]'),
('a26995ed-d061-4ca6-936d-d684aca88596','閨怨','曹勛','宋','宋诗','song-poetry','','[]','頭上百寶釵，終身不相失。',24,'全唐诗/poet.song.109000.json','["頭上百寶釵，終身不相失。", "唯有鴛鴦席，承歡難可畢。"]'),
('78286e50-fd09-4c7c-bdbe-aa3eb2965a28','玉階怨','曹勛','宋','宋诗','song-poetry','','[]','堂上燼銀釭，閨中下羅幕。',24,'全唐诗/poet.song.109000.json','["堂上燼銀釭，閨中下羅幕。", "思君度遥夕，長於金井索。"]'),
('0de76b97-7c0a-4fb1-b87e-02f49cd36600','幽閨怨','曹勛','宋','宋诗','song-poetry','','[]','妾年十五從良人，良人待旦驅從軍。',48,'全唐诗/poet.song.109000.json','["妾年十五從良人，良人待旦驅從軍。", "至今遠戍燕山北，但見春歸秋草碧。", "年年塞雁去還來，深院無人空綠苔。"]'),
('8dca6829-d71f-43bc-9436-598de2412f0a','春日有所思','曹勛','宋','宋诗','song-poetry','','[]','陽春被華旦，草木蒙恩私。',108,'全唐诗/poet.song.109000.json','["陽春被華旦，草木蒙恩私。", "沉沉幽谷蘭，不得同其施。", "女蘿託喬松，光彩紛葳蕤。", "游塵薄雄風，光景低鬰儀。", "巖花落深澗，甘爲井底泥。", "升沉固難量，寧復論高卑。", "佳人去已遠，良遇安可期。", "流年易凋落，榮盛能幾時。", "促席具樽酒，不醉夫何爲。"]'),
('b879e4c1-2b85-42d1-8952-9844e8826879','有所思二首  其一','曹勛','宋','宋诗','song-poetry','','[]','有所思兮天一涯，彼美人兮安得知。',80,'全唐诗/poet.song.109000.json','["有所思兮天一涯，彼美人兮安得知。", "江臯送日下洲渚，心遥目斷征鴻飛。", "蘭嗟蕙怨芳草歇，春歸猶見霏霏雪。", "文姬著破去時衣，寂寞愁看漢家月。", "南箕北斗苦相望，綿綿此恨無時絕。"]'),
('48a9a438-bc61-4fc4-bf80-5f3762abf351','有所思二首  其二','曹勛','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','有所思，藐何許。',61,'全唐诗/poet.song.109000.json','["有所思，藐何許。", "乃在洞庭之陽，瀟湘之浦。", "我欲訪之限重阻。", "水有吞舟之巨魚兮，山有食人之猛虎。", "有所思，藐何許，沉沉靜夜愁風雨。"]'),
('74ad0254-99ab-4ca3-98c0-9833679cf64b','遺所思','曹勛','宋','宋诗','song-poetry','','[]','君行既云遠，我思日以長。',108,'全唐诗/poet.song.109000.json','["君行既云遠，我思日以長。", "思君無所遺，寶带雙鴛鴦。", "鴛鴦不相失，錦翼游方塘。", "副之玳瑁簪，同心復同房。", "上有金蓮花，莖葉相扶將。", "下有並根藕，藕絲百尺長。", "同緘尺素書，封以紫錦囊。", "上言長相憶，下言莫相忘。", "努力加餐飯，歸來花正芳。"]'),
('deb43c9a-e0ea-4268-b958-14d73f62b4c4','思遠人','曹勛','宋','宋诗','song-poetry','','[]','有美人兮天之涯，食蘭菊兮服錦衣，披瓊簡兮規天維。',87,'全唐诗/poet.song.109000.json','["有美人兮天之涯，食蘭菊兮服錦衣，披瓊簡兮規天維。", "隔昆丘之遐阻兮，限弱水之漫瀰。", "曾故人之莫吾知兮，曠千載而不歸。", "歲冉冉其將莫兮，儼吾駕而不可以徒回。", "幾逍遥於山阿，思夫君於式微。"]'),
('7c11c1be-8d1d-4013-9372-ee017dce975d','天陰望鍾山','曹勛','宋','宋诗','song-poetry','','[]','塵土不滿眼，飛鴻入無倪。',76,'全唐诗/poet.song.109000.json','["塵土不滿眼，飛鴻入無倪。", "摇情望鍾山，巖壑移東西。", "荆榛蔽青靄，上下紛冥迷。", "昔人去已遠，草堂懷煙霏。", "此意竟何往，緬懷誰與追。", "胡爲命駕一登覽，誅除氛祲褰雲旂。"]'),
('505dcc99-764f-4e13-a7ae-1d77687ffa5d','胡姬年十五','曹勛','宋','宋诗','song-poetry','','[]','胡姬年十五，媚臉明朝霞。',60,'全唐诗/poet.song.109000.json','["胡姬年十五，媚臉明朝霞。", "當壚一笑粲，桃葉映桃花。", "王孫停寶馬，公子駐香車。", "學歌裝翡翠，看月弄琵琶。", "不顧金吾子，誰看白鼻騧。"]'),
('4e9e6d53-63a1-4e0c-b041-f161d84c2996','長信宮中草','曹勛','宋','宋诗','song-poetry','','[]','長信宮中草，年來特地長。',24,'全唐诗/poet.song.109000.json','["長信宮中草，年來特地長。", "無人同步輦，門外度斜陽。"]'),
('f0e209ed-faad-47b1-85e4-db0f76a8a008','前有一樽酒','曹勛','宋','宋诗','song-poetry','','[]','前有一樽酒，高張發清彈。',144,'全唐诗/poet.song.109000.json','["前有一樽酒，高張發清彈。", "娥眉揚玉澤，雅舞凌七盤。", "春容媚桃李，艷色夭且妍。", "向我如笑粲，舉酒相爲歡。", "對此如不飲，人生良可歎。", "君不見當年項王之力能拔山，驅除天下猶轉圜。", "又不見儀秦挾策騁雄辯，指揮七國隨縱橫。", "一朝智力有所困，誅滅不得同編氓。", "成敗苟如此，貧賤固所安。", "勸君酩酊寄樽酒，人間萬事無足觀。"]'),
('d6ff787e-60a8-418c-83cf-157af8e4daf5','京口有歸燕','曹勛','宋','宋诗','song-poetry','','[]','春烟晝白春草綠，春水溶溶曲江曲。',160,'全唐诗/poet.song.109000.json','["春烟晝白春草綠，春水溶溶曲江曲。", "吳宮梁苑盡灰飛，胡馬驕嘶銜苜蓿。", "蕭條南國閟春愁，章臺瑶室今茅屋。", "中原民庶被氈裘，萬室無人皆鼠伏。", "子歸何處定安巢，楚幕雖多易傾覆。", "感君爲君思建章，萬戶朱門綴珠玉。", "當時天下尚無爲，今日悲凉變何速。", "感君歌，爲君哭，汾陽已死淮陰族。", "沉沉壯士聽晨雞，豺狼當路食人肉。", "燕齊鄒魯化腥膻，番人走馬鳴𨏔轆。"]'),
('e1fa53f2-e62e-469d-9710-0a88687650b4','人生不長好','曹勛','宋','宋诗','song-poetry','','[]','人生不長好，倏忽如蕣英。',72,'全唐诗/poet.song.109000.json','["人生不長好，倏忽如蕣英。", "臨觴莫辭醉，既醉莫願醒。", "但識醉中理，無欲醒時名。", "夷齊猶餓死，誰復哀屈平。", "陵谷尚遷滅，况乃期促齡。", "已焉謝消長，得失秋毫輕。"]'),
('8d838aa1-9053-496d-bd3d-fcbe33498eb4','姑蘇臺上月','曹勛','宋','宋诗','song-poetry','','[]','姑蘇臺上月，倒景浮天河。',132,'全唐诗/poet.song.109000.json','["姑蘇臺上月，倒景浮天河。", "石梁卧長洲，垂虹躍金波。", "叢薄散蘭麝，水底流笙歌。", "歌聲未斷樽前舞，越兵夜入三江浦。", "吳王沉醉未及醒，不知身已爲降虜。", "響靸廊前珠翠橫，採香徑裏喧鼙鼓。", "西施和淚下珠樓，回首吳宮隔烟霧。", "姑蘇臺殿變秋蓬，荆棘霑衣泣寒露。", "至今風月動凄凉，餘址石橋尚如故。"]'),
('a9062cc3-2de6-4e63-8ea4-ed485fc15271','錦石擣流黄','曹勛','宋','宋诗','song-poetry','','[]','秋風清，秋月明，征人思婦難爲情。',56,'全唐诗/poet.song.109000.json','["秋風清，秋月明，征人思婦難爲情。", "難爲情，蟋蟀遠壁鳴寒聲，霜砧皓腕愁不勝。", "愁不勝，愁不可剪衣可成，夢君先到黄龍庭。"]'),
('9c1bc87d-31e8-4821-8c9c-ce388c4441c6','自君之出矣二首  其一','曹勛','宋','宋诗','song-poetry','','[]','自君之出矣，龍香消寶衣。',24,'全唐诗/poet.song.109000.json','["自君之出矣，龍香消寶衣。", "思君共明月，千里奉光輝。"]'),
('19f44a61-4cc0-43ec-8544-289c73e1ebb6','自君之出矣二首  其二','曹勛','宋','宋诗','song-poetry','','[]','自君之出矣，粧臺生網絲。',24,'全唐诗/poet.song.109000.json','["自君之出矣，粧臺生網絲。", "思君拂團扇，相與共提携。"]'),
('95041b44-461b-447e-b78a-2bf0231dbbc0','迢迢高樓入紫烟','曹勛','宋','宋诗','song-poetry','','[]','迢迢高樓入紫烟，上連阿閣巢青鸞。',64,'全唐诗/poet.song.109000.json','["迢迢高樓入紫烟，上連阿閣巢青鸞。", "青鸞飛飛不復返，朱甍碧瓦空般般。", "而今燕雀互棲止，便便飽逸嗤鷹鸇。", "黄金臺廢燕昭死，嗟嗟誰復旌遺賢。"]'),
('61963089-6ef0-4cc2-bc6e-f0e4f9343f9f','邯鄲才人嫁爲廝養卒婦','曹勛','宋','宋诗','song-poetry','','[]','落葉逐驚風，落花逐流水。',84,'全唐诗/poet.song.109000.json','["落葉逐驚風，落花逐流水。", "漂零無定端，寄託隨所委。", "朝榮瑶圃中，暮落窮轍裏。", "豈不惡糟糠，豈不願羅綺。", "羅綺閉深宮，嫉妬交相靡。", "糟糠守窮廬，苦樂同終始。", "行藏宜自然，燕巢茅屋底。"]'),
('9b878710-0505-40ee-be2b-ee09d09f06d0','上之回','曹勛','宋','宋诗','song-poetry','','[]','衛騎絕沙漠，前驅過玉門。',72,'全唐诗/poet.song.109000.json','["衛騎絕沙漠，前驅過玉門。", "雲旗梢月窟，輦道屬烏孫。", "萬國森環衛，三靈駭駿奔。", "聲容同日月，威德被乾坤。", "巡狩知無外，蠻戎識至尊。", "何當鳴警蹕，高會醼崑崙。"]'),
('1c76d9bb-ab66-423e-8a7d-a243734f1a9a','當置酒','曹勛','宋','宋诗','song-poetry','','[]','置酒臨芳觀，張筵繼落暉。',72,'全唐诗/poet.song.109000.json','["置酒臨芳觀，張筵繼落暉。", "選妓調絲竹，迎賓奉酒巵。", "月影移歌扇，花光照舞衣。", "霞觴飛白羽，高論吐虹霓。", "人生不滿百，行樂當及時。", "當歌期酩酊，誰能較是非。"]'),
('c928343c-7604-49fb-8e69-571c4a172eae','將進酒','曹勛','宋','宋诗','song-poetry','','[]','君唐虞兮臣臯夔，將衛霍兮恢邊陲。',199,'全唐诗/poet.song.109000.json','["君唐虞兮臣臯夔，將衛霍兮恢邊陲。", "時文景兮民雍熙，獄無寃人兮野無蒿藜。", "玉燭亙天流離以昭兮，其惟百姓日用而不知。", "歌鹿鳴與既醉兮，而頌聲洋溢乎康逵。", "顧吾君之清靜躬儉以寂默兮，而猶薄滋味與游嬉。", "臣願得連四海以爲席兮，酌北斗而爲酒巵。", "使五老奉觴上壽以申祝兮，令夫八元夾侍而正儀。", "願聖壽上齊於箕翼兮，其光容充塞於四維。", "醉大道與仁義兮，而淳風浹洽於華夷。", "期億萬斯年兮，民皆陶陶而化之。", "慶君臣之嘉會，陋酆鎬與瑶池。"]'),
('79919ac2-2c41-4716-9181-4ffee16dc3d0','艾如張','曹勛','宋','宋诗','song-poetry','','[]','鴻鵠遠罾繳，燕雀戀藩籬。',48,'全唐诗/poet.song.109000.json','["鴻鵠遠罾繳，燕雀戀藩籬。", "爭食蓬蒿下，觸網斃禍機。", "黄雀老且黠，黄口小且癡。", "黄雀戒黄口，輙莫貪腥肥。"]'),
('e924846d-599d-4fea-b2ab-ef9b0933011c','遠如期','曹勛','宋','宋诗','song-poetry','','[]','約指金環瘦不持，羅衣寬盡減腰圍。',28,'全唐诗/poet.song.109000.json','["約指金環瘦不持，羅衣寬盡減腰圍。", "紅芳坐消歇，王孫歸不歸。"]'),
('1015413b-946c-479e-9620-ee067281eb59','反招隠','曹勛','宋','宋诗','song-poetry','','[]','驊騮天下駿，所制在服箱。',156,'全唐诗/poet.song.109000.json','["驊騮天下駿，所制在服箱。", "蘇秦天下辯，所失戀冠裳。", "達人貴自重，出處保龍光。", "山花麗雲錦，鳥語調絲簧。", "清泉激鳴琴，掩抑合宮商。", "芝朮勝粱肉，蘭菊有餘芳。", "白雲結山友，來往俱相忘。", "世路甚谿谷，簪笏誠羈韁。", "人心若丘山，咫尺不可量。", "猿鶴熟可馴，人熟不可防。", "留侯從赤松，范蠡辭越王。", "二子保令終，避世容何傷。", "王孫促歸軫，吾徒方退藏。"]'),
('e04ac9a2-d49d-4bee-a7c4-e5753a874b95','獨不見','曹勛','宋','宋诗','song-poetry','','[]','獨不見，誰相憶。',80,'全唐诗/poet.song.109000.json','["獨不見，誰相憶。", "花影上珠簾，明月穿窗隙。", "翡翠暗無光，蒼苔點行迹。", "鸞鑑掛珊瑚，寶靨銷金碧。", "彷彿聞簫韶，夢想見顔色。", "爲我報新人，好好承恩澤。", "君看後庭花，芳菲能幾日。"]'),
('0f9389d2-3c4f-4d19-8c65-6ede749d68c3','牀前帳','曹勛','宋','宋诗','song-poetry','','[]','蜀錦牀前帳，四角垂香囊。',48,'全唐诗/poet.song.109000.json','["蜀錦牀前帳，四角垂香囊。", "上有合歡带，下有雙鴛鴦。", "鴛鴦一分散，不得同所將。", "棄捐篋笥裏，誰惜舊時香。"]'),
('bcd62b14-14d8-473d-ab8d-fc90b2782fd3','紫騮馬','曹勛','宋','宋诗','song-poetry','','[]','紫騮馬，出西方。',176,'全唐诗/poet.song.109000.json','["紫騮馬，出西方。", "徑萬國，來咸陽。", "儲精房，鍾馴良。", "口如米火頭如王，尾輕鬣短龍脊剛。", "蹄圓腕蹙森開張，齊平六齒排截肪。", "目如明星威煌煌，驕嘶噴薄思騰驤。", "廕以華屋薦露牀，金羈玉勒紅錦障，鈎膺絡腦垂璫琅。", "漢家驃騎新開府，天子輟賜威遐荒。", "將軍橫槊被金甲，矍鑠超忽踰鷹揚。", "雄鳴矯首厲奔蹙，胡兒百萬紛披攘。", "登封居胥轉瀚海，軍聲陸讋摧天狼。", "歸來明堂見天子，圖形麟閣宣龍光。"]'),
('b65be316-a00a-4a1b-b374-ac00ab0e590e','王孫游二首  其一','曹勛','宋','宋诗','song-poetry','','[]','紅芳開繡戶，碧草襯斜陽。',24,'全唐诗/poet.song.109000.json','["紅芳開繡戶，碧草襯斜陽。", "樓上頻回首，思君道路長。"]'),
('abfe7416-e275-4261-8984-9d482a3d6471','王孫游二首  其二','曹勛','宋','宋诗','song-poetry','','[]','夭桃與芳草，艷色明朝陽。',24,'全唐诗/poet.song.109000.json','["夭桃與芳草，艷色明朝陽。", "思君念華旦，賤妾惜容光。"]'),
('7f5de7cb-b6f9-4dfb-af8f-be3873cf1201','烏夜啼二首  其一','曹勛','宋','宋诗','song-poetry','','[]','饑鳥啞啞不肯棲，雄飛呼雌鳴聲悲。',48,'全唐诗/poet.song.109000.json','["饑鳥啞啞不肯棲，雄飛呼雌鳴聲悲。", "娼樓年少醉歌舞，幽閨思婦寂無語。", "將軍百戰未成功，坐數更籌聽金鼓。"]'),
('ab5a608c-f9fb-4439-b7c9-8b973f1219ce','烏夜啼二首  其二','曹勛','宋','宋诗','song-poetry','','[]','月落啼烏近鎖窗，鎖窗深處繡鴛鴦。',48,'全唐诗/poet.song.109000.json','["月落啼烏近鎖窗，鎖窗深處繡鴛鴦。", "鴛鴦未就腸先結，馬踏天山夜飛雪。", "歸來且莫話封侯，同醉笙歌弄明月。"]'),
('cf3df3dc-b257-4f08-8d7d-0e452c183114','望行人','曹勛','宋','宋诗','song-poetry','','[]','西北有高樓，䆗窱入空碧。',60,'全唐诗/poet.song.109000.json','["西北有高樓，䆗窱入空碧。", "徙倚徧欄干，楊花滿行迹。", "不見行人歸，但有楊花白。", "披襟向春風，爲我傳消息。", "春風不見知，此意無人識。"]'),
('0018694c-ab7e-431c-9e5e-381d0e05fb09','行路難','曹勛','宋','宋诗','song-poetry','','[]','華堂高張千炬燭，光溢樽罍艷流目。',130,'全唐诗/poet.song.109000.json','["華堂高張千炬燭，光溢樽罍艷流目。", "秦姬趙女變新聲，入金石兮裂絲竹。", "少年意氣凌秋陽，奴僕金張嗤宋玉。", "文章富貴何足論，胡必直欲身後名。", "顔回風雨困簞食，伯夷葵藿難爲情。", "何如嫖姚十八從將軍，恩隆愛密收奇勳。", "美人歌舞謝芳草，春花落盡容顔老。", "山長水闊霜雪寒，安用區區涉遠道。"]'),
('c67d3c9d-9e8c-44b5-ba42-63a76489972c','又','曹勛','宋','宋诗','song-poetry','','[]','行路難，行路難，九折之坂無足歎。',116,'全唐诗/poet.song.109000.json','["行路難，行路難，九折之坂無足歎。", "羊腸劍閣視階闥，巫峽灧澦無波瀾。", "長安九衢最巇嶮，侯門處處深如淵。", "深如淵，不可履，翻覆風波當面起。", "况復深宮嚴九重，雖有羽翼無由通。", "行路難，行路難，不如歸去貧窮靜坐巾柴關。", "啜菽飲水自行樂，雖有風雨無憂患。"]'),
('7abef5b0-45fb-4542-9ff2-df15bee44360','歸去來','曹勛','宋','宋诗','song-poetry','','[]','歸去來，歸去來。',186,'全唐诗/poet.song.109000.json','["歸去來，歸去來。", "陸行無車，水行無船。", "足重繭兮，羊腸九折，歷絕嶮而盤盤。", "跼蹐脅息以休影兮，石壁屹立而不可以攀緣。", "上窺不測之夭嶠兮，而下臨無底之深淵。", "寒風凜凜以切骨兮，朔雪漫漫而漲天。", "孤猿哀吟其左右兮，而猛虎咆哮乎後先。", "緬前路之險阻其若此兮，道云遠而莫前。", "悲已往之勤瘁兮，淚流襟而漣漣。", "歸去來，歸去來。", "吾鄉雖遠兮，及此而猶可以生還。", "饑寒迫於屢空兮，庶乎安之若命而終保吾之天年。"]'),
('bf8aaf74-391b-481e-8c64-daaad706d777','沐浴子','曹勛','宋','宋诗','song-poetry','','[]','新沐莫彈冠，新浴莫振衣。',84,'全唐诗/poet.song.109000.json','["新沐莫彈冠，新浴莫振衣。", "聖人貴同塵，賢者汩其泥。", "夷齊立峻節，感激歌採薇。", "子真老谷口，歲晏無苦饑。", "屈原懷獨醒，沉湘誰與悲。", "漁父隨其波，所適安所宜。", "君看侯門客，饑于紈袴兒。"]'),
('f906c046-a930-442e-9519-7ab026cb3d37','樂未央','曹勛','宋','宋诗','song-poetry','','[]','孝武初封禪，蘿圖寶曆新。',48,'全唐诗/poet.song.109000.json','["孝武初封禪，蘿圖寶曆新。", "開邊擢衛霍，儒術用平津。", "禮樂追三統，欽承奉百神。", "嵩呼膺萬壽，歡樂詎容陳。"]'),
('d94ae748-1967-4bb5-9437-4946b7fad15d','荆門道','曹勛','宋','宋诗','song-poetry','','[]','荆門道，在何許，萬里迢迢入南楚。',64,'全唐诗/poet.song.109000.json','["荆門道，在何許，萬里迢迢入南楚。", "故人何事未歸來，滿目豺狼路多阻。", "路多阻兮可奈何，矍鑠廉公亦奚取。", "期君終日醉如泥，賢似靈均醒時語。"]'),
('d33e1a47-d408-4923-9eef-03bc2206e926','臨碣石  其一','曹勛','宋','宋诗','song-poetry','','[]','肅我嚴駕，登彼絕阪。',30,'全唐诗/poet.song.109000.json','["肅我嚴駕，登彼絕阪。", "目極天淵，曾不知遠。", "曜靈舒光，樂彼鰷鰋。"]'),
('02e460b5-3163-49cb-892f-d67515cd4b9f','臨碣石  其二','曹勛','宋','宋诗','song-poetry','','[]','杲日既升，我徒既盈。',30,'全唐诗/poet.song.109000.json','["杲日既升，我徒既盈。", "願言斯適，至樂無聲。", "撫躬增愧，臨深可驚。"]'),
('1bdf6945-c608-4cef-8b8e-f1629ab23553','臨碣石  其三','曹勛','宋','宋诗','song-poetry','','[]','陟彼崇高，慨覽遐宇。',40,'全唐诗/poet.song.109000.json','["陟彼崇高，慨覽遐宇。", "前迹可究，興亡可悟。", "安得英雄，廓彼神武。", "澤及飛沉，致馨梁甫。"]'),
('0bd55685-2dfd-451d-854b-0a8b8a357d92','巫山高','曹勛','宋','宋诗','song-poetry','','[]','巫山高，望不極。',56,'全唐诗/poet.song.109000.json','["巫山高，望不極。", "飛鴻欲度愁無力，我欲絕之乏羽翼。", "峽江水急荆門遠，魚龍游之不能轉。", "下無舟楫上無梁，我欲濟之憂力尠。"]'),
('bac65532-e5fd-4d7e-8c43-f8391116b07b','懷長沙','曹勛','宋','宋诗','song-poetry','','[]','有若人兮眇何所，投蘭袂兮江之滸。',68,'全唐诗/poet.song.109000.json','["有若人兮眇何所，投蘭袂兮江之滸。", "杜蘅約席兮桂柏爲宇，胡爲乎終年而在茲。", "前有沅湘之深水兮，後有岳麓之重阻。", "聊逍遥於山阿，可以避歲寒之風雨。"]'),
('2608efe8-f96b-441e-99c2-982c9dc04a81','空城雀二首  其一','曹勛','宋','宋诗','song-poetry','','[]','去年已生子，今年復生孫。',123,'全唐诗/poet.song.109000.json','["去年已生子，今年復生孫。", "主人既昏亂，國破家亦焚。", "宮館變禾黍，萬人無一存。", "朝伏蓬蒿下，暮宿荆莽間。", "豈不念儔侶，豈不懷玉山。", "儔侶高飛斃繒繳，玉山迢遞多鷹鸇。", "又不見咸陽三月火不滅，吳宮萬戶飛灰烟。", "春鴻社燕尚燒死，况復黄口乏修翰。", "喜無挾彈兒，空城姑所安。"]'),
('894a01f5-693d-46bf-bf11-03cc8ad98177','空城雀二首  其二','曹勛','宋','宋诗','song-poetry','','[]','寂寂空城雀，日暮寒且饑。',105,'全唐诗/poet.song.109000.json','["寂寂空城雀，日暮寒且饑。", "鼯鼠啼林端，豺虎夾路垂。", "蒿間黄雀語黄口，吞聲切莫圖高棲。", "汝不見當年連雲宮館散烟燎，歌臺夾室今狐狸。", "糟丘成糞壤，藜藿生酒池。", "昔人自是不復改，今人始覺前人非。", "今人昔人未爲遠，更望誰家門戶歸。"]'),
('4a608cde-5408-48eb-b6dc-20ac1d8a5545','楚妃歎五首  其一','曹勛','宋','宋诗','song-poetry','','[]','日晚章華翠輦歸，寂寥深院鎖重扉。',32,'全唐诗/poet.song.109000.json','["日晚章華翠輦歸，寂寥深院鎖重扉。", "非緣掩鼻移恩寵，自是新人巧用機。"]'),
('39ed6861-fea9-4668-8500-3671b95ee299','楚妃歎五首  其二','曹勛','宋','宋诗','song-poetry','','[]','用意十分巧畫眉，粧成獨自惜容儀。',32,'全唐诗/poet.song.109000.json','["用意十分巧畫眉，粧成獨自惜容儀。", "非緣鄭袖能歌舞，自是人心著處迷。"]'),
('7a14c7e7-4d17-40d8-ba85-dfde15688725','楚妃歎五首  其三','曹勛','宋','宋诗','song-poetry','','[]','霜滿虛庭月滿樓，羅帷珠箔閉清秋。',32,'全唐诗/poet.song.109000.json','["霜滿虛庭月滿樓，羅帷珠箔閉清秋。", "鑪香烟斷添銀燭，誰道更深睡去休。"]'),
('34ddb4a0-103e-421a-a7f7-4fa18b1f3d0e','楚妃歎五首  其四','曹勛','宋','宋诗','song-poetry','','[]','寶靨香銷翠幄寬，更深明月上闌干。',32,'全唐诗/poet.song.109000.json','["寶靨香銷翠幄寬，更深明月上闌干。", "徘徊踏碎銀蟾影，誰念從來不耐寒。"]'),
('2df7aebb-ff77-42c0-90fc-2514ebcb1a84','楚妃歎五首  其五','曹勛','宋','宋诗','song-poetry','','[]','人靜宮深夜漏長，深宮漏永憶君王。',32,'全唐诗/poet.song.109000.json','["人靜宮深夜漏長，深宮漏永憶君王。", "可憐不及秋蒲草，猶得承歡薦寶牀。"]'),
('409b4120-dc2c-4402-b2ef-fb27c220dc72','隴頭水','曹勛','宋','宋诗','song-poetry','','[]','隴頭之水兮，不可以濺衣。',62,'全唐诗/poet.song.109000.json','["隴頭之水兮，不可以濺衣。", "隴頭之雲兮，不可以同歸。", "事行役兮無已時。", "無已時，千里萬里從旌旗。", "風雨慘慘兮寒且饑，隴頭之水兮鳴聲悲。"]'),
('2ad9b98b-df0b-4532-a47d-03b85859f9a5','莫獨行','曹勛','宋','宋诗','song-poetry','','[]','莫獨行，風雨慘慘兮夜不得明。',68,'全唐诗/poet.song.109000.json','["莫獨行，風雨慘慘兮夜不得明。", "道有石坂兮，使汝車敗而馬驚。", "山有猛虎兮水多暴鯨，任重塗遠兮無欲速其小程。", "莫獨行，莫獨行，聊可以俟同志之友生。"]'),
('5d922ce9-e07e-4b6a-a4a0-8c259db15227','古戰場','曹勛','宋','宋诗','song-poetry','','[]','烟冥露重霜風號，聲悲色慘侵征袍。',176,'全唐诗/poet.song.109000.json','["烟冥露重霜風號，聲悲色慘侵征袍。", "據鞍顧盼度沙磧，縱橫白骨餘殘燒。", "舉鞭遲留問田父，彼將欲語先折腰。", "泣云畔寇昔據此，老夫父子服弓刀。", "將軍下令起丘甲，法嚴勢迫無所逃。", "攻城奪險數十戰，民殘兵弊夷梟巢。", "當時二子沒於陣，老夫幸免甘無聊。", "匹夫僭亂起阡陌，禍延千里俱嗷嗷。", "官私所殺盡民吏，坐令骨肉相征鏖。", "唯餘將軍封萬戶，士卒戰死埋蓬蒿。", "至今野火遍昏黑，天陰鬼哭聲嘈嘈。"]'),
('1a601940-af35-484a-9339-03dc1888737a','戰城南','曹勛','宋','宋诗','song-poetry','','[]','胡騎方侵掠，臨淮厲虎兵。',60,'全唐诗/poet.song.109000.json','["胡騎方侵掠，臨淮厲虎兵。", "三麾俱至地，一戰破思明。", "令下秋霜肅，威行草木驚。", "豈但全孤壘，能令復舊京。", "吾君方用武，宵旰念儀刑。"]'),
('73af5899-d649-46dd-a685-385ab3d0c8f6','箕山操','曹勛','宋','宋诗','song-poetry','','[]','草可以爲衣兮，木可以爲廬。',87,'全唐诗/poet.song.109000.json','["草可以爲衣兮，木可以爲廬。", "水清石白兮，渴飲有時而饑食有餘。", "止不知其吾之有影兮，而行不知其吾之有軀。", "彼日月之自明兮，吾又安知其所如。", "君乎君乎，且將浼我以天下，而無迺不幾於贅乎。"]'),
('bc417e04-6d07-4d8a-a0c1-573e9f1a1981','小游仙三首  其一','曹勛','宋','宋诗','song-poetry','','[]','九霄風靜夜沉沉，仙籟虛徐度玉音。',32,'全唐诗/poet.song.109000.json','["九霄風靜夜沉沉，仙籟虛徐度玉音。", "好是太真歌未闋，飛烟遥上鬰華林。"]'),
('fcf1940a-844c-44ee-95c1-1ad00337db6a','小游仙三首  其二','曹勛','宋','宋诗','song-poetry','','[]','十二層城倚閬風，金臺珠樹鬰葱葱。',32,'全唐诗/poet.song.109000.json','["十二層城倚閬風，金臺珠樹鬰葱葱。", "遥瞻玉室藏書府，萬仞飛光散曉紅。"]'),
('878fa21a-d35c-4d97-a40e-81330194bfca','小游仙三首  其三','曹勛','宋','宋诗','song-poetry','','[]','摇曳空歌上玉清，飛烟冉冉拂仙纓。',32,'全唐诗/poet.song.109000.json','["摇曳空歌上玉清，飛烟冉冉拂仙纓。", "龍軿已過黄金闕，致肅門郎識姓名。"]'),
('6e0f402e-7652-4079-b929-f987b0546324','春光好','曹勛','宋','宋诗','song-poetry','','[]','十年不見春光好，胡人馬齧長安草。',108,'全唐诗/poet.song.109000.json','["十年不見春光好，胡人馬齧長安草。", "長安草盡人已空，宮館園林迹如掃。", "東都西洛暗兵塵，晝引狐狸上黄道。", "長淮水淺吳山低，戍邊時巡無已時。", "無已時，萋萋草綠胡馬肥。", "濠城短小不蔽眼，况復瑣屑游芳菲。", "何當仗劍從神武，晴春甲馬爭光輝。"]'),
('e3afe5ed-e983-4b10-9036-fc8fc4c0bf8a','送春歸','曹勛','宋','宋诗','song-poetry','','[]','送春歸，在何處。',116,'全唐诗/poet.song.109000.json','["送春歸，在何處。", "禾黍正離離，江城匝屯戍。", "楊花零亂點旌旗，天涯芳草連雲暮。", "舊園桃李遍荆棘，故國樓臺盡狐兔。", "衣冠不見洛陽花，胡馬猶嘶漢宮樹。", "吳江水綠吳山青，春到春歸別有情。", "柳色迎人下關塞，隨軍萬里清胡塵。", "黄金臺榭未埋沒，當年勿謂秦無人。"]'),
('c13b589e-ad1c-438b-8a4d-96b4058ac0f2','秋夜長','曹勛','宋','宋诗','song-poetry','','[]','秋夜長，秋夜長，風高月落飛清霜。',96,'全唐诗/poet.song.109000.json','["秋夜長，秋夜長，風高月落飛清霜。", "征鴻蕭蕭度湘水，草木露冷蒹葭黄。", "鐵衣老將尚橫槊，胡兒甲馬爭騰驤。", "閨中思婦燼銀燭，耿耿念遠傷肺腸。", "壯士悲歌扣商角，通夕無寐空凄凉。", "况是愁人怨遥夜，安得日出升扶桑。"]'),
('0fc945ec-536f-4cfb-a17e-64da90c58518','怨遥夜','曹勛','宋','宋诗','song-poetry','','[]','六龍滅景兮疾如馳，結隣曭㬒兮沉海涯。',116,'全唐诗/poet.song.109000.json','["六龍滅景兮疾如馳，結隣曭㬒兮沉海涯。", "飛霜烈烈以襲物兮，其容慘慄。", "陰風凜凜而薄人兮，其聲凄悲。", "祥鸞伏竄兮，鴟梟號呼。", "哲人永歎以哀吟兮，貪夫適其覬覦。", "彼庭燎之不吾遭兮，良卷懷而鬰紆。", "勞歌三發兮，晨雞未旦。", "使我耿耿以戚憂兮，獨展轉而向隅。"]'),
('d8436e60-9029-479c-941f-81fb48e9e0c5','歲將暮','曹勛','宋','宋诗','song-poetry','','[]','歲將暮，歲將暮，靡靡行人不歸去。',92,'全唐诗/poet.song.109000.json','["歲將暮，歲將暮，靡靡行人不歸去。", "不歸去，道路長，道路長兮復限我以石坂羊腸。", "山多喬木兮不能爲吾之棟梁，水多深阻兮不能爲吾之舟航。", "徒頓駕以獨宿兮，趨風雨於晨裝。", "眇佳人兮余懷，期遥集于扶桑。"]'),
('9eedd75b-1a4c-4f69-b806-c6daa556410f','隋堤草','曹勛','宋','宋诗','song-poetry','','[]','綿綿隋堤草，草色翠如茵。',100,'全唐诗/poet.song.109000.json','["綿綿隋堤草，草色翠如茵。", "梧桐間桃李，穠艷驕陽春。", "楊柳垂金堤，拂舞無纖塵。", "行人不敢折，守吏嚴呵嗔。", "大業一崩隕，九廟猶荆榛。", "隋堤草與木，採斫雜樵薪。", "秋風號枯枝，野火燒陳根。", "園林宮館尚禾黍，草木於爾何足論。"]'),
('647d990d-d33c-42dd-9b6e-0d16c05a52c3','蔓草長','曹勛','宋','宋诗','song-poetry','','[]','蔓草長，摇風緣砌凌高堂。',96,'全唐诗/poet.song.109000.json','["蔓草長，摇風緣砌凌高堂。", "萋萋密葉護葱蒨，漙漙湛露滋瀼瀼。", "下有徑寸蘭，委靡塗秋霜。", "依憑既失所，不及菰與蔣。", "託身肯媚附喬木，持芳自潔凝幽香。", "蔓草長，因緣從爾摩蒼蒼。", "一朝喬木夭斤斧，掘根削株貽汝殃。"]'),
('03d89138-352e-46c9-aa5e-d1475c2d521d','隋堤柳','曹勛','宋','宋诗','song-poetry','','[]','隋隄柳，千里夾隋隄。',146,'全唐诗/poet.song.109000.json','["隋隄柳，千里夾隋隄。", "隄中有平道，百尺隠金鎚。", "柳色間桃李，行客迷芳菲。", "牙檣從西來，雲表開龍旗。", "一舟挽千人，萬舟若魚麗。", "舟中盡絕色，不厭荒淫饑。", "錦帆壓奔流，日夜東南馳。", "龍舟未及返，身辱吳公泥。", "神器失所託，化作迷樓灰。", "向來桃與李，花色猶不衰。", "向來堤上柳，柳色猶依依。", "唐公已舉晉陽甲，草木雖小知無隋。"]'),
('14c137d2-5a99-404b-abc0-9ad40343598d','折楊柳五首  其一','曹勛','宋','宋诗','song-poetry','','[]','折楊柳，上隋堤，攀條同憶送君時。',32,'全唐诗/poet.song.109000.json','["折楊柳，上隋堤，攀條同憶送君時。", "君王近發關中卒，更戍歸來尚未遲。"]'),
('69f488b7-6ad7-4088-a875-724a797f0cb4','折楊柳五首  其二','曹勛','宋','宋诗','song-poetry','','[]','折楊柳，上章臺，柳色依依尚未回。',32,'全唐诗/poet.song.109000.json','["折楊柳，上章臺，柳色依依尚未回。", "漢家盡得單于壘，屈指歸同社燕來。"]'),
('0e140208-18fc-4779-b806-d838f930dae8','折楊柳五首  其三','曹勛','宋','宋诗','song-poetry','','[]','折楊柳，灞橋西，去日同君上柳堤。',32,'全唐诗/poet.song.109000.json','["折楊柳，灞橋西，去日同君上柳堤。", "聞道將軍得天馬，歸時芳草正萋萋。"]'),
('b9631a59-2231-4e31-9ed4-aedc680ba39c','折楊柳五首  其四','曹勛','宋','宋诗','song-poetry','','[]','君去霏霏雪滿衣，思君楊柳正依依。',32,'全唐诗/poet.song.109000.json','["君去霏霏雪滿衣，思君楊柳正依依。", "新來又得征人信，君去交河尚未歸。"]'),
('7b026be8-da11-4ba8-8aec-bbb36b38ecb4','折楊柳五首  其五','曹勛','宋','宋诗','song-poetry','','[]','去日同君過渭橋，橋邊新雪未全消。',32,'全唐诗/poet.song.109000.json','["去日同君過渭橋，橋邊新雪未全消。", "如今窗外楊花滿，憔悴無心約細腰。"]'),
('868c840e-662c-4fb2-890d-598462ff82a2','悲採薇','曹勛','宋','宋诗','song-poetry','','[]','昔辭萬乘寵，潔己歸其仁。',120,'全唐诗/poet.song.109000.json','["昔辭萬乘寵，潔己歸其仁。", "强諫非矯訐，所守懷真淳。", "邈矣思唐虞，去去迹已陳。", "夏禹且不讓，叔世良悲辛。", "採薇歌西山，獨往誰與鄰。", "激節不少渝，終始無緇磷。", "優入聖人域，清風高隠淪。", "嗟嗟首陽山，今飛胡馬塵。", "况乃匪湯武，吾子勞諄諄。", "已而復已而，緬默思良辰。"]'),
('e3b2fd7b-4c44-4b69-a3c0-cefeee6bd876','感秋蘭','曹勛','宋','宋诗','song-poetry','','[]','雲何爲兮深山，水何爲兮幽谷。',45,'全唐诗/poet.song.109000.json','["雲何爲兮深山，水何爲兮幽谷。", "匪雜珮于華裾，恥見珍于流俗。", "噫嘻，疑枳棘與荆榛，不辭榮於秋綠。"]'),
('72dbdd48-95fe-4991-81f2-951a3819849c','梅花落','曹勛','宋','宋诗','song-poetry','','[]','殖雖無遠近，開獨占三冬。',48,'全唐诗/poet.song.109000.json','["殖雖無遠近，開獨占三冬。", "怨入胡笳切，香凝素臉穠。", "有子調金鼎，遺根益縣封。", "佳人初睡起，留取照芳容。"]'),
('51b2ce3b-d354-45d2-9758-68565e3df115','哀孤鴻','曹勛','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','哀孤鴻，孤鴻杳何所。',126,'全唐诗/poet.song.109000.json','["哀孤鴻，孤鴻杳何所。", "堅冰合洞庭，積雪滿南楚。", "弔影破寒空，凄凉宿烟雨。", "上林衰草暗池塘，衡岳居人雜豺虎。", "縣官下詔收箭工，繒繳高張求勁羽。", "稻粱粒粒盡輸軍，飲啄號呼困秋浦。", "至今燕代滿胡兒，每欲歸飛畏弓弩。", "畏弓弩，誰能爲我驅胡虜。", "胡虜驅除漢道昌，一身雖困忘辛苦。"]'),
('e4b2fdf2-2a6d-455a-8bb1-0446170844a6','天上月','曹勛','宋','宋诗','song-poetry','','[]','皎皎天上月，隨人如有情。',24,'全唐诗/poet.song.109000.json','["皎皎天上月，隨人如有情。", "何當背銀燭，棄我如絕纓。"]'),
('c0e680f6-4e12-4057-aec0-979d2378c7f8','關山月','曹勛','宋','宋诗','song-poetry','','[]','關山月，關山月。',36,'全唐诗/poet.song.109000.json','["關山月，關山月。", "分影送征人，寒光射矛戟。", "胡笳聲斷塞鴻驚，征人淚下思鄉國。"]'),
('cd2bf472-c904-4ffa-950f-50ee119093cf','高樓月','曹勛','宋','宋诗','song-poetry','','[]','高樓月，倒景入闌干。',34,'全唐诗/poet.song.109000.json','["高樓月，倒景入闌干。", "人眠綺窗影，月在青雲端。", "相攀不可得，空成簾幕寒。"]'),
('715a4000-1e0c-4ed2-a119-1b31fb337585','估客樂','曹勛','宋','宋诗','song-poetry','','[]','朝飲文君酒，莫宿邯鄲妓。',24,'全唐诗/poet.song.109000.json','["朝飲文君酒，莫宿邯鄲妓。", "近得浮梁書，春前辦行計。"]'),
('f5e208e0-f5cd-42d6-a5ae-f4352a2a1dd0','班婕妤','曹勛','宋','宋诗','song-poetry','','[]','寵移非爲妬，花落不因風。',24,'全唐诗/poet.song.109000.json','["寵移非爲妬，花落不因風。", "來往長門月，羞將團扇同。"]'),
('d2312cab-5a95-4925-9981-b6fcb2e51b1d','王昭君','曹勛','宋','宋诗','song-poetry','','[]','好惡由來各在人，况憑圖像覓天真。',32,'全唐诗/poet.song.109000.json','["好惡由來各在人，况憑圖像覓天真。", "君王視聽能無壅，延壽何知敢妄陳。"]'),
('629bf5c3-4e0a-415a-81f5-1d8ca8b9dc4a','游仙四首  其一','曹勛','宋','宋诗','song-poetry','','[]','天河水冷烟波渺，流水無聲銀浪小。',128,'全唐诗/poet.song.109000.json','["天河水冷烟波渺，流水無聲銀浪小。", "白榆歷歷映瑶沙，白露凄清下雲表。", "扶疎丹桂落紅英，片片紅霞散瑶草。", "月中桂子空傳名，散在人間無處討。", "仙翁呼童收紫芝，紫芝肥嫩光離離。", "遺英殘萼墜無數，仙鶴飲啄時鳴飛。", "仙人種玉耕雲隈，倚雲橫笛學鳳吹。", "須臾羲御崦嵫沒，相呼拍手騎龍歸。"]'),
('f2bd759e-3eef-45c1-8a4c-7d4f29e9c0b4','游仙四首  其二','曹勛','宋','宋诗','song-poetry','','[]','飛轡絡絕景，訪我同心人。',120,'全唐诗/poet.song.109000.json','["飛轡絡絕景，訪我同心人。", "解駕三秀嶺，濯足玉華津。", "晤言會良契，携手凌高晨。", "揚旌出閶闔，羽節趣羣真。", "入宴明霞館，回軿過始青。", "音靈散空洞，逸響縈雲營。", "倏忽九萬里，流目低蓬瀛。", "玉妃款清話，偃蓋希林庭。", "顧彼簪纓客，寵辱勞汝形。", "神仙有真訣，胡不希長齡。"]'),
('92a4c358-c8a4-4d6a-8523-2e9fb58989a0','游仙四首  其三','曹勛','宋','宋诗','song-poetry','','[]','嚴駕發滄浪，行樂從所之。',132,'全唐诗/poet.song.109000.json','["嚴駕發滄浪，行樂從所之。", "方諸款青童，隠景朝鬰儀。", "流金戒前導，玉節紛萎蕤。", "運策乘飛電，揚旌耀彩霓。", "斑龍承倒景，蠖略翔紫微。", "命我發金策，受事臨西垂。", "白帝啟真籙，斟酌合四時。", "解带清商館，置酒璇淵池。", "高酣發空謠，羣響凄以悲。", "海水變蒼陸，翻覆如奕棋。", "咄叱紅塵子，役役何所爲。"]'),
('80b2512a-71e2-4a0f-928f-4389bb94e0f1','游仙四首  其四','曹勛','宋','宋诗','song-poetry','','[]','駕景絡絕響，游目低陰虹。',120,'全唐诗/poet.song.109000.json','["駕景絡絕響，游目低陰虹。", "靈光轉修袂，羽節飄晨風。", "抗手辭金母，偃蓋東華宮。", "高仙發空謠，逸響飛九重。", "霞觴艷流日，疊舞歌玉童。", "緣雲上虛籟，笑語鏗洪鐘。", "海水屢清淺，倏忽欣再逢。", "不惜暫游詣，情款無初終。", "歡餘促歸軫，攝轡翔斑龍。", "投閑憇三素，保績崇真功。"]'),
('99c8ece4-7464-422a-a963-d8e41bc64c59','劉生','曹勛','宋','宋诗','song-poetry','','[]','劉生世關輔，游俠周五陵。',156,'全唐诗/poet.song.109000.json','["劉生世關輔，游俠周五陵。", "天下俊倜儻，持夸矜劉生。", "落魄游其間，豪族相依承。", "鬭雞橫大道，走馬入重城。", "醉卧金張館，高談衛霍營。", "報仇先劇孟，排難鄙侯嬴。", "逸氣凌秋鶚，清才瑩玉繩。", "燈前看寶劍，雪裏按蒼鷹。", "校獵黄山苑，追兵青海濱。", "華夷知姓字，燕趙冠婚姻。", "恥作諸侯客，寧爲奔走臣。", "匈奴方入覲，雄略未能申。", "且醉胡姬酒，將軍詎敢嗔。"]'),
('37aed80d-a2c6-4b90-87d2-c4895a66213a','細君','曹勛','宋','宋诗','song-poetry','','[]','族類皆有偶，所偶各有方。',216,'全唐诗/poet.song.109000.json','["族類皆有偶，所偶各有方。", "我本漢家女，遠嫁烏孫王。", "言語既不通，嗜欲寧相當。", "生肉以爲食，羶酪以爲漿。", "毛卉襲衣服，蒜薤爲馨香。", "嗚嗚當歌舞，跳躍紛低昂。", "風沙障白日，四野皆蒼黄。", "逐獵射禽獸，藉草氈爲牆。", "喜怒不可測，貪戾過豺狼。", "自爲治宮室，僅能庇風霜。", "歲時一相見，但見眉目光。", "東南望漢日，獨覺霜天長。", "飛鳥戀故林，游子思故鄉。", "而我被遐棄，失身投窮荒。", "明明漢天子，一女奚足傷。", "武威與文德，豈不在周行。", "吾王居下國，奉上固所當。", "結親徒自辱，掩泣羞漢皇。"]'),
('182bd065-6f06-40ae-845e-b9f27c1b8044','懷遠','曹勛','宋','宋诗','song-poetry','','[]','有美人兮隔千里，彼不來兮我獨止。',32,'全唐诗/poet.song.109000.json','["有美人兮隔千里，彼不來兮我獨止。", "吳江木落又經年，壯士悲聲寒易水。"]'),
('98ce8d37-361b-4744-a7ab-a32ebab7bf14','秋色','曹勛','宋','宋诗','song-poetry','','[]','空煙翔水裔，海月飛冰輪。',48,'全唐诗/poet.song.109000.json','["空煙翔水裔，海月飛冰輪。", "大旆連天山，羽校羅秋旻。", "霜輝明縞練，綵錯光鱗鱗。", "一掃龍庭空，海宇無纖塵。"]'),
('61c97259-81e1-4234-b130-8d2d140446d1','秋思','曹勛','宋','宋诗','song-poetry','','[]','日落碧山暮，陰風生白蘋。',48,'全唐诗/poet.song.109000.json','["日落碧山暮，陰風生白蘋。", "飛響散高梧，水石光粼粼。", "海草未凋綠，胡馬嘶咸秦。", "蕭颯兩華鬢，十年吹戰塵。"]'),
('fac82b05-34e1-4c8a-9bca-93a5105b56fd','黄鶴','曹勛','宋','宋诗','song-poetry','','[]','子晉升真後，茅君謁帝初。',72,'全唐诗/poet.song.109000.json','["子晉升真後，茅君謁帝初。", "靈風翔羽葆，舒轡聳雲裾。", "凌虛前虎節，方駕後龍輿。", "平旦辭龜嶺，禺中過鳳虛。", "故里頻遷改，山川遽有無。", "當時武昌水，清淺轉城隅。"]'),
('a73c82db-3d0f-4789-b65f-9f3692cd2a7b','黄雀','曹勛','宋','宋诗','song-poetry','','[]','羣聚羣飛畏行止，飲啄驚鳴顧無已。',32,'全唐诗/poet.song.109000.json','["羣聚羣飛畏行止，飲啄驚鳴顧無已。", "多虞多事足機張，獨宿蓬蒿信爲美。"]'),
('fc729ac7-7d60-41d7-89ad-de121b9c735e','楊花','曹勛','宋','宋诗','song-poetry','','[]','春光誰占得，楊花獨自知。',48,'全唐诗/poet.song.109000.json','["春光誰占得，楊花獨自知。", "未到傳消息，將歸送別離。", "隨風飛更急，入戶舞還低。", "大有撩人處，粧臺惱畫眉。"]'),
('e2b9d84f-bfb2-45fd-8432-f2dd77571603','當壚','曹勛','宋','宋诗','song-poetry','','[]','胡姬年十五，艷色嬌陽春。',48,'全唐诗/poet.song.109000.json','["胡姬年十五，艷色嬌陽春。", "花間開繡戶，席上設紅茵。", "含羞留醉客，歛袂送行人。", "多謝金吾子，衷情詎易陳。"]'),
('a00add85-d8f5-49e8-93d9-d5cae06b4490','有雪','曹勛','宋','宋诗','song-poetry','','[]','有雪有雪何不時，號令無乃乖其宜。',182,'全唐诗/poet.song.109000.json','["有雪有雪何不時，號令無乃乖其宜。", "玄冥失職變常燠，草木不黄流不澌。", "羣蟄開張動平陸，廣野宮闕騰蛟螭。", "方今春王布仁政，育養萬物如嬰兒。", "爾何干職助陰沴，致使造物無威儀。", "四序平分佐天吏，物色消長隨指揮。", "元綱既絕亂箕斗，五行顛倒盈縮虧。", "安得調元按天步，太微受事三光齊。", "璇璣不愆四七正，時歌玉燭滋黔黎。", "爾之不職有常律，司辰執僇歸攝提。", "願得唐虞二八一十六相佐天子，雷風時至無錯迷。"]'),
('031ba6ee-19ec-4a23-837a-859b8c704202','皚如山上雪','曹勛','宋','宋诗','song-poetry','','[]','皚如山上雪，凜冽生陰寒。',108,'全唐诗/poet.song.109000.json','["皚如山上雪，凜冽生陰寒。", "狐狸卧深穴，猛虎饑不眠。", "下有千尺松，埋沒多摧殘。", "山椒冠叢祠，寂寞無孤烟。", "傍有古戰場，鬼哭聲煩寃。", "燈火斷城郭，雞犬雜喧喧。", "朝官急征夫，迫促爭後先。", "柴門不得閉，行者不得還。", "何當霽風雪，巖岫開南山。"]'),
('e7a6ae2b-fbcb-401d-a7b1-5cbabe196413','僕持節朔庭自燕山向北部落以三分爲率南人居其二聞南使過駢肩引頸氣哽不得語但泣數行下或以慨歎僕每爲揮涕憚見也因作出入塞紀其事用示有志節憫國難者云 入塞','曹勛','宋','宋诗','song-poetry','','[]','妾在靖康初，胡塵蒙京師。',60,'全唐诗/poet.song.109000.json','["妾在靖康初，胡塵蒙京師。", "城陷撞軍入，掠去隨胡兒。", "忽聞南使過，羞頂羖羊皮。", "立向最高處，圖見漢官儀。", "數日望回騎，薦致臨風悲。"]'),
('fafaf5c1-1fd2-4871-b9fe-c4489e6121bd','僕持節朔庭自燕山向北部落以三分爲率南人居其二聞南使過駢肩引頸氣哽不得語但泣數行下或以慨歎僕每爲揮涕憚見也因作出入塞紀其事用示有志節憫國難者云 出塞','曹勛','宋','宋诗','song-poetry','','[]','聞道南使歸，路從城中去。',48,'全唐诗/poet.song.109000.json','["聞道南使歸，路從城中去。", "豈如車上缾，猶掛歸去路。", "引首恐過盡，馬疾忽無處。", "吞聲送百感，南望淚如雨。"]'),
('6d919814-26d2-40e4-8077-96ca3de1ac37','早行相州道中','曹勛','宋','宋诗','song-poetry','','[]','安陽道上晨沖融，西有雲氣成青紅。',128,'全唐诗/poet.song.109000.json','["安陽道上晨沖融，西有雲氣成青紅。", "四重欄干五滴水，五花競鬭相穹崇。", "旁有臺殿峙鴟尾，上有翔翥如飛龍。", "擎拳歎仰得未有，頗似西母居其中。", "微臣一念到彼處，仙班趨揖殊從容。", "跪奏內人遇至道，沆瀣一飲和氣充。", "翛然退歸復故幹，神宇欲便摩青空。", "仰看向來禮謁處，但見碧落相冥濛。"]'),
('c9c2760f-299c-4c10-bc51-eff6799a5d07','過楚有作','曹勛','宋','宋诗','song-poetry','','[]','昔見山陽盛，氣象吞淮壖。',156,'全唐诗/poet.song.109000.json','["昔見山陽盛，氣象吞淮壖。", "士子世忠孝，民物安園田。", "再到已屯兵，鼙鼓喧中天。", "戶口莽凋弊，廬里儲櫜鞬。", "濟師有虎臣，隔岸威腥羶。", "翠華江海上，玉闕風塵邊。", "未至重慨歎，荒城委蒼烟。", "貔貅過江南，狐兔游城顛。", "餘民如驚鹿，菜色慘不鮮。", "呼之莫肯留，猶意虜所專。", "三過乃三變，感時良泫然。", "二趙忠益高，仲車魂尚賢。", "欲弔寂無所，淮月空娟娟。"]'),
('fdcce2c5-8670-4c6b-bed7-87d1df4291c1','過邯鄲','曹勛','宋','宋诗','song-poetry','','[]','恭持天子節，再經邯鄲城。',132,'全唐诗/poet.song.109000.json','["恭持天子節，再經邯鄲城。", "斷垣四頹缺，草樹皆欹傾。", "慨念全趙時，英雄疲戰爭。", "殆及五季末，瓜分無定盟。", "慨念藺君高，璧亦安所盛。", "翩翩魏公子，有德勝所稱。", "殆今已千年，廢臺漫崢嶸。", "趙民尚自若，歌舞娛春榮。", "金石絲簧奏，彷彿餘新聲。", "興廢乃爾爾，人事徒營營。", "望城只歎息，盡付西山青。"]'),
('060e4b33-f97e-4286-b2b4-dd788d77d016','望太行','曹勛','宋','宋诗','song-poetry','','[]','落月如老婦，蒼蒼無顔色。',48,'全唐诗/poet.song.109000.json','["落月如老婦，蒼蒼無顔色。", "稍覺林影疎，已見東方白。", "一生困塵土，半世走阡陌。", "臨老復茲游，喜見太行碧。"]'),
('6cce398c-bd95-449c-9934-77466e769591','持節回呈王樞','曹勛','宋','宋诗','song-poetry','','[]','去時炎歊極蒸鬰，塵滿籃輿困摇兀。',64,'全唐诗/poet.song.109000.json','["去時炎歊極蒸鬰，塵滿籃輿困摇兀。", "歸時大嶺雪已飛，易水清漳醒病骨。", "三月不親君子儒，一笑且脫蕭何律。", "身輕頃刻渡長淮，殊喜眼前無俗物。"]'),
('c5d7084a-b5f2-4162-b558-2a462088b6f1','賦洪景伯分繡閣','曹勛','宋','宋诗','song-poetry','','[]','赤城今屏翰，瀕濕浙右同。',120,'全唐诗/poet.song.109000.json','["赤城今屏翰，瀕濕浙右同。", "不有仙人居，梅溽難從容。", "洪仙下瀛洲，一笑除蒿蓬。", "創閣俯江海，重簷煥雲空。", "排衙碧嶙峋，烟霞透玲瓏。", "遥岑與絕壁，但覺開青紅。", "愛之榜佳名，坐見羣山工。", "萬疊烘曉日，六幕泛景風。", "時時與賓僚，醉酌黄金鍾。", "請憑十二欄，更賦烟雨中。"]'),
('210f66eb-903e-4870-92bf-33f825fbac96','及甫坐上分題賦洗竹得百字','曹勛','宋','宋诗','song-poetry','','[]','𠜴竹有舊貫，剪伐未容測。',48,'全唐诗/poet.song.109000.json','["𠜴竹有舊貫，剪伐未容測。", "長身數竿足，叢薄徒累百。", "稍令掩翳去，漸放脩直色。", "要知清明朝，惡者在所格。"]'),
('5096d93a-2f13-455e-9fd8-025769214ea9','有惠錦鷄者因暇賦之','曹勛','宋','宋诗','song-poetry','','[]','山雞美毛羽，五采若絺繡。',72,'全唐诗/poet.song.109000.json','["山雞美毛羽，五采若絺繡。", "不能掩顔色，居然遭籠囿。", "嗟賞入欄檻，玩好資稚幼。", "有稻莫能飽，有水漫濡咮。", "低昂不自得，雲山計未就。", "應歎鴟鴉類，腐鼠遨白晝。"]'),
('1c56e6de-7a07-44f9-b3fd-c57373b751e3','分題墨梅','曹勛','宋','宋诗','song-poetry','','[]','北風吹雲村寂寂，練練溪流湛寒碧。',96,'全唐诗/poet.song.109000.json','["北風吹雲村寂寂，練練溪流湛寒碧。", "馬頭忽有暗香來，撼雪尋芳識標格。", "揚鞭敲鐙荒寒路，酒惡難禁頼銷釋。", "隴上故人消息遲，一枝誰寄疎煙隔。", "老禪幻此空花相，墨暈橫斜清照客。", "定應飛夢會姑仙，玉樓澹月連天白。"]'),
('69e96554-e1fe-411c-96e6-13ea345b022e','題澉浦金粟寺  其一','曹勛','宋','宋诗','song-poetry','','[]','我聞金粟名，來謁示病相。',48,'全唐诗/poet.song.109000.json','["我聞金粟名，來謁示病相。", "不見隠几老，松竹空函丈。", "雨花誰聲聞，擎鉢定非想。", "歸去一笑粲，春風快雙槳。"]'),
('867ca288-cd1f-484b-a3cb-ea90ebbac43f','題澉浦金粟寺  其二','曹勛','宋','宋诗','song-poetry','','[]','入門不見佛，已悟本無相。',48,'全唐诗/poet.song.109000.json','["入門不見佛，已悟本無相。", "若爲是真求，沙界等尋丈。", "欣逢兩禪老，妙悟滅心想。", "行當求所求，筏喻不言槳。"]'),
('0a17793d-bd6b-47e0-9f39-4417a88507ce','題黄灣真如山般若臺','曹勛','宋','宋诗','song-poetry','','[]','真如山中龍象宅，前三後三率禪客。',64,'全唐诗/poet.song.109000.json','["真如山中龍象宅，前三後三率禪客。", "珍公提唱悟本心，一指不留庭下柏。", "我來春事梅已玉，仍吸靈泉酌寒碧。", "會看海印發光時，臺前璧月連天白。"]'),
('a1f03aa8-e148-4707-9c85-e562197f59a4','題唯庵後大松','曹勛','宋','宋诗','song-poetry','','[]','唯庵有長松，秀拔撐青空。',48,'全唐诗/poet.song.109000.json','["唯庵有長松，秀拔撐青空。", "銅石並根幹，榆枋比蒿蓬。", "天地蔭中邊，日月奔西東。", "願言滋浩養，千歲看此公。"]'),
('de82d657-93d4-46d2-967d-4671a7b0b306','題友人書後','曹勛','宋','宋诗','song-poetry','','[]','客子得秋凉，壯懷亦增慨。',24,'全唐诗/poet.song.109000.json','["客子得秋凉，壯懷亦增慨。", "永念故人遠，三湘渺滄海。"]'),
('cf5791d5-4393-490c-b1ca-7654a81c189c','題王氏女自寫渡水羅漢','曹勛','宋','宋诗','song-poetry','','[]','尊者暫離方廣間，神通游戲山水閑。',64,'全唐诗/poet.song.109000.json','["尊者暫離方廣間，神通游戲山水閑。", "女郎夙植窺其藩，妙筆寫出尊者顔。", "甚知此意大廓落，直與世塵解纏縛。", "不須錫飛與盃渡，政恐有僧敲折脚。"]'),
('338b0a23-0003-4cc2-9f3a-19c14cc1fc5f','贈吳思道','曹勛','宋','宋诗','song-poetry','','[]','某也極連蹇，世緣牽喧卑。',240,'全唐诗/poet.song.109000.json','["某也極連蹇，世緣牽喧卑。", "久困戎燼間，方與鞍馬辭。", "得奉宮觀祿，遽失糟糠妻。", "淚零繐帷風，春慘中梱悲。", "生理正落莫，幽思難平治。", "公來黟歙遥，率孤再拜之。", "慰藉累年別，歎息私門衰。", "而公顔渥丹，綠鬢白髮稀。", "頓換神氣妙，密驗刀圭奇。", "內典禪悅深，外丹日月遲。", "陰功粹雅度，方爲世所師。", "永懷我先君，與公深相知。", "辱以執友契，肯顧賤子微。", "賤子感誨言，於茲老鋤犁。", "甌窶祝場圃，翕張防寒饑。", "時時躬遠郊，一一得自怡。", "次第教三子，令諳田畝爲。", "老鈍依頹簷，忘言隨四時。", "幸會道此樂，秋風遽言歸。", "尚有一瓣香，願奉鍾呂期。"]'),
('c0051bca-c7d9-4c73-84ed-92f76dcee37f','贈陳季野','曹勛','宋','宋诗','song-poetry','','[]','平生聞說陳季野，渠正奇奇余下下。',64,'全唐诗/poet.song.109000.json','["平生聞說陳季野，渠正奇奇余下下。", "人間韻語光陸離，韞櫝藏之當待價。", "顧我飄然離帝傍，適是適非思陶寫。", "庶幾一笑排春溫，頼有梅花尚盈把。"]'),
('726742c7-a138-47cb-84dd-5b71655d7a20','選上人素履精修僕先識於崇信岑寂之時重來見之作詩爲贈','曹勛','宋','宋诗','song-poetry','','[]','我初游赤城，松竹空函丈。',84,'全唐诗/poet.song.109000.json','["我初游赤城，松竹空函丈。", "師時奉諸佛，畧不乏供養。", "茲游再見之，談笑益夷曠。", "橫披慰老眼，罌粟煎夜餉。", "不以三生緣，遂作一指想。", "新蕉展時雨，風鑾鳴晝講。", "勉旃自愛重，公才定龍象。"]'),
('25528338-c089-48d3-9c32-1643316288f7','寄蘇徵君','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','平生聞說蘇養直，鞅掌塵勞慚未識。',64,'全唐诗/poet.song.109000.json','["平生聞說蘇養直，鞅掌塵勞慚未識。", "清江韻語百代尊，擬望孤撐徒著屐。", "未將經綸在廊廟，且落珠璣滿泉石。", "頗知新築更靚深，願並廬山歌馬跡。"]'),
('996a4b5e-bbaa-4ad8-9838-955a8acb77e6','寄張達道先生','曹勛','宋','宋诗','song-poetry','','[]','永懷凝神公，履正羣仙誇。',108,'全唐诗/poet.song.109000.json','["永懷凝神公，履正羣仙誇。", "流目厭塵土，軒冕卑泥沙。", "羽蓋承倒景，飆輪泛晨霞。", "前旌絡霄隊，駐節王母家。", "真童發清謠，雲表翔哀笳。", "樓居映朝日，服采明珠華。", "萬春等朝菌，歡事詎可涯。", "瑶席未終醼，零落蟠桃花。", "想同董奉君，更尋上漢槎。"]'),
('d723c4e2-4812-4b8f-a6f6-65553c902f75','寄鄭漁仲','曹勛','宋','宋诗','song-poetry','','[]','君家谷口藹清節，後裔於今耿冰雪。',80,'全唐诗/poet.song.109000.json','["君家谷口藹清節，後裔於今耿冰雪。", "高明固已天下聞，却向山中弄明月。", "貫穿諸史極成敗，鼓吹六經方論說。", "碧雲日暮臨庭柯，緘封肯寄衝烟蘿。", "邊頭嗷嗷一雁過，坐想空山霜露多。"]'),
('3112dd42-80ec-466d-ad04-2aa0c26ad6d4','寄空上人','曹勛','宋','宋诗','song-poetry','','[]','華頂峰頭空侍者，家在全閩九峰下。',64,'全唐诗/poet.song.109000.json','["華頂峰頭空侍者，家在全閩九峰下。", "后山妙香今始聞，西江一口元非假。", "可但枯木已陽豔，更喜淮碑仍續雅。", "天風海雨會入詩，况近梅花欲盈把。"]'),
('f279d84b-36a5-4a11-9730-7206e81fcb5e','雨中寄李正字','曹勛','宋','宋诗','song-poetry','','[]','我能甘貧誰委悉，惟欠鼓頷曳杖乞。',64,'全唐诗/poet.song.109000.json','["我能甘貧誰委悉，惟欠鼓頷曳杖乞。", "閉門寧餓十日雨，約己何能六尺屈。", "裹子桑飯公等恩，食駿馬肉我固失。", "行將雲水縱所如，一琖清泉負朝日。"]'),
('78a66569-d27e-4c0c-a446-ee0b58cad8ea','新歲七十以人生七十古來稀爲韻寄錢大參七首  其一','曹勛','宋','宋诗','song-poetry','','[]','從心之歲自由身，恩許前期脫搢紳。',32,'全唐诗/poet.song.109000.json','["從心之歲自由身，恩許前期脫搢紳。", "一褐林泉侶樵牧，熙熙端是太平人。"]'),
('a275af94-8818-4a17-8fa3-eef16b8373f1','新歲七十以人生七十古來稀爲韻寄錢大參七首  其二','曹勛','宋','宋诗','song-poetry','','[]','蕭然心跡喜雙清，且得肩頭擔已輕。',32,'全唐诗/poet.song.109000.json','["蕭然心跡喜雙清，且得肩頭擔已輕。", "老病正須安靜處，林間風味慰平生。"]'),
('d2ef30f8-c58a-49fb-b8db-30786893652a','新歲七十以人生七十古來稀爲韻寄錢大參七首  其三','曹勛','宋','宋诗','song-poetry','','[]','一二三四五六七，行年臨之如電疾。',32,'全唐诗/poet.song.109000.json','["一二三四五六七，行年臨之如電疾。", "只將香火對清閑，古井無波應委悉。"]'),
('80574267-6f85-4eec-bc02-e156a6e0c234','新歲七十以人生七十古來稀爲韻寄錢大參七首  其四','曹勛','宋','宋诗','song-poetry','','[]','未遂歸心如束濕，久客京塵常汲汲。',32,'全唐诗/poet.song.109000.json','["未遂歸心如束濕，久客京塵常汲汲。", "碧雲向晚愛歸飛，空看五五與十十。"]'),
('93c6ab4f-a1fe-463b-b7d6-ca23ad7c818b','新歲七十以人生七十古來稀爲韻寄錢大參七首  其五','曹勛','宋','宋诗','song-poetry','','[]','小築幽深無伴侶，默坐忘言時獨許。',32,'全唐诗/poet.song.109000.json','["小築幽深無伴侶，默坐忘言時獨許。", "百年心事付閑雲，一卷仙經還太古。"]'),
('b7dceeac-1e04-4a12-9b75-d729e0f69411','新歲七十以人生七十古來稀爲韻寄錢大參七首  其六','曹勛','宋','宋诗','song-poetry','','[]','一廛兒輩自鋤開，繞屋稍稍併種梅。',32,'全唐诗/poet.song.109000.json','["一廛兒輩自鋤開，繞屋稍稍併種梅。", "摘葉尋枝看未足，橫斜已覺報春來。"]'),
('65f2e4e8-162d-4c06-92b6-13693746bb3f','新歲七十以人生七十古來稀爲韻寄錢大參七首  其七','曹勛','宋','宋诗','song-poetry','','[]','居當山麓入烟扉，喬木蒼藤接翠微。',32,'全唐诗/poet.song.109000.json','["居當山麓入烟扉，喬木蒼藤接翠微。", "築室暮年今尚少，得歸真是眼中稀。"]'),
('38663a8c-3310-48fa-b49d-fa1a57d152fe','錢大參有和用韻謝之七首  其一','曹勛','宋','宋诗','song-poetry','','[]','瑞峯來現宰官身，清峙巖巖聳搢紳。',32,'全唐诗/poet.song.109000.json','["瑞峯來現宰官身，清峙巖巖聳搢紳。", "聞道石頭時說偈，一堂驚動水雲人。"]'),
('11abf47d-2acd-4bc9-9403-cb06b66e67fe','錢大參有和用韻謝之七首  其二','曹勛','宋','宋诗','song-poetry','','[]','冰玉無塵徹骨清，世間榮祿一毫輕。',32,'全唐诗/poet.song.109000.json','["冰玉無塵徹骨清，世間榮祿一毫輕。", "未論此際通三際，直向今生度此生。"]'),
('4b797c59-b73b-47bc-bb62-279c6d875047','錢大參有和用韻謝之七首  其三','曹勛','宋','宋诗','song-poetry','','[]','天一地二數至七，開天之天識量疾。',32,'全唐诗/poet.song.109000.json','["天一地二數至七，開天之天識量疾。", "蕩然獨立放全身，莫問諸方悉不悉。"]'),
('cb61cbcc-23f5-482d-bb22-ed46128f9a2f','錢大參有和用韻謝之七首  其四','曹勛','宋','宋诗','song-poetry','','[]','露地全牛何濕濕，豈比漢陰負井汲。',32,'全唐诗/poet.song.109000.json','["露地全牛何濕濕，豈比漢陰負井汲。", "拈出老胡向上機，便知挂一不成十。"]'),
('dde75396-f6ee-439f-9311-8f2366608618','錢大參有和用韻謝之七首  其五','曹勛','宋','宋诗','song-poetry','','[]','相君自是仙山侶，大筆如椽鄙燕許。',32,'全唐诗/poet.song.109000.json','["相君自是仙山侶，大筆如椽鄙燕許。", "七篇方愧不成章，肆筆相酬語冞古。"]'),
('d6b3a6a4-65df-46af-9fef-5800fc3a8979','錢大參有和用韻謝之七首  其六','曹勛','宋','宋诗','song-poetry','','[]','忠孝傳家大府開，蒼生久已待鹽梅。',32,'全唐诗/poet.song.109000.json','["忠孝傳家大府開，蒼生久已待鹽梅。", "我雖潦倒山林下，會聽中天紫詔來。"]'),
('4f5be49f-57b2-4d20-a49e-8d51f99a1973','錢大參有和用韻謝之七首  其七','曹勛','宋','宋诗','song-poetry','','[]','曾奉清言吐屑霏，巖廊又復仰幾微。',32,'全唐诗/poet.song.109000.json','["曾奉清言吐屑霏，巖廊又復仰幾微。", "正須國論籌前箸，毋使人間見亦稀。"]'),
('8da5881d-987a-4152-8966-590f5a985a2d','瑞巖仰老見和復酬前韻七首  其一','曹勛','宋','宋诗','song-poetry','','[]','請得忙中物外身，要看飛瀑瀉天紳。',32,'全唐诗/poet.song.109000.json','["請得忙中物外身，要看飛瀑瀉天紳。", "佳時每與漁樵伴，倣語相倍是故人。"]'),
('88afc647-320c-4b92-afcb-e11b434dbdc7','瑞巖仰老見和復酬前韻七首  其二','曹勛','宋','宋诗','song-poetry','','[]','雙澗流泉徹底清，五峯晴挂白雲輕。',32,'全唐诗/poet.song.109000.json','["雙澗流泉徹底清，五峯晴挂白雲輕。", "泉流雲散遲歸步，猶欲思豐問此生。"]'),
('3be0ec57-5ab3-4679-b724-7ea5ada691b9','瑞巖仰老見和復酬前韻七首  其三','曹勛','宋','宋诗','song-poetry','','[]','生死之徒六與七，可救羣生可愈疾。',32,'全唐诗/poet.song.109000.json','["生死之徒六與七，可救羣生可愈疾。", "心如秋月碧潭空，深閉巖扉方表悉。"]'),
('e6eb3cef-e7b9-4091-a49e-cb5cf40435fe','瑞巖仰老見和復酬前韻七首  其四','曹勛','宋','宋诗','song-poetry','','[]','台山之麓少卑濕，小築還專甘井汲。',32,'全唐诗/poet.song.109000.json','["台山之麓少卑濕，小築還專甘井汲。", "陋巷閉門飲一瓢，慚非回也能知十。"]'),
('6f2436c0-c8a0-4dae-9de2-e05d1279a2d4','瑞巖仰老見和復酬前韻七首  其五','曹勛','宋','宋诗','song-poetry','','[]','當年卜近虎溪侶，領畧閑心笑相許。',32,'全唐诗/poet.song.109000.json','["當年卜近虎溪侶，領畧閑心笑相許。", "豈圖雲水各一方，回首向來若懷古。"]'),
('9315dbca-340f-42ce-81ba-c9fda24c6e94','瑞巖仰老見和復酬前韻七首  其六','曹勛','宋','宋诗','song-poetry','','[]','白足持詩懷抱開，清言秀潤喜惟梅。',32,'全唐诗/poet.song.109000.json','["白足持詩懷抱開，清言秀潤喜惟梅。", "便知雅貺翛翛意，端爲閑人特特來。"]'),
('a643d0ca-45c5-4ca1-8dc1-ab5071debd5d','瑞巖仰老見和復酬前韻七首  其七','曹勛','宋','宋诗','song-poetry','','[]','雲英兩鳳跨烟扉，收盡詩才坐翠微。',32,'全唐诗/poet.song.109000.json','["雲英兩鳳跨烟扉，收盡詩才坐翠微。", "相國題評爲携挈，一方蓮社似公稀。"]'),
('55807b49-685f-4e1e-a4f6-f5d037059eee','送凝神張先生還茅山','曹勛','宋','宋诗','song-poetry','','[]','我家天台玉霄峰，旁臨雲海空復空。',248,'全唐诗/poet.song.109000.json','["我家天台玉霄峰，旁臨雲海空復空。", "水光際天接山影，山間樓閣相溟濛。", "仙人騎鯨度空碧，步虛聲下飄天風。", "纓冠葳蕤跨綵翼，子晉鳳笙驚盲聾。", "半夜電雷動巖壑，一壇松檜知仙公。", "別來放跡入朝市，但覺塵土填心胸。", "猿驚鶴怨愧昏旦，竹露蘿月徒葱蘢。", "君庵三茅何沖融，暮春旅寓凡聖同。", "同造勝境瞻真蹤，弟兄乘雲御飛龍。", "爲時作瑞留從容，但見仙驥頂有紅。", "凝神坐嘯隠萬松，粲粲玉齒猶顔童。", "珮聲促詔朝帝宮，清浄爲正裨舜聰。", "坐乎少廣追崆峒，物不疵癘壽域中。", "翩然鶴歸茅岫東，一篙秋靜磨青銅。", "他年我亦披蒙茸，草屨瘦藤饑不充，應許下竈爲陪從。"]'),
('8f40f685-975e-4fc1-94f7-128598415e6d','送曹藴清歸廬山','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','吾宗出西蜀，託跡廬阜岑。',48,'全唐诗/poet.song.109000.json','["吾宗出西蜀，託跡廬阜岑。", "恭禮清虛尊，相與道義深。", "別時白日長，忽茲秋雲陰。", "永懷一笑粲，水雲勞我心。"]'),
('1a71c11e-c679-45df-af7a-b7d05519df0d','送子威兄鈐兵池陽','曹勛','宋','宋诗','song-poetry','','[]','伊昔侍伯父，一官尉池陽。',252,'全唐诗/poet.song.109000.json','["伊昔侍伯父，一官尉池陽。", "時年方九齡，讀書未知方。", "於今涉五紀，皤然鬚鬢霜。", "茲喜伯兄官，鈐兵總戎行。", "素風出韜畧，貔貅稟閎綱。", "小試部勒勤，著鞭揚榮光。", "青林脫幽籜，濃綠棲殘芳。", "起予水雲心，尚拘朝市忙。", "齊山上穹碧，九華儼珪璋。", "紫巖楮敲冰，雲葉供展張。", "清江霽遠目，帆檣下滄浪。", "林泉作佳游，爲公發天藏。", "伯父昔所臨，雲漢披天章。", "琳琅戛鳴球，往往題僧坊。", "何當切訪問，便與磨珉蒼。", "庶於門戶間，能事歲月長。", "仙舟涉初夏，浮家及清凉。", "毫舉塵土境，海運圖南翔。", "兄弟各垂白，語離熱中腸。", "願言養浩然，時舉黄金觴。", "因風託素鰭，訪我菰蒲鄉。"]'),
('47d1e6a2-41fb-4fc9-9ac0-5cd73ccbaead','送許尉','曹勛','宋','宋诗','song-poetry','','[]','平生許彥充，軀膽兩豪舉。',156,'全唐诗/poet.song.109000.json','["平生許彥充，軀膽兩豪舉。", "掀髯參軍事，詎可細碎語。", "我時百僚下，計拙役甚苦。", "從事得餘力，慷慨志相許。", "公乃小著鞭，一官尉南浦。", "鹽車雖云困，垂棒亦其所。", "願子自薦達，天王方振旅。", "求田勿墮氣，苞茅當問楚。", "此事豈不壯，况復吾素與。", "我緣擁縗服，窘欲訪雞黍。", "天寒霜雪盛，世亂豺狼阻。", "何堪南北趨，別意寓琖俎。", "傷心有清淚，揮灑欲如雨。"]'),
('42fe6633-b11f-4bc8-8d44-f8ebbc57bf1f','送戴才美郎中出使襄漢','曹勛','宋','宋诗','song-poetry','','[]','仕宦將相理所當，致君澤民則爲良。',128,'全唐诗/poet.song.109000.json','["仕宦將相理所當，致君澤民則爲良。", "竊竊苟作兒女語，紛紛徒在鵷鷺行。", "惟君英槩吞七澤，早以閎畧走黠羌。", "天子神聖熟姓字，臨遣亟自尚書郎。", "密奉疇咨持玉節，荆襄將漕觀施設。", "小攄胸次浩不極，一闢土疆包有截。", "江南梅開欲飛雪，老境何堪與君別。", "可竚促召黄金闕，爲賀收功在三傑。"]'),
('4846a6e2-ba0b-43c9-bad4-dc43cf84680f','送徐正時歸浦城','曹勛','宋','宋诗','song-poetry','','[]','徐子志義士，觸熱如探湯。',132,'全唐诗/poet.song.109000.json','["徐子志義士，觸熱如探湯。", "遠從南浦來，訪我存與亡。", "語兼瓊瑶溫，氣回蘭蕙芳。", "炎雲正爍石，懷抱爲清凉。", "顧予巖壑姿，小築台山傍。", "兒輩雜編氓，荆扉繞松篁。", "感公久留茲，語離熱中腸。", "行行括蒼道，念此山路長。", "公懷武夷春，復多知見香。", "青雲勉震耀，宜近天漢光。", "草堂不道遠，時寄烟蒼茫。"]'),
('e1acc04c-61a4-4c0f-b0ad-5872d28a7a82','別鄭康道','曹勛','宋','宋诗','song-poetry','','[]','與公相從久，未始蹈瑣細。',156,'全唐诗/poet.song.109000.json','["與公相從久，未始蹈瑣細。", "我既困索米，公已安吳地。", "一廛了百指，與閑殆天意。", "陛下聖而武，庶物進以彙。", "擇材訪耆宿，粲若數一二。", "考槃出幽隠，鼓篋趨朝市。", "公尚有遐心，詎宜忽初志。", "腰鐮與手斧，甘窮幾經歲。", "我願以公名，充庭如孔翠。", "風雲際盛旦，用激志士氣。", "胡爲倏來往，老懷惜摻袂。", "惟冀加餐飯，賢者不終棄。", "功名會有日，當看詠既醉。"]'),
('0e4d13ae-ee77-4c57-bb5d-132db4f7f139','別無錫南禪蓮老','曹勛','宋','宋诗','song-poetry','','[]','生平罹百憂，老來始一欣。',72,'全唐诗/poet.song.109000.json','["生平罹百憂，老來始一欣。", "得履方外趣，不涉卷內聞。", "留錫憇福境，禪悅志所勤。", "日款鄉關舊，俱歎鴻鵠分。", "偶同一窗雨，永懷九仙雲。", "好持洞下香，法界期普薰。"]'),
('a5fb5c1d-4d41-489d-ab93-35981ab0cd2f','和程機宜見貽','曹勛','宋','宋诗','song-poetry','','[]','僕昔困犯難，戎陸日所虞。',192,'全唐诗/poet.song.109000.json','["僕昔困犯難，戎陸日所虞。", "何能守一經，且話雄千夫。", "識公好兄弟，宛同周司徒。", "爽徹絕俗姿，秀發連璧軀。", "駸駸駕文圃，吐論清而腴。", "伊流如學源，一洗衆病膚。", "韶音沿沂說，舉世必所無。", "公家徐起之，力因拯其橅。", "諸儒步武役，反若轅下駒。", "方知鉅鹿功，列國宜鳬趨。", "念茲風塵際，再得如玄珠。", "流光澈太清，欲飛月下烏。", "釀爲五字句，妙語兼良圖。", "愧此溢美多，通甚非康衢。", "新凉到棐几，翠竹環茅廬。", "更當對論文，莫問金僕姑。"]'),
('979dca88-a9c7-4681-b865-9ad8e7807c26','和鄭康道喜雪','曹勛','宋','宋诗','song-poetry','','[]','東方已明雲海立，怪來雀噪爭枝集。',208,'全唐诗/poet.song.109000.json','["東方已明雲海立，怪來雀噪爭枝集。", "凜氣著人不苦寒，老境增衣欲重襲。", "忽驚朔吹翔臘白，隴畝爲祥時適及。", "稍聞清響食蠶聲，漸看落簷傾粟粒。", "縈梅閣竹巧相積，透隙穿窗莫能戢。", "散鹽蔽空誠非虛，回風作舞勢方急。", "歷亂瓦溝已一撇，紛泊何假鮫人泣。", "但喜彌空絮影下，不管霑衣玉塵濕。", "谷口先生好出詞，韻險致高俱足給。", "嘉言浩若長河注，答問殊非古井汲。", "乘時和樂致上瑞，屢豐固非一朝緝。", "須知天門開九重，布化調元密呼吸。", "明朝稱賀明光宮，高冠長劍千官入。"]'),
('1724b3aa-5fa2-4931-8855-f236dbb576d7','和李判院見貽','曹勛','宋','宋诗','song-poetry','','[]','楚風燃竹爆幽吼，曉覺春雲時蒼狗。',96,'全唐诗/poet.song.109000.json','["楚風燃竹爆幽吼，曉覺春雲時蒼狗。", "慚看曆日與桃符，猶襲塵緣戀升斗。", "先生冒雪肯過我，椒觴得奉談天口。", "寒素每歎濡之儒，品俎常嗟韭之九。", "但喜盍簪侍誨約，涉世粗豪一肯首。", "五雲會約采真游，天公見賜良不苟。"]'),
('873e1e71-3fac-4073-8695-7559ce7e976a','和王倅見惠十篇  其一','曹勛','宋','宋诗','song-poetry','','[]','惟公霄漢資，梢梢摩天翮。',36,'全唐诗/poet.song.109000.json','["惟公霄漢資，梢梢摩天翮。", "回溪畧蹭蹬，乃爾詠葵麥。", "會復見軒昂，一笑忘羈客。"]'),
('ac8f615d-58e9-4b9b-b57d-6340d209ea18','和王倅見惠十篇  其二','曹勛','宋','宋诗','song-poetry','','[]','有琴寫流水，無言道情素。',36,'全唐诗/poet.song.109000.json','["有琴寫流水，無言道情素。", "水寒江海深，川闊牛羊暮。", "倒指三十年，猶記潮陽路。"]'),
('fce88ae3-180b-4161-b369-58da850d1951','和王倅見惠十篇  其三','曹勛','宋','宋诗','song-poetry','','[]','道遠一跬步，心勤每僑如。',36,'全唐诗/poet.song.109000.json','["道遠一跬步，心勤每僑如。", "荷深露初下，翠密紅亦疏。", "是知詩興多，賸寄懷人書。"]'),
('1ed93430-e84c-4692-9c33-25e1bbcfd6b0','和王倅見惠十篇  其四','曹勛','宋','宋诗','song-poetry','','[]','老態念百出，傖客無吳田。',36,'全唐诗/poet.song.109000.json','["老態念百出，傖客無吳田。", "空收靜中觀，三疊能蹁躚。", "以之忘物我，此生休問天。"]'),
('b11dbcc9-e412-41ee-a28c-0ac69ae0fca2','和王倅見惠十篇  其五','曹勛','宋','宋诗','song-poetry','','[]','十篇賁蓬茅，心親不道遠。',36,'全唐诗/poet.song.109000.json','["十篇賁蓬茅，心親不道遠。", "內抃如登瀛，外愧稽策蹇。", "徒誦碧雲句，幽香發芳苑。"]'),
('391c267b-f2a6-4654-a5a2-da466895ebd3','和王倅見惠十篇  其六','曹勛','宋','宋诗','song-poetry','','[]','若人富文史，皮裏羅陽秋。',36,'全唐诗/poet.song.109000.json','["若人富文史，皮裏羅陽秋。", "婉此建安格，當從古人求。", "醉侯豈可縻，當封富民侯。"]'),
('492da83a-4799-48ae-8f21-b7c52754c428','和王倅見惠十篇  其七','曹勛','宋','宋诗','song-poetry','','[]','伊昔晉室雄，風流藹於門。',36,'全唐诗/poet.song.109000.json','["伊昔晉室雄，風流藹於門。", "至今掇危科，儒行歸後昆。", "子舍江左來，應喜今尚存。"]'),
('d57891fa-0c01-4ef5-9dd9-dc6d3ab3764e','和王倅見惠十篇  其八','曹勛','宋','宋诗','song-poetry','','[]','僕頃將明命，三往責楛矢。',36,'全唐诗/poet.song.109000.json','["僕頃將明命，三往責楛矢。", "所期宣國威，寧復賦霞綺。", "須知處死時，與生亦相似。"]'),
('370d2491-08e2-4518-920e-742515fe0526','和王倅見惠十篇  其九','曹勛','宋','宋诗','song-poetry','','[]','嗟嗟困犯難，皎皎心莫改。',36,'全唐诗/poet.song.109000.json','["嗟嗟困犯難，皎皎心莫改。", "而能畏四知，遂復瞻八綵。", "又起山林思，浩蕩渺江海。"]'),
('83a42f77-ef4c-4341-ad7e-82b3eba2a571','和王倅見惠十篇  其一○','曹勛','宋','宋诗','song-poetry','','[]','潦倒固久矣，猶涉世網深。',36,'全唐诗/poet.song.109000.json','["潦倒固久矣，猶涉世網深。", "中經謗嫉人，屢欲魑魅尋。", "赫然天日照，敢改藜藿心。"]'),
('2f56f508-7ba4-4ba7-941a-780f0bf2d32d','和程右史見貽','曹勛','宋','宋诗','song-poetry','','[]','平生仰東坡，蘇程契尤熟。',48,'全唐诗/poet.song.109000.json','["平生仰東坡，蘇程契尤熟。", "兩家流慶深，雲外世高躅。", "於今鳳池貴，方判卞氏玉。", "何止試典刑，一想岷峩綠。"]'),
('2908dc6b-c6e3-424e-bb3d-32d13518abbe','和程進道見貽','曹勛','宋','宋诗','song-poetry','','[]','秋聲起木杪，便覺密葉稀。',192,'全唐诗/poet.song.109000.json','["秋聲起木杪，便覺密葉稀。", "風至草木勁，水闊鴻雁知。", "壯懷感摇落，歎息囊中錐。", "功名未卓立，此心常坐馳。", "君家朱橋側，細俯秋水遲。", "氣近龍鳳闕，喧無笳鼓悲。", "蕭齋琴書靜，不知花影移。", "棣華好伯仲，騰起風雲時。", "心親詩禮學，日與富貴期。", "不忘黄塵苦，乃眷寒士饑。", "此理誠愫抱，豈復持詭隨。", "已獻仲舒策，孰謂李廣奇。", "文中有至樂，妙處含天機。", "一官勿言困，且喜願不違。", "我誠老賓客，合爪喜見之。", "關西相有在，行矣當無疑。"]'),
('b5bff3dd-08a4-44a8-ba36-3436608b7934','和李提舉山宮梅','曹勛','宋','宋诗','song-poetry','','[]','客中乍喜暄風回，徐行東郭嘉惟梅。',128,'全唐诗/poet.song.109000.json','["客中乍喜暄風回，徐行東郭嘉惟梅。", "蕭蕭千竿繚秀色，粲粲萬玉明芳蕤。", "海山飛仙墮萼綠，珠璫縞袂令人疑。", "須臾四山下倒景，華姿照眼無纖疵。", "主人才氣世所知，意謂澹坐徒爾爲。", "杯槃錯落光陸離，與客揖此玉一圍。", "鏘然韻語壓鄒枚，清思徹骨歌無歸。", "它時尚容嗣此賞，冠巾亂插無迎隨。"]'),
('9cc23717-2fb5-4d9c-a02d-0cb08b216877','和仲遠新池','曹勛','宋','宋诗','song-poetry','','[]','公有靜中趣，鑿山俯清深。',48,'全唐诗/poet.song.109000.json','["公有靜中趣，鑿山俯清深。", "秋風夜雨過，飽聞泉石音。", "雲岫冷蒼翠，游萍紛浮沉。", "心賞殊不已，悠然付微吟。"]'),
('81f948cd-4be9-4e4e-bd09-4ad678ba8c49','和錢處和扇車','曹勛','宋','宋诗','song-poetry','','[]','君家世德胄，富貴出謙受。',168,'全唐诗/poet.song.109000.json','["君家世德胄，富貴出謙受。", "泠然禦寇車，爲君駐戶牖。", "初訝鼓清薰，與客破宿酒。", "又疑建溪風，碾聲出兩肘。", "細視碧玉架，蓮梗轉雙手。", "遂令青田鶴，奮翼揮莫後。", "因知心匠妙，殆與造物友。", "人生土宇內，孰不涉煩垢。", "有物能渾成，既耦不以九。", "坐使塵沙劫，熱惱如拉朽。", "惟君韻高秀，人譽不容口。", "述作協穆如，亦莫祕關鈕。", "願君均此施，清凉被馳走。", "他時贊南風，爲佐虞舜壽。"]'),
('f519a8a1-4038-4393-995d-91258ce67c45','和李次仲韻','曹勛','宋','宋诗','song-poetry','','[]','先生柱史後，道價連城重。',108,'全唐诗/poet.song.109000.json','["先生柱史後，道價連城重。", "火龍燎金鼎，玉樓詎可凍。", "扁舟造交舊，已奏少微動。", "藹然義風暢，舉世士莫共。", "雪聲灑篷背，皓彩耿幽夢。", "相見忻把酒，清嘯塵落棟。", "願奉圯橋履，豈憚吏部甕。", "六鑿方有愧，一錐煩屢痛。", "益知仁者心，新詩得頻諷。"]'),
('f65e302b-ef06-4e48-a11a-0035bacaad96','和丹客林公','曹勛','宋','宋诗','song-poetry','','[]','自念老境今枯楊，徒順兒輩求藥方。',224,'全唐诗/poet.song.109000.json','["自念老境今枯楊，徒順兒輩求藥方。", "頗聞大藥性炎燥，如燎于原其中藏。", "是非海裏石鼎煎，大藥何適求雲仙。", "但傳鍾呂有妙旨，著在詩曲成華編。", "誦之如射必中的，堅然不朽貫金石。", "內外悉云妙在丹，吐納何嘗及津液。", "此事知有行則差，種麻安得豆有芽。", "北轅適楚每自失，復似入海欲算沙。", "豈惟阮籍途窮哭，錄錄尚念太倉粟。", "水雲難訪我輩人，風期詎知晉江客。", "三百字與五千言，一指便到玄牝門。", "它年肯約移玉趾，焚香促膝爲細論。", "浩氣收還質無槁，有待斯言能却老。", "小築雲卧天台山，再挂此冠供汛掃。"]'),
('69450983-f4c2-4ac5-a12d-696c14446def','小三郎試院高捷喜成四韻','曹勛','宋','宋诗','song-poetry','','[]','吾姪千里駒，一噴綠沙外。',48,'全唐诗/poet.song.109000.json','["吾姪千里駒，一噴綠沙外。", "韜鈐本書史，方畧挾經緯。", "小出附衆策，坐使勍敵潰。", "持弧褦襶子，雨汗亦良媿。"]'),
('c46004e1-89b4-4b0c-aac9-a3c2bc110862','憶天台','曹勛','宋','宋诗','song-poetry','','[]','懸車歸台山，乘田方自勤。',48,'全唐诗/poet.song.109000.json','["懸車歸台山，乘田方自勤。", "豈謂羈紲舊，嚴召煩聖君。", "至止忽三歲，遇事無一欣。", "屢奏歸田書，遐心行白雲。"]'),
('f2de1311-8f8f-4545-b64f-6e4ab6e2304e','送趙添戎還漳州','曹勛','宋','宋诗','song-poetry','','[]','北風號枯葉，漠漠天正寒。',132,'全唐诗/poet.song.109000.json','["北風號枯葉，漠漠天正寒。", "弛擔逆旅中，方稅游子鞍。", "吾甥遽相訪，別久心萬端。", "意定話親舊，或悲或可歡。", "乃將十年心，只作累刻殫。", "脩涂困塵土，客庖無盤餐。", "舉杯少延款，荷子襟抱寬。", "明朝復摻袂，老懷悽以酸。", "漳山無瘴烟，漳水無驚湍。", "侍親友于樂，勿倦爲戎官。", "願因南風期，時時寄平安。"]'),
('5c433bee-2861-4b16-ba49-7f51b004a9d9','春晴野步','曹勛','宋','宋诗','song-poetry','','[]','春風摇天宇，散策喜徐步。',48,'全唐诗/poet.song.109000.json','["春風摇天宇，散策喜徐步。", "樂與二三子，綠草池塘路。", "鳩鳴桑柘春，川闊牛羊暮。", "眷言益妍煖，更約窮逸趣。"]'),
('18b737ce-4280-4c85-b391-6000300bc70b','聞北軍犯淮','曹勛','宋','宋诗','song-poetry','','[]','落日慘客意，老懷增百憂。',60,'全唐诗/poet.song.109000.json','["落日慘客意，老懷增百憂。", "朔風動地吼，湖水吞天流。", "甲馬隘兩淮，殺氣橫九州。", "無德彼將滅，復讎我有休。", "羽檄交馳際，哀歌寄清愁。"]'),
('86bc5bca-1314-4a98-80a6-ef6a98f2b842','大駕親征','曹勛','宋','宋诗','song-poetry','','[]','驕虜敗盟至，飲馬淮之沱。',120,'全唐诗/poet.song.109000.json','["驕虜敗盟至，飲馬淮之沱。", "烟塵犯江漢，腥膻連岷峩。", "王師因雷動，虎臣亦星羅。", "靈旗蕩醜類，鐵馬馳琱戈。", "三軍指故國，巨艦凌滄波。", "一戎遂大定，上天佑無頗。", "整刷舊俗苦，掃除夷法苛。", "奸謀尚濟詭，既戰猶連和。", "復圖稱職爾，眇哉浯溪磨。", "已悉將相力，敢獻大風歌。"]'),
('267ecb7f-27f3-485a-a54d-48688e1703d0','將至嚴州丘平仲忽舟中見過','曹勛','宋','宋诗','song-poetry','','[]','念子別我久，我心嘗忡忡。',60,'全唐诗/poet.song.109000.json','["念子別我久，我心嘗忡忡。", "豈意蘭溪船，忽作瀟湘逢。", "一笑出意表，相對如夢中。", "子有親庭樂，我無塵事籠。", "願言雲水信，時寄菰蒲風。"]'),
('9270493e-03e7-4f6d-94d9-b4327d88d62d','次魯季欽安序堂韻','曹勛','宋','宋诗','song-poetry','','[]','蒙溪有廣厦，先生居之安。',144,'全唐诗/poet.song.109000.json','["蒙溪有廣厦，先生居之安。", "雅得林泉樂，不與塵土干。", "隠隠揖遥碧，瀰瀰濯清川。", "高明意乃適，至游情所耽。", "世故蠟味薄，豈待寶所參。", "北窗接陶令，素月撫阮咸。", "終吉遂無咎，位置遵連山。", "邈哉巖壑老，公契如金蘭。", "揆此宅相奇，歡然談笑間。", "落落幽勝處，安得同游盤。", "媿我西北客，恨匪戶籍占。", "但當風月夕，遐想冰雪顔。"]'),
('42a80b89-2d67-4e77-aa7e-0f8f7b242064','次李提舉過南園飲散賦詩韻','曹勛','宋','宋诗','song-poetry','','[]','小山叢薄棲南郭，蘭若蔽虧如間錯。',128,'全唐诗/poet.song.109000.json','["小山叢薄棲南郭，蘭若蔽虧如間錯。", "竹色低侵几案凉，海雲常壓波濤惡。", "遣愁五字了未有，取醉一樽良可托。", "折簡敢致先生游，俎豆陶匏殊寂寞。", "風流固自出元化，祥鳳本合巢阿閣。", "步武乃肯臨草草，塵光不間知落落。", "今年田疇極豐熟，早禾晚禾靡風雹。", "爲酒具黍共婆娑，應爲野人一笑作。"]'),
('46dcf37e-304f-4624-bb4a-d29dc544e4cf','次蔡瞻明題南園','曹勛','宋','宋诗','song-poetry','','[]','小亭倚山肋，東望渺雲海。',96,'全唐诗/poet.song.109000.json','["小亭倚山肋，東望渺雲海。", "松蘿翳窗戶，披拂大塊噫。", "細路窘步武，幽花植湫隘。", "鄰有長者轍，乃幸接符采。", "山爲獻秀潤，水亦舞澎湃。", "語真頓忘歸，談宗知有在。", "復拜五字句，新喜入四大。", "尚期一笑粲，天宇約晴快。"]'),
('557d6019-84b9-4e85-a0cc-c0addf816f0a','次韻程機宜感懷  其一','曹勛','宋','宋诗','song-poetry','','[]','幾見秋風來，坐念歲月改。',24,'全唐诗/poet.song.109000.json','["幾見秋風來，坐念歲月改。", "宮蕉泣白雨，孤愁越青海。"]'),
('cbcd4051-2c55-4429-b7ef-2d8a72b0f063','次韻程機宜感懷  其二','曹勛','宋','宋诗','song-poetry','','[]','十年戈甲際，四海烟塵中。',24,'全唐诗/poet.song.109000.json','["十年戈甲際，四海烟塵中。", "慘慘鼓角晚，萋萋禾黍風。"]'),
('eaaba608-5887-4e67-b666-e23553b398a3','次韻程機宜感懷  其三','曹勛','宋','宋诗','song-poetry','','[]','至交類萍梗，離合寧前知。',24,'全唐诗/poet.song.109000.json','["至交類萍梗，離合寧前知。", "相思梅花發，豈待中郎吹。"]'),
('23f2d90d-191e-4e28-9201-4e62f7cab7a1','次韻程機宜感懷  其四','曹勛','宋','宋诗','song-poetry','','[]','老驥千里志，元龍百尺樓。',24,'全唐诗/poet.song.109000.json','["老驥千里志，元龍百尺樓。", "想同湖海心，逸氣橫清秋。"]'),
('10a21557-cc20-4f54-980d-28b67a25e04d','次韻程機宜感懷  其五','曹勛','宋','宋诗','song-poetry','','[]','阿俊平生友，忘言金石志。',24,'全唐诗/poet.song.109000.json','["阿俊平生友，忘言金石志。", "永懷菡蓞晚，應想峨嵋翠。"]'),
('c472a379-34b9-4053-b926-6a18ac31bc1f','次韻程機宜感懷  其六','曹勛','宋','宋诗','song-poetry','','[]','北塞草色黄，吹作邊風駛。',24,'全唐诗/poet.song.109000.json','["北塞草色黄，吹作邊風駛。", "惟公發蹤謀，莫並橫經士。"]'),
('34a21731-016b-4ec2-9266-e4682318440f','次韻程機宜感懷  其七','曹勛','宋','宋诗','song-poetry','','[]','浩蕩氣明絜，慷慨念廢興。',24,'全唐诗/poet.song.109000.json','["浩蕩氣明絜，慷慨念廢興。", "何能一念息，空令衆愁增。"]'),
('95eed1a8-1b2d-46f9-9863-a42a4fdf4c75','次韻程機宜感懷  其八','曹勛','宋','宋诗','song-poetry','','[]','敵疆未尋盟，天王日嘗膽。',24,'全唐诗/poet.song.109000.json','["敵疆未尋盟，天王日嘗膽。", "邊聲入河嶽，孤臣增百感。"]'),
('73116eef-595a-4e43-9171-88bc81ac8f65','次南安務前水亭趙介叔韻','曹勛','宋','宋诗','song-poetry','','[]','茲亭楚風烟，晴嵐獻斜疊。',48,'全唐诗/poet.song.109000.json','["茲亭楚風烟，晴嵐獻斜疊。", "我來及秋杪，黄花舞紅葉。", "主人喜清論，曠覽意並愜。", "明年西郊春，會當來日涉。"]'),
('c74e815b-f447-4342-a049-b9761460eb2f','松窗用杜句爲韻和以棋酒爲意十首  其一','曹勛','宋','宋诗','song-poetry','','[]','相君有妙趣，一切不容且。',24,'全唐诗/poet.song.109000.json','["相君有妙趣，一切不容且。", "紋楸誰與談，惟彼上人者。"]'),
('3fee9cf5-7d53-4cdb-94f8-d7cc6620116b','松窗用杜句爲韻和以棋酒爲意十首  其二','曹勛','宋','宋诗','song-poetry','','[]','燕坐靡天游，何必求雲將。',24,'全唐诗/poet.song.109000.json','["燕坐靡天游，何必求雲將。", "泠然契至道，廐有真乘黄。"]'),
('c16651c2-d42a-4570-8e01-776cc4dc24c0','松窗用杜句爲韻和以棋酒爲意十首  其三','曹勛','宋','宋诗','song-poetry','','[]','游戲三昧手，絕代無對棋。',24,'全唐诗/poet.song.109000.json','["游戲三昧手，絕代無對棋。", "勝負俱可喜，是中聊作癡。"]'),
('90e23c76-d8d9-45fd-b103-5a0a5e15ceb7','松窗用杜句爲韻和以棋酒爲意十首  其四','曹勛','宋','宋诗','song-poetry','','[]','簾旌風不摇，博山雲自度。',24,'全唐诗/poet.song.109000.json','["簾旌風不摇，博山雲自度。", "主人下東山，月色轉歸路。"]'),
('07a34d34-a909-4e04-b0f8-aee7ef12f7a1','松窗用杜句爲韻和以棋酒爲意十首  其五','曹勛','宋','宋诗','song-poetry','','[]','小小試部勒，誠可銷長日。',24,'全唐诗/poet.song.109000.json','["小小試部勒，誠可銷長日。", "汀沙點鴉鷺，局带山雲濕。"]'),
('f7bcd471-9eb9-443b-9291-bb542f32bb18','松窗用杜句爲韻和以棋酒爲意十首  其六','曹勛','宋','宋诗','song-poetry','','[]','相君有妙理，芳醪正所應。',24,'全唐诗/poet.song.109000.json','["相君有妙理，芳醪正所應。", "紅粧艷綺席，翠幕張華燈。"]'),
('5eca1e40-4fdf-4d05-9631-79213b606715','松窗用杜句爲韻和以棋酒爲意十首  其七','曹勛','宋','宋诗','song-poetry','','[]','公富天人學，已收廊廟用。',24,'全唐诗/poet.song.109000.json','["公富天人學，已收廊廟用。", "宿有雲水債，聊寄泉石供。"]'),
('ea8b1889-abe9-4455-90f0-53beb29125ee','松窗用杜句爲韻和以棋酒爲意十首  其八','曹勛','宋','宋诗','song-poetry','','[]','擣香復篩辣，兵厨瀉芳酒。',24,'全唐诗/poet.song.109000.json','["擣香復篩辣，兵厨瀉芳酒。", "天宇澄清瀾，山中寄聲否。"]'),
('951c533b-f7ba-460c-b5a1-3196c7907891','松窗用杜句爲韻和以棋酒爲意十首  其九','曹勛','宋','宋诗','song-poetry','','[]','紅塵舊老我，青秧新插爲。',24,'全唐诗/poet.song.109000.json','["紅塵舊老我，青秧新插爲。", "寧幸田畯喜，何能屬車鴟。"]'),
('51763a64-a838-4e3f-8cc1-a25299783233','松窗用杜句爲韻和以棋酒爲意十首  其一○','曹勛','宋','宋诗','song-poetry','','[]','誦公十妙語，便覺舒華年。',24,'全唐诗/poet.song.109000.json','["誦公十妙語，便覺舒華年。", "意與境俱會，超凌心欲仙。"]'),
('7045a3fa-f160-47a7-b99f-c6e161140430','登逍遥閣','曹勛','宋','宋诗','song-poetry','','[]','松杉閟琳宮，仙君朝帝所。',48,'全唐诗/poet.song.109000.json','["松杉閟琳宮，仙君朝帝所。", "神風故靜默，人間漫今古。", "地靈驅鳥雀，磬聲肅壇宇。", "倚檻夕陽間，雲山認歸路。"]'),
('2c0147dd-8a26-4656-baa5-24ada2b4557c','謝李伯時自臨安見過台州二首  其一','曹勛','宋','宋诗','song-poetry','','[]','我生雅志泉石間，金閨通籍誠厚顔。',32,'全唐诗/poet.song.109000.json','["我生雅志泉石間，金閨通籍誠厚顔。", "真人下憫羈靮舊，琳館許辭鵷鷺班。"]'),
('a3568b7d-c152-41b7-a9ae-c4e58d5e6ea6','謝李伯時自臨安見過台州二首  其二','曹勛','宋','宋诗','song-poetry','','[]','念公萬里回異俗，睠我南來忘趼足。',32,'全唐诗/poet.song.109000.json','["念公萬里回異俗，睠我南來忘趼足。", "它時短幅問死生，爲向荒寒訪雲屋。"]'),
('abdc5675-b724-44a9-a531-d6b1a1b26b52','與曹道士','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','吾宗有佳士，導江秀賢支。',48,'全唐诗/poet.song.109000.json','["吾宗有佳士，導江秀賢支。", "妙處本清浄，浩氣蟠虹蜺。", "駕言還廬山，春臺方融怡。", "他時鳴雲璈，共採桐柏芝。"]'),
('a1ef2e3c-b85f-4a37-be1b-3d600d951d85','擬古','曹勛','宋','宋诗','song-poetry','','[]','君有西州役，金爐斷夕香。',48,'全唐诗/poet.song.109000.json','["君有西州役，金爐斷夕香。", "虛窗伴幽獨，惟有明月光。", "帳深清露寒，繡冷雙鴛鴦。", "明發持似君，知妾心凄凉。"]'),
('d8ab8dbe-2288-460a-9452-d7e17b300528','戲作','曹勛','宋','宋诗','song-poetry','','[]','昨日暴熱加藴隆，今日寒色如窮冬。',112,'全唐诗/poet.song.109000.json','["昨日暴熱加藴隆，今日寒色如窮冬。", "居然寒暑變春事，大鈞造化誰始終。", "我欲直前扣天闕，萬神森衛不可謁。", "上玄豈縱勾芒神，朝驅赫日夜沉月。", "吹香濕玉失長養，發陳璺啟若徒設。", "願天勿令移指麾，却收正令還春曦。", "暄風布暖活貧窶，免詠眉山禦臘衣。"]'),
('52ca6481-0ec8-4394-a3c2-2ce9d2aecf66','效寒山體  其一','曹勛','宋','宋诗','song-poetry','','[]','嗟我世間人，有山只暫聚。',48,'全唐诗/poet.song.109000.json','["嗟我世間人，有山只暫聚。", "富貴空中花，遇合風裏絮。", "夜夜植業種，朝朝奔苦趣。", "佛有妙蓮花，讀取平等句。"]'),
('20e72b11-f767-470a-9146-beb50288c660','效寒山體  其二','曹勛','宋','宋诗','song-poetry','','[]','嗟我世間人，强有六親念。',48,'全唐诗/poet.song.109000.json','["嗟我世間人，强有六親念。", "看子是惡少，目妬作美艷。", "分香且供佛，有財莫言儉。", "俯仰即異世，六尺那可占。"]'),
('c9deec1b-e1c2-4d5a-ae46-efb9c8d18102','新秋自喜信筆','曹勛','宋','宋诗','song-poetry','','[]','嫋嫋秋色來不慳，翩飜落葉鋪闌干。',64,'全唐诗/poet.song.109000.json','["嫋嫋秋色來不慳，翩飜落葉鋪闌干。", "藏鶑杜燕圃中靜，蘆葉藕花波水寒。", "我生逢辰似陸賈，老去恨未歸長安。", "天公賜以八旬老，客况如寄僧家園。"]'),
('a1ce65bb-3960-4127-9d7b-88c04734d418','中秋前一日邀賀子忱爲對月之款乃審放意山林扁舟東去引企不已偶得小詩','曹勛','宋','宋诗','song-poetry','','[]','積陰掃秋風，吹作今夕月。',48,'全唐诗/poet.song.109000.json','["積陰掃秋風，吹作今夕月。", "山嶽四高寒，天地一澄澈。", "幽人渺何許，應喜清暉發。", "一樽不同樂，孤光共愁絕。"]'),
('8ac7c232-72b1-4965-85e5-ec9165fa4d8f','人倫僧求字','曹勛','宋','宋诗','song-poetry','','[]','上人早出岷峩山，頗游五嶺崎嶇還。',64,'全唐诗/poet.song.109000.json','["上人早出岷峩山，頗游五嶺崎嶇還。", "妙定休咎指諸掌，會心不出眉宇間。", "顧予從來多得喪，歸老林泉喜無量。", "它年見我巖壑中，應笑如如得非相。"]'),
('a151136b-4137-41fe-aff8-ea17315ee4b5','過江州柴桑淵明故居','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡廬游遍僧家園，南望柴桑墟里烟。',64,'全唐诗/poet.song.109000.json','["匡廬游遍僧家園，南望柴桑墟里烟。", "但尋疃畦供指畫，不知市井今幾遷。", "五柳既無只衰草，三徑莫識皆平田。", "欲歸四顧但遐想，歸來高致猶凜然。"]'),
('3bf367c0-8694-455f-ba84-290f059ba1e0','感齒髮之衰作詩自解','曹勛','宋','宋诗','song-poetry','','[]','我生飽艱苦，初年心已衰。',192,'全唐诗/poet.song.109000.json','["我生飽艱苦，初年心已衰。", "况今七十化，形憊聊支持。", "頭童漸不束，齒敗餘牆圍。", "髮落尚爾爾，齒豁良依依。", "魚蟹强剝啄，梨栗亦空施。", "豈惟意倦怠，咀齧徒攢眉。", "老妻諳其苦，飯顆必若糜。", "佐以推飯物，批抹煩刀揮。", "不知更十年，此身何可支。", "昔聞張蒼老，相國力乃疲。", "金盤厭羔膩，玉乳環蛾眉。", "至真瀹元精，芳潤充豐肌。", "閑出天下論，用爲漢室奇。", "我今何有哉，豐悴理所宜。", "不然舉此志，中有浩氣怡。", "外形以爲得，彼美當虛辭。"]'),
('572001dc-9422-431f-b91c-cfb8a647dfd0','過淮值雨偶成呈王樞密','曹勛','宋','宋诗','song-poetry','','[]','明日立秋秋色至，向晚雨隨大風起。',64,'全唐诗/poet.song.109000.json','["明日立秋秋色至，向晚雨隨大風起。", "飜盆如麻不足喻，倒海傾江差可擬。", "高林老木亞復折，簾幕頹垣紛若委。", "須臾霽色上南山，落日燒雲照淮水。"]'),
('c4e09f7f-e1c5-45a0-aa14-e3347ec334b3','王樞密見和復用前韻','曹勛','宋','宋诗','song-poetry','','[]','惟公带礪長淮比，聊爲蒼生拂衣起。',64,'全唐诗/poet.song.109000.json','["惟公带礪長淮比，聊爲蒼生拂衣起。", "一時冠劍滿漢殿，簡注非公欲誰擬。", "金鑾文采粲黼藻，玉扆平章看端委。", "敢將蠅影附驥涂，願薦盤盂奉明水。"]'),
('5e69ce7a-483d-40d9-b4b3-506fee60e9b8','老病','曹勛','宋','宋诗','song-poetry','','[]','老態日益出，老病日見侵。',48,'全唐诗/poet.song.109000.json','["老態日益出，老病日見侵。", "疾多戒少飲，杯行常淺斟。", "孤坐每憚起，紓思不成吟。", "白日事有待，中夜誰知音。"]'),
('03d834c9-19d7-458b-8632-c3ba5934c799','懷歸自訟','曹勛','宋','宋诗','song-poetry','','[]','讀書老不入，屢讀屢遺忘。',48,'全唐诗/poet.song.109000.json','["讀書老不入，屢讀屢遺忘。", "遇事欲强記，轉首輙怊悵。", "以此趨事爲，豈但成嘲謗。", "人豈不自知，去矣殆天放。"]'),
('9bce2c14-64ff-4073-b504-95f569cd5963','治圃','曹勛','宋','宋诗','song-poetry','','[]','腰斧治小圃，樸樕久不省。',48,'全唐诗/poet.song.109000.json','["腰斧治小圃，樸樕久不省。", "妬芽盡芟除，條達出秀整。", "臨津獲梅株，蓓玉作寒炯。", "三遶無所裁，留看橫斜影。"]'),
('2f4e213d-bd5c-4a35-bc63-509dd69ceacf','虛飄飄','曹勛','宋','宋诗','song-poetry','','[]','虛飄飄，虛飄飄。',64,'全唐诗/poet.song.109000.json','["虛飄飄，虛飄飄。", "禹門三級浪，仙子百花橋。", "雪霙輕作霰，簷溜凍成條。", "游絲千尺網春色，掣電一抹收遠霄。", "虛飄飄，虛飄飄，此時幻聚猶堅牢。"]'),
('45e9ce2b-1cf9-4ce0-b1c2-1ea78a523f13','梅','曹勛','宋','宋诗','song-poetry','','[]','吾家舍西多此梅，白玉花綴棠棣枝。',128,'全唐诗/poet.song.109000.json','["吾家舍西多此梅，白玉花綴棠棣枝。", "冒寒糝糝已藴玉，自開及謝酒屢持。", "羈栖臨安三換歲，向來一醉知無期。", "君家此花富冰艷，舉觴折贈如雲披。", "欣然拱眎不暇揖，坐想故隠增依依。", "只今匏繫未歸去，俗鞅吏網相驅馳。", "就公看花仍摘實，信美我語如觀頤。", "祇應兩庵有歸夢，夢到花下奚復疑。"]'),
('91d50ffd-6e3a-4916-8513-30ec9dd6af61','寄張達道','曹勛','宋','宋诗','song-poetry','','[]','茅峰何山亦何好，瑶木琪華並三島。',112,'全唐诗/poet.song.109000.json','["茅峰何山亦何好，瑶木琪華並三島。", "其間巖洞邃且深，隠居仙人得窮討。", "遠業已跨雪色馿，諸孫何能玉顔老。", "黑虎會有青鸞信，洞章同夢池塘草。", "關鍵真符付自爾，鴛鴦瓊壺每傾倒。", "頗聞雲篆經九試，自應太上傳三寶。", "他年芒屨謁凝神，洗心拱聽無上道。"]'),
('b416bee7-274a-49e8-a09f-5ab40e779cd7','送鄭猷歸福唐','曹勛','宋','宋诗','song-poetry','','[]','君家有唐第一人，耕隠谷口同子真。',64,'全唐诗/poet.song.109000.json','["君家有唐第一人，耕隠谷口同子真。", "臨安始終三十載，我亦掛冠君歸閩。", "重話向來倦游處，蒼顔禿鬢皆如銀。", "喜君南歸不可從，雁飛時寄天台春。"]'),
('9785216b-8f8f-43d8-ac95-e045f8757aff','王正道再遇竹冠輒和來韻見鄙愫二首  其一','曹勛','宋','宋诗','song-poetry','','[]','惟公秉操如仙官，一任酷暑兼祁寒。',116,'全唐诗/poet.song.109000.json','["惟公秉操如仙官，一任酷暑兼祁寒。", "存心香火接造物，達誠果再逢竹冠。", "應言蓬萊有至樂，六十九洞無纖惡。", "松姿鶴態不復老，琪蘂瑶房未嘗落。", "上庵至真聞屢過，口付訣目相琢磨。", "公今得妙騰逸駕，我嗟老景飛輕梭。", "願投黄寧拯將溺有香，一瓣致禮敬誦生神歌。"]'),
('a1a48f5d-0509-44cf-b303-78c608865efe','王正道再遇竹冠輒和來韻見鄙愫二首  其二','曹勛','宋','宋诗','song-poetry','','[]','先生有號復有官，不畏隆暑兼冬寒。',116,'全唐诗/poet.song.109000.json','["先生有號復有官，不畏隆暑兼冬寒。", "歸來山中侶松檜，無愧太上翔雲冠。", "我比同庵有餘樂，雲山百好無一惡。", "喜君宏度如容波，媿我大匏真濩落。", "乃今漂流如無何，進退未果徒鎸磨。", "夢魂游揚欲舞蝶，歸意浩蕩遄飛梭。", "得歸沖嗇雖當侵伐後，一醉尚可同詠歸山歌。"]'),
('8a5bcc69-9c5e-411b-96e6-206927f97e9b','與馬通判','曹勛','宋','宋诗','song-poetry','','[]','皖山邃密常若春，中有仙士久隠淪。',64,'全唐诗/poet.song.109000.json','["皖山邃密常若春，中有仙士久隠淪。", "幅巾嘯傲喜接物，彷彿白鶴乘孤雲。", "朅來帝所暫戾止，亹亹清言償所喜。", "內慙已老不受教，猶幸一奉圯橋履。"]'),
('6c0324a8-3169-4650-817b-7a3b1b8225bc','題衛太尉巖集圖','曹勛','宋','宋诗','song-poetry','','[]','衛公雅志安林泉，稟生似無塵土緣。',192,'全唐诗/poet.song.109000.json','["衛公雅志安林泉，稟生似無塵土緣。", "英標孤映出羣鶴，姿儀密際三界仙。", "居臨山麓絕煥麗，楚楚松竹相後先。", "幽巖嵌空截綠玉，嘉木蔭映摇蒼烟。", "喜招社友共清集，中有一老談幽禪。", "其餘六逸咸自若，炷香瀹茗殊怡然。", "曹丘倚案獨閣筆，想見窘思人所憐。", "衆賓得接書史樂，浩氣高壓江湖天。", "只覺談話可上漢，不擬步武猶居廛。", "墨隠能畫巧爲此，一段美事端宜傳。", "好辭更賦風月上，勝韻直徹星辰邊。", "他時一笑忽相值，固應何止三千年。"]'),
('b99326d7-b7ae-4ac0-abca-4981dd307545','謝彭大夫惠寒山詩三首  其一','曹勛','宋','宋诗','song-poetry','','[]','老彭臨安來，惠我以寒山。',48,'全唐诗/poet.song.109000.json','["老彭臨安來，惠我以寒山。", "盡是化導意，更無一句閒。", "頓驅迷悞心，盡置針石間。", "久久得受用，誰畏凋朱顔。"]'),
('08028efe-053c-46f8-b90f-662d142883f2','謝彭大夫惠寒山詩三首  其二','曹勛','宋','宋诗','song-poetry','','[]','人生大塊內，徒以蟻旋磨。',48,'全唐诗/poet.song.109000.json','["人生大塊內，徒以蟻旋磨。", "不有明眼人，何能知己過。", "直指識自性，老甑必破墮。", "身詩忽兼忘，嘉惠天來大。"]'),
('31a5dea1-e5a5-4e5d-810d-26db33609607','謝彭大夫惠寒山詩三首  其三','曹勛','宋','宋诗','song-poetry','','[]','平生爲物役，年紀積漸老。',48,'全唐诗/poet.song.109000.json','["平生爲物役，年紀積漸老。", "不省這箇意，老得越顛倒。", "自讀二詩來，迷雲掃空照。", "爲我謝彭翁，且喜無煩惱。"]'),
('8c74b44a-c138-4947-9439-4696a095b1a9','投連泉州顯學五十韻','曹勛','宋','宋诗','song-poetry','','[]','某也多奇蹇，艱難已十年。',288,'全唐诗/poet.song.109000.json','["某也多奇蹇，艱難已十年。", "素風惟汗簡，生計只韋編。", "先業雖殊軌，時流幸比肩。", "固窮心尚壯，鼓勇氣無前。", "念昔時方阨，居懷影自憐。", "廟堂蜂蠆毒，宮闕犬羊羶。", "胡騎南趨楚，天皇北狩燕。", "六龍塵黯淡，二聖淚潺湲。", "故國人何在，新君信未傳。", "自陳心膽大，肯避虎狼先。", "落日幽都路，西風易水壖。", "珥璫金不暗，睿札墨仍鮮。", "間道逃穹帳，開緘徹御筵。", "第知從聖化，寧復較騰騫。", "寵錫蒙天造，兵戎付路權。", "危言乖上相，邏職俾南泉。", "復記丹陽渡，初移御座船。", "孤城逃守令，衂陣擁戈鋋。", "法駕方登頓，生民豈保全。", "嬰城因率爾，拔劍意茫然。", "軍旅增提振，囷儲不棄捐。", "詔封霑錄用，師氣亦周旋。", "部領終如舊，奔馳信有緣。", "萱庭方舞綵，紼序忽終天。"]'),
('0c86b997-be35-49b2-af88-e363411047a5','張右相生日二首  其一','曹勛','宋','宋诗','song-poetry','','[]','玉律歌無射，金風下四蓂。',48,'全唐诗/poet.song.109000.json','["玉律歌無射，金風下四蓂。", "三台丞相位，一德將臣星。", "弼亮時師表，文章世典刑。", "百神扶大手，遠業慶千齡。"]'),
('078ab461-ac46-4c30-bd63-c2ed36aea2e9','張右相生日二首  其二','曹勛','宋','宋诗','song-poetry','','[]','氣稟無爲秀，鍾靈付秉鈞。',48,'全唐诗/poet.song.109000.json','["氣稟無爲秀，鍾靈付秉鈞。", "周南知盛德，江左在斯民。", "衮繡東山望，貂蟬綵服春。", "帝師殊壽祉，漢祚有元臣。"]'),
('40bdb00a-a192-4451-8e15-23386da3a9bb','曾端伯自承移帥川口有懷風旨無便附信忽領教喜成小詩附便奉呈三首  其一','曹勛','宋','宋诗','song-poetry','','[]','好在曾夫子，寧知晤語期。',48,'全唐诗/poet.song.109000.json','["好在曾夫子，寧知晤語期。", "倚毗離楚日，鼓吹入夔時。", "赤甲薰風近，黄堂淑景遲。", "相望邈坤軸，空詠竹枝詞。"]'),
('d993c098-627f-4282-b559-8756a3f57f69','曾端伯自承移帥川口有懷風旨無便附信忽領教喜成小詩附便奉呈三首  其二','曹勛','宋','宋诗','song-poetry','','[]','衣袽先九潤，此日上瞿塘。',48,'全唐诗/poet.song.109000.json','["衣袽先九潤，此日上瞿塘。", "風月動官柳，旌旗開蜀疆。", "詩壇凌李杜，政績過龔黄。", "追詔知非晚，肯令生智囊。"]'),
('2ac139d8-f85c-499a-8348-1d19e6b6f597','曾端伯自承移帥川口有懷風旨無便附信忽領教喜成小詩附便奉呈三首  其三','曹勛','宋','宋诗','song-poetry','','[]','某也庵居久，心形付自然。',48,'全唐诗/poet.song.109000.json','["某也庵居久，心形付自然。", "山林藏老退，松竹養風烟。", "遇物元非遠，尋真自一天。", "懷人會心處，熟誦見山篇。"]'),
('0bb40956-e74b-4a94-a7ce-e9ff7e6c6481','和賀子忱喜雪','曹勛','宋','宋诗','song-poetry','','[]','藴玉梅初艷，埋青麥自豐。',96,'全唐诗/poet.song.109000.json','["藴玉梅初艷，埋青麥自豐。", "漸冰留水研，時喜拂窗風。", "能賦懷王粲，開樽憶孔融。", "警寒方認鶴，掃逕屢嗔童。", "色動書帷白，寒侵蠟炬紅。", "剡溪方逸想，秀句墮春工。", "豈意疎慵外，猶存引領中。", "須君乘暖景，一笑得相同。"]'),
('f22d5967-9d47-433b-a58f-a4cd7e18d7e2','和泉伯幽思韻二首  其一','曹勛','宋','宋诗','song-poetry','','[]','蕭蕭雲日靜，細細竹風侵。',48,'全唐诗/poet.song.109000.json','["蕭蕭雲日靜，細細竹風侵。", "窗影方虛白，爐烟一沒沉。", "帝鄉憐久客，歸夢亦何心。", "洞戶褰珠網，應煩問藁砧。"]'),
('ade302ae-369d-40f2-8d00-ded2c23ce99d','和泉伯幽思韻二首  其二','曹勛','宋','宋诗','song-poetry','','[]','每惜年華易，風燈與鑿光。',48,'全唐诗/poet.song.109000.json','["每惜年華易，風燈與鑿光。", "心情成老大，世態只炎凉。", "冷入芭蕉雨，烟輕薜荔牆。", "故人愁更遠，夜夜渡清湘。"]'),
('520a6c58-483e-40e3-909d-6c1443b111d2','和子忱惠八月青梅','曹勛','宋','宋诗','song-poetry','','[]','神仙聞水部，妙物與長生。',48,'全唐诗/poet.song.109000.json','["神仙聞水部，妙物與長生。", "鼎飪元滋味，山樊好弟兄。", "佳音當有象，短韻已馳兵。", "試咽甘酸處，行看雪裏英。"]'),
('8f3c0148-1c0c-457a-ac4e-3878742623d2','和錢處和野堂  其一','曹勛','宋','宋诗','song-poetry','','[]','日浄嵐光上，山藏野意添。',48,'全唐诗/poet.song.109000.json','["日浄嵐光上，山藏野意添。", "海潮來隠几，越岫巧當簾。", "絕俗宜招隠，論詩未屬厭。", "居雖朝市近，事事見安恬。"]'),
('101cf12f-50cf-474e-8a8d-b626946226a8','和錢處和野堂  其二','曹勛','宋','宋诗','song-poetry','','[]','堂隠雲將隔，名高客已知。',48,'全唐诗/poet.song.109000.json','["堂隠雲將隔，名高客已知。", "半巖施匠石，一室見操爲。", "鐘鼎功方著，山林興未遲。", "蘭臺風致在，更喜讀新詩。"]'),
('25c7d7e7-cd4e-4ce0-9f60-4b599666931a','和次子耜久雨韻三首  其一','曹勛','宋','宋诗','song-poetry','','[]','綠漲東籬菊，桐凋古井欄。',48,'全唐诗/poet.song.109000.json','["綠漲東籬菊，桐凋古井欄。", "雨頻傷早穀，烟冷作新寒。", "有木皆生耳，何顔得渥丹。", "平章濟農事，清坐且團團。"]'),
('7608638a-34f7-4012-afa4-c093b31e98da','和次子耜久雨韻三首  其二','曹勛','宋','宋诗','song-poetry','','[]','眩瞀知陰久，茶甌不厭濃。',48,'全唐诗/poet.song.109000.json','["眩瞀知陰久，茶甌不厭濃。", "第憂沉稼穡，寧問浸芙蓉。", "天闊翻盆雨，雲昏淡墨峯。", "長安鼎烹者，列坐正撞鐘。"]'),
('05aa7612-92c7-40c3-a542-a2969deec0ce','和次子耜久雨韻三首  其三','曹勛','宋','宋诗','song-poetry','','[]','連朝陰未斷，仰食慮尤深。',48,'全唐诗/poet.song.109000.json','["連朝陰未斷，仰食慮尤深。", "簷溜無窮響，村燈幾處砧。", "吾兒詩有債，老我韻勞心。", "屏翳安能借，吹天掃積陰。"]'),
('e887b04e-d935-4cf4-bf52-00ad09eaa7fb','和曾守有作','曹勛','宋','宋诗','song-poetry','','[]','問俗猶秋熱，移牀趁晚凉。',48,'全唐诗/poet.song.109000.json','["問俗猶秋熱，移牀趁晚凉。", "笑談懷酒伴，節物念吾鄉。", "聞道銀槽熟，思傾玉指香。", "政須圖一醉，寧復較行觴。"]'),
('84398cf8-c27c-437d-8acd-e1b131cd5d8c','和人見貽','曹勛','宋','宋诗','song-poetry','','[]','某也多奇蹇，當年侍玉除。',48,'全唐诗/poet.song.109000.json','["某也多奇蹇，當年侍玉除。", "馳驅先輅馬，扈從達幽都。", "守己常安分，臨官歎自愚。", "旨甘方薄宦，一語冀逢途。"]'),
('23a0d54d-51dc-498f-92ec-6811a1283ab0','和王應夫見貽二首  其一','曹勛','宋','宋诗','song-poetry','','[]','不見應夫久，永懷清晤同。',48,'全唐诗/poet.song.109000.json','["不見應夫久，永懷清晤同。", "名高湖海內，詩在笑談中。", "光泛崇蘭露，香傳碧桂風。", "只應家學著，更看廟堂功。"]'),
('c4505964-10f5-43cb-a980-37c236d8bf72','和王應夫見貽二首  其二','曹勛','宋','宋诗','song-poetry','','[]','况味年來薄，書音寄亦稀。',48,'全唐诗/poet.song.109000.json','["况味年來薄，書音寄亦稀。", "亂離多病後，人物故園非。", "潮揭當年會，朋儕幾旐歸。", "悲心那聽此，生理念依微。"]'),
('08903aa3-ba49-4159-9bd1-441615a0fa97','和雙溪','曹勛','宋','宋诗','song-poetry','','[]','常憶雙溪老，伽陀日益多。',48,'全唐诗/poet.song.109000.json','["常憶雙溪老，伽陀日益多。", "津梁今坐斷，風月奈君何。", "清梵山藏路，南薰歸滿柯。", "何時話暌闊，芒屨入雲蘿。"]'),
('7987fca2-3ea5-40b3-9283-11069171da37','和曾谹父見寄二首  其一','曹勛','宋','宋诗','song-poetry','','[]','活水從澆竹，閑書會引眠。',48,'全唐诗/poet.song.109000.json','["活水從澆竹，閑書會引眠。", "玉溪何處所，璧月共清圓。", "詩到惟供錄，歡如不隔年。", "何當見風度，應向日華邊。"]'),
('a292998f-9220-424e-8ee9-8b6a05c5fdb2','和曾谹父見寄二首  其二','曹勛','宋','宋诗','song-poetry','','[]','小庵雲雨上，朝檻俯晴雷。',48,'全唐诗/poet.song.109000.json','["小庵雲雨上，朝檻俯晴雷。", "客子得幽勝，道人時往來。", "閑情聊自喜，昔事只堪哀。", "沖嗇從茲老，何能敘玉臺。"]'),
('df6a7a17-5b3f-4a35-8eff-0113fa059749','和茅山張達道二首  其一','曹勛','宋','宋诗','song-poetry','','[]','茅岫藏清隠，詩仙秀格春。',48,'全唐诗/poet.song.109000.json','["茅岫藏清隠，詩仙秀格春。", "道真淵有妙，素守峻能循。", "鶴舉秋聲遠，詩成句法新。", "遥知游詠樂，下筆更如神。"]'),
('d9092208-9d52-4039-b21a-9f492d5dfbb6','和茅山張達道二首  其二','曹勛','宋','宋诗','song-poetry','','[]','好笑曹功顯，山林過幾春。',48,'全唐诗/poet.song.109000.json','["好笑曹功顯，山林過幾春。", "世緣猶積壓，塵網復因循。", "踵息綿如在，顛毛雪更新。", "歲華行八十，泉石正馳神。"]'),
('626918a2-b932-4928-a13e-d89aa13d431c','和國器喜以事業爲懷二首  其一','曹勛','宋','宋诗','song-poetry','','[]','鄭氏傳家學，詩書不愧心。',48,'全唐诗/poet.song.109000.json','["鄭氏傳家學，詩書不愧心。", "佩刀知素業，左序况同襟。", "但喜知難字，何能識至音。", "小軒多暇日，爲賦九州箴。"]'),
('91b82f9e-2ffe-4634-ac5a-d1bb6d8d34b8','和國器喜以事業爲懷二首  其二','曹勛','宋','宋诗','song-poetry','','[]','久無軒冕意，出處亦何心。',48,'全唐诗/poet.song.109000.json','["久無軒冕意，出處亦何心。", "世味思三沐，花風快一襟。", "喜君方礪志，顧我豈知音。", "醫手非吾事，深慚不可箴。"]'),
('934f87ef-087d-4839-88d0-11edd9e47d06','次韻呈南嘉','曹勛','宋','宋诗','song-poetry','','[]','塞北初辭虜，泉南濫總戎。',48,'全唐诗/poet.song.109000.json','["塞北初辭虜，泉南濫總戎。", "請纓懷壯節，橫槊媿家風。", "草木年華晚，關河鼓角雄。", "何當一笑粲，要賦馬羣空。"]'),
('52342007-2fcf-4349-be2a-529098b810f6','用李參政游延福寺韻上之','曹勛','宋','宋诗','song-poetry','','[]','落日泉南郡，秋風嶺北城。',144,'全唐诗/poet.song.109000.json','["落日泉南郡，秋風嶺北城。", "台符均庶等，杖履喜幽行。", "與客情文重，持懷事物輕。", "致君皆典禮，躋俗向丕平。", "相業甌名在，辭華鉢韻成。", "豈惟才廣大，且復性澄泓。", "賤子欣承庇，微官得代耕。", "孤單常自畏，比數欲誰名。", "橐有書千卷，家無屋一楹。", "朝廷今再造，心跡漸雙清。", "山轉客容薄，天迷海色橫。", "心期奉圯履，鎔冶在高情。"]'),
('89d77150-d103-43fe-9259-170631978a38','和同官問耳疾六首  其一','曹勛','宋','宋诗','song-poetry','','[]','行年七十化，聵景亦乘時。',48,'全唐诗/poet.song.109000.json','["行年七十化，聵景亦乘時。", "日近尤爲祟，雷轟尚弗知。", "顧多居士病，頼有寧馨兒。", "若得都無聽，唯哦見贈詩。"]'),
('a2d40a11-55c5-4c48-9ddb-c3028489738f','和同官問耳疾六首  其二','曹勛','宋','宋诗','song-poetry','','[]','鐘鼓嗟無與，衰殘亦任時。',48,'全唐诗/poet.song.109000.json','["鐘鼓嗟無與，衰殘亦任時。", "歲華髭鬢上，心事水雲知。", "尚若泠然善，何能養就兒。", "數篇存雅道，三復愧新詩。"]'),
('df7da7a5-88ef-46e7-8d74-2b1fb11e7bd8','和同官問耳疾六首  其三','曹勛','宋','宋诗','song-poetry','','[]','牛鬭當年事，何當復此時。',48,'全唐诗/poet.song.109000.json','["牛鬭當年事，何當復此時。", "謷乎雖有象，默爾類無知。", "不作多聞士，難尤造物兒。", "儻能三耳出，更誦五言詩。"]'),
('289ae03f-b21f-4806-9b35-d262e7124b02','和同官問耳疾六首  其四','曹勛','宋','宋诗','song-poetry','','[]','慍心雖悄悄，藥物亦時時。',48,'全唐诗/poet.song.109000.json','["慍心雖悄悄，藥物亦時時。", "半耳念非病，全身聵始知。", "三湘懷楚些，一櫂憶吳兒。", "會見相陪處，應多古錦詩。"]'),
('6a1025a2-ce81-443c-9d3a-425e1f611b87','和同官問耳疾六首  其五','曹勛','宋','宋诗','song-poetry','','[]','袁宏方詠史，江總得隨時。',48,'全唐诗/poet.song.109000.json','["袁宏方詠史，江總得隨時。", "歸興連天去，文盟落筆知。", "雨多移蟻垤，花過靜蜂兒。", "頼有西齋友，薰風正入詩。"]'),
('60308070-2738-47bf-b233-1ef423ccc5a5','和同官問耳疾六首  其六','曹勛','宋','宋诗','song-poetry','','[]','中原困戎馬，久欲謁明時。',48,'全唐诗/poet.song.109000.json','["中原困戎馬，久欲謁明時。", "文軌雖非昔，英雄似未知。", "寰中無好漢，帳下得豬兒。", "慨念燕然勒，終還吉甫詩。"]'),
('d3ac6a0a-707b-4e60-ae3a-c7cf50e9a52f','久雨三首  其一','曹勛','宋','宋诗','song-poetry','','[]','五月正陽月，何嘗與雨期。',48,'全唐诗/poet.song.109000.json','["五月正陽月，何嘗與雨期。", "浹旬簷溜注，冞夕水聲馳。", "古屋床床漏，苔牆堵堵隳。", "子桑誰復餉，勾漏政須醫。"]'),
('846ee027-7a1a-4e19-9aca-89cd0fbea184','久雨三首  其二','曹勛','宋','宋诗','song-poetry','','[]','蝕餘仍苦雨，猶爾晦陽暉。',48,'全唐诗/poet.song.109000.json','["蝕餘仍苦雨，猶爾晦陽暉。", "浩浩陂三尺，家家水半扉。", "汩陳非佛意，昏墊蓋天機。", "祈懇須冥造，當仁要達微。"]'),
('a0af5ba3-6588-4e32-a2c8-1c42725458ca','久雨三首  其三','曹勛','宋','宋诗','song-poetry','','[]','一旬連夜雨，人物困泥中。',48,'全唐诗/poet.song.109000.json','["一旬連夜雨，人物困泥中。", "竹樹侵書暗，橫流趁路通。", "竈烟薪更濕，簷溜耳難聰。", "潤逼衣襟重，何時日照東。"]'),
('6e8fa4cb-e683-44b2-83e7-8ad3abd73821','贈胡珵隠君','曹勛','宋','宋诗','song-poetry','','[]','星聚西豪里，人誰識少微。',48,'全唐诗/poet.song.109000.json','["星聚西豪里，人誰識少微。", "忘懷卷外少，此道眼中稀。", "筆墨騰瀛禁，圖書動衮衣。", "趨風忻並世，一語欲清非。"]'),
('4f34ae1a-e730-4746-b90e-8abdc42e72fa','贈張鍊師二首  其一','曹勛','宋','宋诗','song-poetry','','[]','昔仰蘇仙跡，今瞻弄玉身。',48,'全唐诗/poet.song.109000.json','["昔仰蘇仙跡，今瞻弄玉身。", "岳靈朝捧劍，飆馭夜朝真。", "笙鶴聲常近，烟霞到處新。", "願言承道蔭，秘語慰斯民。"]'),
('5e62e6af-8010-4e47-9c2d-9cb08e8de3a5','贈張鍊師二首  其二','曹勛','宋','宋诗','song-poetry','','[]','護幄通明殿，仙階貴可知。',48,'全唐诗/poet.song.109000.json','["護幄通明殿，仙階貴可知。", "塵凡聊混跡，功行欲康時。", "明月丹崖路，秋風白玉墀。", "行聞普濟足，飛步萬真期。"]'),
('8d6af67c-4cdd-45bf-a2f0-c2a876c4d140','題小石接待庵','曹勛','宋','宋诗','song-poetry','','[]','老大思閒適，山林喜晦藏。',48,'全唐诗/poet.song.109000.json','["老大思閒適，山林喜晦藏。", "一廛雖異縣，三徑得崇岡。", "地僻烟雲潤，年豐黍稷香。", "心期得多矣，襟袖更新凉。"]'),
('ceb05b6d-daa4-4538-ba44-76a3d1b88663','題今是齋','曹勛','宋','宋诗','song-poetry','','[]','偉矣高情著，齋名世亦稀。',48,'全唐诗/poet.song.109000.json','["偉矣高情著，齋名世亦稀。", "但能塵事遠，便覺昔年非。", "琴靜凝香碧，神清衆妙歸。", "諸緣只心法，鷗鳥亦忘機。"]'),
('6359f1bf-7792-4651-b92b-990041d8cd3a','敬題箕潁集後二首  其一','曹勛','宋','宋诗','song-poetry','','[]','昔侍先君日，多令誦近詩。',48,'全唐诗/poet.song.109000.json','["昔侍先君日，多令誦近詩。", "尚知塗抹處，猶記唱酬時。", "竟負經邦志，終爲造物疑。", "篇篇親訓釋，字字念恩慈。"]'),
('e8e94847-1ca5-4eb2-8d57-7571adc00ce5','敬題箕潁集後二首  其二','曹勛','宋','宋诗','song-poetry','','[]','太史推經學，先君得最深。',48,'全唐诗/poet.song.109000.json','["太史推經學，先君得最深。", "文章八面敵，辛苦一生心。", "禁掖傳新句，公卿錄苦吟。", "遺留示有子，捧卷淚盈襟。"]'),
('43cfb7d8-4111-4ad0-bcfc-6ac45558428f','寄溧水宰李仲鎮','曹勛','宋','宋诗','song-poetry','','[]','不見李君久，水雲魚雁沉。',48,'全唐诗/poet.song.109000.json','["不見李君久，水雲魚雁沉。", "調官聊製錦，得句賸關心。", "每訪民情悅，相望春事深。", "故鄉與賢者，北首重登臨。"]'),
('9eed57d1-9d4c-4c6d-9a1f-e7da0562108a','小三姪遠持兄嫂之命見訪于荒寒寂寞中將歸二詩爲別  其一','曹勛','宋','宋诗','song-poetry','','[]','投老台山麓，松篁築靚幽。',48,'全唐诗/poet.song.109000.json','["投老台山麓，松篁築靚幽。", "行年今七十，撫事幾春秋。", "但喜親情話，難忘爲小留。", "山川煩跋履，事事見操修。"]'),
('2d6b0d06-e217-4a18-b6c5-b220b8e89657','小三姪遠持兄嫂之命見訪于荒寒寂寞中將歸二詩爲別  其二','曹勛','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','不見小阮久，相看情甚溫。',48,'全唐诗/poet.song.109000.json','["不見小阮久，相看情甚溫。", "肯來成宅相，端可大吾門。", "暖日長江路，梅花細雨村。", "真成好兄弟，言謝却忘言。"]'),
('10de14b2-3b0c-47f6-af7d-4d438dd562d7','示諸子','曹勛','宋','宋诗','song-poetry','','[]','霜入晴雲暖，冰生掠岸沙。',48,'全唐诗/poet.song.109000.json','["霜入晴雲暖，冰生掠岸沙。", "卑枝閑剪橘，幽徑試尋花。", "客路人情薄，鄉關去路賒。", "只應託諸子，莫倦問桑麻。"]'),
('6aa4944f-c39f-447e-aa6b-1feb1e941ca6','獨步南園寄子忱','曹勛','宋','宋诗','song-poetry','','[]','野老悲春事，相如復倦游。',48,'全唐诗/poet.song.109000.json','["野老悲春事，相如復倦游。", "肯來傾濁酒，同與散清愁。", "遠岸重重柳，晴江處處舟。", "飛紅殘照晚，閑倚水邊樓。"]'),
('a2a44180-bbba-418d-8348-ac6ca2af071c','聞逆虜近淮','曹勛','宋','宋诗','song-poetry','','[]','壬午收亨運，餘屯未肯休。',48,'全唐诗/poet.song.109000.json','["壬午收亨運，餘屯未肯休。", "風烟淮水近，天地老身愁。", "虜意驕如昨，江干景易秋。", "得閑如自若，心在一扁舟。"]'),
('cf2a2157-ca47-4b67-9c8f-3dcc724996b3','方檢詳出歙研求詩','曹勛','宋','宋诗','song-poetry','','[]','黟歙與端璞，爭雄稱權奇。',48,'全唐诗/poet.song.109000.json','["黟歙與端璞，爭雄稱權奇。", "馬肝乃正色，龍尾終視儀。", "霜毫瀹紫玉，松烟生華滋。", "都付文學老，看誦浯溪時。"]'),
('28a0cabf-3c9d-4eca-8ac0-5d3a5e353914','淮上幕府','曹勛','宋','宋诗','song-poetry','','[]','上將宣威重，長淮朔吹來。',48,'全唐诗/poet.song.109000.json','["上將宣威重，長淮朔吹來。", "兵戎已超距，鼓角有餘哀。", "日薄雲多暝，天寒火易灰。", "詩成且排悶，興在倒金罍。"]'),
('6607a342-2683-49c7-aadc-f5ed575e5732','聞有衣冠附僞命者','曹勛','宋','宋诗','song-poetry','','[]','義分元無守，跳梁遂不臣。',48,'全唐诗/poet.song.109000.json','["義分元無守，跳梁遂不臣。", "美新應有賦，思漢定何人。", "晚景嗟逢此，孤忠尚欲伸。", "君王在靈武，日竚靖風塵。"]'),
('dac8d877-5963-4469-b148-82c56e82d39e','問訊子忱游天台','曹勛','宋','宋诗','song-poetry','','[]','落落賀吏部，蕭蕭湖海姿。',48,'全唐诗/poet.song.109000.json','["落落賀吏部，蕭蕭湖海姿。", "好山應自適，短棹得回遲。", "花發庭中檻，香傳舍外籬。", "相思梅已謝，無處問歸期。"]'),
('1c9b2680-baed-4cb8-b969-c194ea8388cf','喜張叔潛登第','曹勛','宋','宋诗','song-poetry','','[]','潜也忠良士，騫騰喜縱觀。',48,'全唐诗/poet.song.109000.json','["潜也忠良士，騫騰喜縱觀。", "主文收俊彥，學校益尊安。", "臺閣名聞久，交游意始寬。", "佐時行拭目，正論聳朝端。"]'),
('d95f0435-9c13-40bb-94d1-865a77019069','到廬阜謁清虛','曹勛','宋','宋诗','song-poetry','','[]','足趼踰千里，仙山豈易逢。',48,'全唐诗/poet.song.109000.json','["足趼踰千里，仙山豈易逢。", "欲將遮日手，款扣撥雲峯。", "奎壁垂無極，星辰拱幾重。", "師心微太漠，不礙白雲封。"]'),
('ec33186c-5e66-406e-b9dc-ff67bcaeae71','游廬山道中作','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','早踏丹楓路，西風禾豆乾。',48,'全唐诗/poet.song.109000.json','["早踏丹楓路，西風禾豆乾。", "鳴榔秋水闊，擊漂曉溪寒。", "短褐宜扶杖，長涂懶據鞍。", "却思冬後景，黄菊壓欄干。"]'),
('d42ca11d-3117-4b4a-a4da-35f161eff1ab','游廬山涂中雜詩三首  其一','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','天台久宴坐，廬阜得遊遨。',48,'全唐诗/poet.song.109000.json','["天台久宴坐，廬阜得遊遨。", "殊慰水雲念，敢辭塵土勞。", "冬溫寒色少，江靜水痕高。", "歸趁新年近，同斟玉色醪。"]'),
('04f0c135-6e1a-4325-ac96-c9f690e93214','游廬山涂中雜詩三首  其二','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','去去忘回遠，行行迫臘天。',48,'全唐诗/poet.song.109000.json','["去去忘回遠，行行迫臘天。", "江寒侵老淚，霜冷逼宵眠。", "客路雖經至，歸涂尚過千。", "家山在台嶽，南望幾悠然。"]'),
('df7c371a-e9c1-4606-997e-0ec65d20cb39','游廬山涂中雜詩三首  其三','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','稅駕南昌郡，城頭喜少留。',48,'全唐诗/poet.song.109000.json','["稅駕南昌郡，城頭喜少留。", "兒時誦閑賦，老境作佳游。", "傑閣收英槩，長江倚暮愁。", "何人識老子，清月上貂裘。"]'),
('39993da7-55c1-43d8-8e4d-ebaee3bbebe5','苕溪道中','曹勛','宋','宋诗','song-poetry','','[]','秋日苕溪路，輕舟棹晚霞。',48,'全唐诗/poet.song.109000.json','["秋日苕溪路，輕舟棹晚霞。", "夢魂猶畏客，行李乍離家。", "細細來凉吹，娟娟有晚花。", "平生雲水興，老境似難誇。"]'),
('b9db3b3c-270d-4edf-a5a0-9411fa117766','過小圃','曹勛','宋','宋诗','song-poetry','','[]','小隠州城北，先謀儋石儲。',48,'全唐诗/poet.song.109000.json','["小隠州城北，先謀儋石儲。", "幾椽將弊屋，數策未看書。", "碧色新松徑，泉聲舊石渠。", "欣然終日過，真是愛吾廬。"]'),
('f3ff8ac6-84d9-4454-a01c-aed826d4a872','上塘值清明八首  其一','曹勛','宋','宋诗','song-poetry','','[]','客路逢寒食，划船閙水干。',48,'全唐诗/poet.song.109000.json','["客路逢寒食，划船閙水干。", "嬌雲易得雨，暴冷不成寒。", "白水連天去，繁桃觸目看。", "朝來有家信，稚子報平安。"]'),
('b6c5ebf0-1a8a-4b78-b95a-0e1db0627975','上塘值清明八首  其二','曹勛','宋','宋诗','song-poetry','','[]','客路逢寒食，清明未到家。',48,'全唐诗/poet.song.109000.json','["客路逢寒食，清明未到家。", "起居須藥餌，飲食任魚蝦。", "水浄垂垂柳，風遲艷艷花。", "興來隨處樂，不復問年華。"]'),
('591b1dbf-a747-4cf5-9afe-f68cb3d3099c','上塘值清明八首  其三','曹勛','宋','宋诗','song-poetry','','[]','客路逢寒食，猶尋禦臘衣。',48,'全唐诗/poet.song.109000.json','["客路逢寒食，猶尋禦臘衣。", "羣芳須暖景，曨日尚寒暉。", "餘力求閑早，勞生昨夢非。", "薺花渾似雪，蝴蝶夢中歸。"]'),
('465b9835-8214-48c2-80b1-7c4212eb1316','上塘值清明八首  其四','曹勛','宋','宋诗','song-poetry','','[]','客路逢寒食，光陰亦可驚。',48,'全唐诗/poet.song.109000.json','["客路逢寒食，光陰亦可驚。", "如何介子節，再過闔廬城。", "列岫遥逾碧，羣芳晚更明。", "飯餘風力壯，掀舞小舟輕。"]'),
('a80c86a0-f7a8-4419-bbd8-d1c571560afb','上塘值清明八首  其五','曹勛','宋','宋诗','song-poetry','','[]','客路逢寒食，山光觸處新。',48,'全唐诗/poet.song.109000.json','["客路逢寒食，山光觸處新。", "取魚多樣網，艤岸幾州人。", "默爾非無住，超然得任真。", "今年卦氣盡，四顧欲何親。"]'),
('a1019eb1-a85e-4f97-abfd-491e7f03e2cc','上塘值清明八首  其六','曹勛','宋','宋诗','song-poetry','','[]','客路逢寒食，浙西春事稀。',48,'全唐诗/poet.song.109000.json','["客路逢寒食，浙西春事稀。", "日華藏暖景，天氣未單衣。", "歌棹喧椎鼓，桃花巧映扉。", "空收麰麥粉，藥病豈心違。"]'),
('7f5a8aec-6caf-4951-a1e0-bea7170962df','上塘值清明八首  其七','曹勛','宋','宋诗','song-poetry','','[]','客路逢寒食，禾秧出已齊。',48,'全唐诗/poet.song.109000.json','["客路逢寒食，禾秧出已齊。", "清溪三汊淺，白鷺一行低。", "禊飲心何在，茅峰路恐迷。", "隨時隨有樂，何處不幽棲。"]'),
('224a0f22-3b79-4763-8e35-ff69da7f38af','上塘值清明八首  其八','曹勛','宋','宋诗','song-poetry','','[]','客路逢寒食，欣同不繫舟。',48,'全唐诗/poet.song.109000.json','["客路逢寒食，欣同不繫舟。", "閑中聊適性，要地固抽頭。", "不作揚州夢，何能賈客留。", "壯懷今斷斷，世事任悠悠。"]'),
('14c0d079-faf7-45b1-aa49-05182555ae1d','涂中寒食','曹勛','宋','宋诗','song-poetry','','[]','上巳當羈旅，飄然浙水東。',48,'全唐诗/poet.song.109000.json','["上巳當羈旅，飄然浙水東。", "好花閑照水，宿雨冷連空。", "靈武兵方振，燕然信未通。", "無人訪老子，有淚濕春紅。"]'),
('47bf2eb2-670b-4ca4-8b02-dec726732c8d','南園夜宿有懷','曹勛','宋','宋诗','song-poetry','','[]','老病杜門久，佳時誰與過。',48,'全唐诗/poet.song.109000.json','["老病杜門久，佳時誰與過。", "親朋懷我少，風月向人多。", "梅景橫清夜，江聲動白波。", "不如潮早晚，牆外聽漁歌。"]'),
('7e8d0025-147b-45ad-8836-24a0833dacc8','臨安久雨','曹勛','宋','宋诗','song-poetry','','[]','初夏連朝雨，土人云入梅。',48,'全唐诗/poet.song.109000.json','["初夏連朝雨，土人云入梅。", "但聞簷溜密，不見曉光開。", "衣潤疑霑汗，階空任長苔。", "地車無住著，只擬上層臺。"]'),
('adcfbe69-d940-4a79-a006-3a24a1b1641f','謝岸老惠顯明新芽','曹勛','宋','宋诗','song-poetry','','[]','幽壑乘春摘，芳芽辱見分。',48,'全唐诗/poet.song.109000.json','["幽壑乘春摘，芳芽辱見分。", "鶑花妨老眼，香味喜新聞。", "細石飛輕雪，圓甌泛亂雲。", "雖無七碗量，清興重欣欣。"]'),
('bda63a27-3564-4b6c-81d4-2881782c5828','食虀有作','曹勛','宋','宋诗','song-poetry','','[]','點化八珍爽，須煩一品虀。',48,'全唐诗/poet.song.109000.json','["點化八珍爽，須煩一品虀。", "村寒求甕下，麵法記山西。", "宮徵難忘味，膏粱勿遽迷。", "終然調鼎手，深旨出扶犁。"]'),
('be5b7e20-e7d1-4c17-8b2d-760849591820','得致仕喜成','曹勛','宋','宋诗','song-poetry','','[]','久甚嗟形役，今方得自怡。',48,'全唐诗/poet.song.109000.json','["久甚嗟形役，今方得自怡。", "所欣官已了，得與靜相期。", "風月閑如舊，心情喜可知。", "山中雞黍友，賀幅已先持。"]'),
('c178c384-aaa7-4120-9156-c1ce23d1c5b6','憶梅','曹勛','宋','宋诗','song-poetry','','[]','江雲暗江路，曾向玉川家。',48,'全唐诗/poet.song.109000.json','["江雲暗江路，曾向玉川家。", "冷入參差玉，香隨的皪花。", "照溪回夜色，冒雪冠春華。", "猶記西窗伴，寒枝片月斜。"]'),
('afeeb771-936e-4f49-b101-be30e37a0931','暑後喜雨','曹勛','宋','宋诗','song-poetry','','[]','雨因祈禱得，連日作廉纖。',48,'全唐诗/poet.song.109000.json','["雨因祈禱得，連日作廉纖。", "候變凉飆肅，人皆和氣添。", "秋暘猶執熱，竹色故侵簷。", "但喜穹崇德，難從甲乙占。"]'),
('9b2cb3f1-4288-40c3-b343-33d41c8ad7f9','招賈祕書','曹勛','宋','宋诗','song-poetry','','[]','不見賈夫子，病懷何得陳。',48,'全唐诗/poet.song.109000.json','["不見賈夫子，病懷何得陳。", "呻吟一春了，物色九秋新。", "閑花翳欄檻，秀氣浮衣巾。", "笑言約中澣，雞黍供蕭晨。"]'),
('02ada418-e857-49f1-bf4c-ec8b8e5d16dd','和張才甫野望軒','曹勛','宋','宋诗','song-poetry','','[]','聞闢新軒檻，高明豈鞠窮。',48,'全唐诗/poet.song.109000.json','["聞闢新軒檻，高明豈鞠窮。", "八荒供望眼，萬事付冥鴻。", "聊味青龍鈔，行趨白虎通。", "大千兼內外，拈出便無同。"]'),
('7887b176-81e5-4390-8fbe-fdf621af9e40','寄吳思道','曹勛','宋','宋诗','song-poetry','','[]','別去書音短，愁來客路長。',48,'全唐诗/poet.song.109000.json','["別去書音短，愁來客路長。", "飛魂常故國，舉目念殊鄉。", "未暇論奇字，何堪別最良。", "秋風入邊草，意苦不相忘。"]'),
('ee100102-ce72-44c4-8316-ed23e7c09b82','簡沖嗇庵中故人','曹勛','宋','宋诗','song-poetry','','[]','寄跡臨安久，思歸夕夢頻。',48,'全唐诗/poet.song.109000.json','["寄跡臨安久，思歸夕夢頻。", "愁多難强醉，病苦故禁人。", "夜短無清夢，年高歎幻身。", "山中有道伴，雲壑擅餘春。"]'),
('81240d9a-d7e1-458b-a96c-a53edfa13327','恭進德壽芝草','曹勛','宋','宋诗','song-poetry','','[]','椒掖沖襟奉玉宸，靈芝莖葉出氤氳。',64,'全唐诗/poet.song.109000.json','["椒掖沖襟奉玉宸，靈芝莖葉出氤氳。", "如頒月令欣欣政，先學巫山藹藹雲。", "璀璨吐奇康壽棟，輪囷絕異漢唐聞。", "只應一葉三千歲，萬億斯年贊大君。"]'),
('aaa638ef-e5f8-4293-a24c-a64e735fca63','會慶聖節','曹勛','宋','宋诗','song-poetry','','[]','帝出乘時叶小春，中興復古付曾孫。',64,'全唐诗/poet.song.109000.json','["帝出乘時叶小春，中興復古付曾孫。", "奉親聖德躬仁孝，御極天章廓晏溫。", "書軌自應歸正統，蠻夷先已侍脩門。", "凌虛志遠吞寰宇，億載端臨四海尊。"]'),
('517e512b-f257-4b61-ad44-3bb54474617c','癸巳聖節二首  其一','曹勛','宋','宋诗','song-poetry','','[]','堪輿亨會接洪基，鬰鬰葱葱動紫微。',64,'全唐诗/poet.song.109000.json','["堪輿亨會接洪基，鬰鬰葱葱動紫微。", "理契弈秋專國手，德兼周武一戎衣。", "恩言下浹皆中道，帝意終潜復九圍。", "升濟羣生歸大業，同心億萬仰天威。"]'),
('40b5116b-29f6-478a-a55e-9704f75f106c','癸巳聖節二首  其二','曹勛','宋','宋诗','song-poetry','','[]','曉雲紺瓦不飛霜，瑞靄融春十月陽。',64,'全唐诗/poet.song.109000.json','["曉雲紺瓦不飛霜，瑞靄融春十月陽。", "電繞璇樞開上瑞，虹流華渚叶珍祥。", "威騰紫塞天驕外，日拱蒼龍闕角傍。", "今歲泰壇伸謁款，是宜萬壽詠無疆。"]'),
('7bce00fe-b73d-4a8e-9f97-d0b47337a420','恭奉聖訓賦凌虛','曹勛','宋','宋诗','song-poetry','','[]','新規傑閣倚蒼巒，地拱天成十二欄。',64,'全唐诗/poet.song.109000.json','["新規傑閣倚蒼巒，地拱天成十二欄。", "但覺星辰來廣漠，不知步武切高寒。", "春風先到黄金闕，皓月常臨白玉槃。", "曾侍威顔香案末，邃瞻旒扆瑞雲端。"]'),
('0fe97fca-c306-4f49-a323-74bbcfa79e1e','宣召看紅木犀賜宴索詩并謝恩','曹勛','宋','宋诗','song-poetry','','[]','九霞深借曉光披，粟粟輕紅蔭碧枝。',64,'全唐诗/poet.song.109000.json','["九霞深借曉光披，粟粟輕紅蔭碧枝。", "不逐秋香勻菊艷，要烘花色並彤墀。", "凉雲收雨頒慈惠，寶幄中天拜宴私。", "折得一枝恩所賜，喜如初挂綠衣時。"]'),
('f04e33c1-0745-4637-9ba4-882c102c92cb','恭睹上聖親臨江淮耀武伊洛謹成詩一章仰贊聖化','曹勛','宋','宋诗','song-poetry','','[]','曉傳清警出龍樓，八駿騰驤下斗牛。',64,'全唐诗/poet.song.109000.json','["曉傳清警出龍樓，八駿騰驤下斗牛。", "鐵騎屯雲朝障殿，羽林扈蹕拱凝旒。", "暫迂玉趾臨三楚，便覺榮光煥九州。", "恢復故疆知默定，已看森索墜旄頭。"]'),
('3f852ad6-b91c-4f5b-bf7b-cd8d55fd572a','恭題觀堂','曹勛','宋','宋诗','song-poetry','','[]','松篁深靚隠新宮，十六清真位位同。',64,'全唐诗/poet.song.109000.json','["松篁深靚隠新宮，十六清真位位同。", "笙鶴似臨三境上，珮環應下五雲中。", "烟霞頓隔塵寰路，道德追還太古風。", "固已羣仙資聖壽，嵩呼益願祝堯聰。"]'),
('8bbe4112-a859-4221-9f67-f3edef731218','初到闕下','曹勛','宋','宋诗','song-poetry','','[]','墨敕雙馳侍帝傍，何堪窘步入明光。',64,'全唐诗/poet.song.109000.json','["墨敕雙馳侍帝傍，何堪窘步入明光。", "退風久作翻風翼，倦客何能久客梁。", "野寺殘僧思緩步，斷橋流水憶寒香。", "何時裋褐携筇去，數里松聲細麥岡。"]'),
('86487e23-73f9-48c7-833e-15a2e3a1230b','故舊見辟幕府','曹勛','宋','宋诗','song-poetry','','[]','生逢艱苦念無前，扈聖猶悲易水壖。',64,'全唐诗/poet.song.109000.json','["生逢艱苦念無前，扈聖猶悲易水壖。", "知效一官常自愧，死須五鼎遂身先。", "頗收姓字朝廷上，寧復功名日月邊。", "軍旅固非平日事，願將餘力從櫜鞬。"]'),
('9f4426b3-69e0-4c07-a44d-5696e07bbc3c','持節和王樞密三首  其一','曹勛','宋','宋诗','song-poetry','','[]','長淮矯首得遐觀，猶記當年獲奉鑾。',64,'全唐诗/poet.song.109000.json','["長淮矯首得遐觀，猶記當年獲奉鑾。", "萬馬飲淮貔虎肅，六師扈蹕水雲寒。", "欣瞻幕府蓮依水，慨念神州李下冠。", "狼望已銷歸廟畧，更持韻語訪任安。"]'),
('8b78189c-dd1d-4dac-aa24-b4c0e2f87a0a','持節和王樞密三首  其二','曹勛','宋','宋诗','song-poetry','','[]','稍陪酬唱與榮觀，聲並琳琅和八鑾。',64,'全唐诗/poet.song.109000.json','["稍陪酬唱與榮觀，聲並琳琅和八鑾。", "可但文華迎日麗，自然符采照人寒。", "笑談殊喜親犀麈，接侍終慚戴鶡冠。", "公等雍容瑚璉器，騫騰行見近長安。"]'),
('8e496861-26b1-4e59-b582-31138f6f5ea8','持節和王樞密三首  其三','曹勛','宋','宋诗','song-poetry','','[]','右府登車竦聽觀，皎如玉韻叶和鑾。',64,'全唐诗/poet.song.109000.json','["右府登車竦聽觀，皎如玉韻叶和鑾。", "清薰已解南風慍，和氣先舒易水寒。", "行李喜陪金虎節，移文應閟竹皮冠。", "願看歸去爲霖雨，天下蒼生在謝安。"]'),
('9f6e6da9-e882-4c53-8516-d196ef934f5e','持節過界','曹勛','宋','宋诗','song-poetry','','[]','泗濱悵望草連雲，眼暗凄塵祇斷魂。',64,'全唐诗/poet.song.109000.json','["泗濱悵望草連雲，眼暗凄塵祇斷魂。", "香火固難尋寶塔，雲烟時復見沙墩。", "五更悲壯眠難熟，一片荒寒曉更昏。", "往事興懷今二紀，道傍父老豈兒孫。"]'),
('585a49b9-61fe-4c8e-b3bc-46d0628fc4d8','持節過京','曹勛','宋','宋诗','song-poetry','','[]','與客西游歷汴都，荒寒不復見吾廬。',64,'全唐诗/poet.song.109000.json','["與客西游歷汴都，荒寒不復見吾廬。", "只今黯黯塵埃起，當日葱葱氣象無。", "雖覺人情猶向化，不知天意竟何如。", "遥思閶闔西邊路，一夕飛魂繞故居。"]'),
('676522bf-8828-4982-bf81-7854e64374b3','聞江上捷音','曹勛','宋','宋诗','song-poetry','','[]','黠虜窺邊久未恭，天王清蹕殄元凶。',64,'全唐诗/poet.song.109000.json','["黠虜窺邊久未恭，天王清蹕殄元凶。", "軍威早已聞三捷，喜色遥知動六龍。", "師旅夙嚴新號令，版圖行復舊提封。", "中興大業書歌詠，願刻浯溪頌九重。"]'),
('f070eaa0-41a8-4aa0-8a1f-2c98c33b25a9','被旨軍前講和得回','曹勛','宋','宋诗','song-poetry','','[]','仗節親宣詔語還，敢期幼稚得重看。',64,'全唐诗/poet.song.109000.json','["仗節親宣詔語還，敢期幼稚得重看。", "鐵衣冷桂龍鱗靜，寶劍高藏玉彘寒。", "兵甲從今挽河水，兒孫力與復儒冠。", "清閑放意山林下，老援何能更據鞍。"]'),
('fd3d885e-a77c-4998-ba8e-05b08e1a768b','呈時宰二首  其一','曹勛','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','黔黎誰識迓衡功，赤白囊閑寢燧烽。',64,'全唐诗/poet.song.109000.json','["黔黎誰識迓衡功，赤白囊閑寢燧烽。", "史不絕書稱上瑞，地無遺利足三農。", "已聞奠玉祠真室，未見泥金款岱宗。", "七十二君梁父禪，何時展采更東封。"]'),
('b45f1e26-1a64-484c-ac78-0e752f886cc0','呈時宰二首  其二','曹勛','宋','宋诗','song-poetry','','[]','不毛山海盡梯航，德洽重熙聖祚昌。',64,'全唐诗/poet.song.109000.json','["不毛山海盡梯航，德洽重熙聖祚昌。", "萬國鼎新周禮樂，千官星拱舜衣裳。", "惠霑圜土恩波闊，德及昆蟲化日長。", "天地至和昭感格，比聞甘露降番陽。"]'),
('2234fa32-c142-48bc-95bc-69400053c906','政府生日四首  其一','曹勛','宋','宋诗','song-poetry','','[]','文經武緯致尊榮，功德崇高不可名。',64,'全唐诗/poet.song.109000.json','["文經武緯致尊榮，功德崇高不可名。", "草檄預聞全國勢，按圖行見復都城。", "衮衣三總郊丘禮，黛耜初親帝藉耕。", "過眼蓬萊幾清淺，凝神治道自長生。"]'),
('410195c5-a651-456e-bee6-6c38e087267d','政府生日四首  其二','曹勛','宋','宋诗','song-poetry','','[]','上公翊戴肅朝紳，衮繡趨庭下帝宸。',64,'全唐诗/poet.song.109000.json','["上公翊戴肅朝紳，衮繡趨庭下帝宸。", "一德格天瞻相業，密雲不雨協郊禋。", "初筵寵錫清都奏，和氣融隨明日春。", "成算自應同壽算，兩河黎庶待陶鈞。"]'),
('57bb8e69-5fdb-403f-8a4e-2903794af0ae','政府生日四首  其三','曹勛','宋','宋诗','song-poetry','','[]','鉅德元功鳳應韶，屏風隔坐翊昌朝。',64,'全唐诗/poet.song.109000.json','["鉅德元功鳳應韶，屏風隔坐翊昌朝。", "星辰循軌三階正，鐘鼓重新一氣調。", "活國工夫歸斷斷，鍊形真一已飄飄。", "芒鞋門下塵埃客，拔宅惟看上紫霄。"]'),
('0db4415c-47c0-47aa-8d36-f79e09695d66','政府生日四首  其四','曹勛','宋','宋诗','song-poetry','','[]','歲躔回次拱台星，麟閣儀刑首萬英。',64,'全唐诗/poet.song.109000.json','["歲躔回次拱台星，麟閣儀刑首萬英。", "鍾阜堂堂分秀潤，淮波衮衮湛清明。", "鋪張治具調元化，整頓皇綱撫有生。", "鶴馭它時赤松伴，丹砂九轉待功成。"]'),
('027853fe-f8eb-4711-bc0c-165d13f84446','殿帥生日','曹勛','宋','宋诗','song-poetry','','[]','薰風拂拂下槐庭，師帥膺時奠四溟。',64,'全唐诗/poet.song.109000.json','["薰風拂拂下槐庭，師帥膺時奠四溟。", "代北家聲今嗣業，淮南草木亦知名。", "陣前鐵馬三軍勇，肘後金丹九轉成。", "立國宗臣宜壽考，陰功篆玉定長生。"]'),
('45459734-1512-4518-8198-26b4ff0cc64d','林詔使生日','曹勛','宋','宋诗','song-poetry','','[]','杪冬慶閥綺雲浮，挺育文英氣奪秋。',64,'全唐诗/poet.song.109000.json','["杪冬慶閥綺雲浮，挺育文英氣奪秋。", "烏府暫煩安遠俗，龍驤方倚破姦謀。", "三吳遂奠時巡馭，四海咸瞻入告猷。", "何止陰功鍾五福，巖廊已識濟川舟。"]'),
('0f38bd3b-937f-4375-afd6-6ed44b55bd1e','何季崇生日','曹勛','宋','宋诗','song-poetry','','[]','慶閥當年侍從臣，傳家今見石麒麟。',64,'全唐诗/poet.song.109000.json','["慶閥當年侍從臣，傳家今見石麒麟。", "瑶觴初過菖蒲節，碧海聊觀荔子春。", "超逸絕塵髯政事，暑天湯餠魏簪紳。", "祝公千百松筠壽，常對團團月色新。"]'),
('9db0d46b-e6cb-4f30-89f9-226b41af7c3b','題吳郡王家雙竹','曹勛','宋','宋诗','song-poetry','','[]','環碧亭前碧玉枝，森森連璧揖多姿。',64,'全唐诗/poet.song.109000.json','["環碧亭前碧玉枝，森森連璧揖多姿。", "節涵宿雨蒼龍並，梢舞晴雲翠鳳差。", "架雪凌霜俱有志，懷仁抱義本同時。", "戚垣密協如苞瑞，盛事應先黼扆知。"]'),
('f3bfc75a-486c-47ad-a4d5-938d960f13f2','題錢參政東巖','曹勛','宋','宋诗','song-poetry','','[]','龍顧初聞闢縱觀，盡收清勝閟高寒。',64,'全唐诗/poet.song.109000.json','["龍顧初聞闢縱觀，盡收清勝閟高寒。", "四圍列岫飛雲靜，十里平湖碧照寬。", "麈尾有言皆灌頂，塵中無路不驚湍。", "東巖端作東山望，行爲蒼生起謝安。"]'),
('5a80c441-ea45-4919-bf84-95d1037d86a5','題王懋功秀才秀野堂','曹勛','宋','宋诗','song-poetry','','[]','卜築清幽遠市塵，一川窈窕靜松筠。',64,'全唐诗/poet.song.109000.json','["卜築清幽遠市塵，一川窈窕靜松筠。", "下臨城郭千門曉，中有軒窗五畝春。", "游藝本圖佳客語，好賢不覺主人貧。", "我來登覽秋風晚，喜揖清言月色新。"]'),
('67b8b8c5-5ccb-47dd-b9c7-1a9d2449b350','題謝太尉養素堂','曹勛','宋','宋诗','song-poetry','','[]','東山雅望意雍容，養素璇題振道風。',64,'全唐诗/poet.song.109000.json','["東山雅望意雍容，養素璇題振道風。", "賸貯琴書供嘯詠，更新窗戶不青紅。", "數峯吳越登臨外，千里江山指顧中。", "玉碾碧天冷無際，中秋莫放酒杯空。"]'),
('51989c90-dd18-443b-bb71-b744c39744c4','賦郭步帥歸耕堂','曹勛','宋','宋诗','song-poetry','','[]','漢水無波楚岫青，歸來風月久經營。',64,'全唐诗/poet.song.109000.json','["漢水無波楚岫青，歸來風月久經營。", "要親稼穡資三徑，已試韜鈐息五兵。", "賣劍買牛聊適意，揚鞭敲𩍐暫忘情。", "祇應未穩耘耔樂，褒詔行需父子榮。"]'),
('1fd1824e-9f80-45a0-9a40-81482601e5c1','題迎暉堂','曹勛','宋','宋诗','song-poetry','','[]','爽塏幽居抵萬金，東西領畧水雲深。',64,'全唐诗/poet.song.109000.json','["爽塏幽居抵萬金，東西領畧水雲深。", "江山入坐清無暑，文史銷閒靜有琴。", "何處菱歌烟艇雨，最宜秋月海潮音。", "主人占得林泉樂，本有江湖一片心。"]'),
('66021d2d-add9-430f-87fb-bc21183c2d27','題人舫齋','曹勛','宋','宋诗','song-poetry','','[]','君家作屋擬虛舟，想見低窗事事幽。',64,'全唐诗/poet.song.109000.json','["君家作屋擬虛舟，想見低窗事事幽。", "竹幹巧同檣影直，簾波寒並水光浮。", "五湖烟月應無意，四海風塵計少留。", "挂旆天山端有待，要憑巨楫濟橫流。"]'),
('9672908e-9fa4-4f07-98e3-4dc0cab91fb4','題客舍','曹勛','宋','宋诗','song-poetry','','[]','路邊小舍靜無泥，風入松杉綠滿枝。',64,'全唐诗/poet.song.109000.json','["路邊小舍靜無泥，風入松杉綠滿枝。", "溪抱回隄山抱屋，舟藏曲港竹藏籬。", "主人野性留應懶，倦客閑情去輙遲。", "內訟塵埃猶僕僕，厚顔如奉北山移。"]'),
('74ad7aa5-6a2f-4717-b7e7-0cd9d0ce03e3','寄題祝祕校航齋','曹勛','宋','宋诗','song-poetry','','[]','密密簾垂映柁樓，濟川聊此艤虛舟。',64,'全唐诗/poet.song.109000.json','["密密簾垂映柁樓，濟川聊此艤虛舟。", "羣經列坐供游息，巨浪掀天得罷休。", "猿鶴依棲知有地，兒童遺墜且無憂。", "業成一棹黄金闕，穩上鼇頭拜冕旒。"]'),
('b1136a62-bc72-4a0b-b1e2-b94d4f87682b','賦陳嘉謨東西軒二首  其一','曹勛','宋','宋诗','song-poetry','','[]','田田東作襯柴關，濕碧吹青一望間。',64,'全唐诗/poet.song.109000.json','["田田東作襯柴關，濕碧吹青一望間。", "已許傾心常向日，尚容高卧且懷山。", "光風春動方崇蕙，沆瀣宵零可駐顔。", "要是耕耘在毛墨，圖書佳客樂餘閒。"]'),
('a600db47-b7f2-4d29-8e9b-fc84fe4014b8','賦陳嘉謨東西軒二首  其二','曹勛','宋','宋诗','song-poetry','','[]','西成高鑿一軒通，荷蓋吹凉入坐中。',64,'全唐诗/poet.song.109000.json','["西成高鑿一軒通，荷蓋吹凉入坐中。", "新月不妨回夜色，有秋何止閲年豐。", "直須落日紅無際，剩看羣山翠掃空。", "更約他年身退後，披襟來此揖凉風。"]'),
('3b1b9c8b-0e93-43b5-b7f6-cf25a753aa17','詠雙竹','曹勛','宋','宋诗','song-poetry','','[]','千巖萬壑碧嶙峋，密有雙成瑞此君。',64,'全唐诗/poet.song.109000.json','["千巖萬壑碧嶙峋，密有雙成瑞此君。", "破籜猗猗聯綠玉，並梢裊裊舞清薰。", "巧穿怪石嵌空地，色映虛亭窈窕雲。", "比節合心皆美事，孤高殊喜不同羣。"]'),
('c741ee8a-7828-4cbd-a3cc-da937a670073','賦友人竹軒','曹勛','宋','宋诗','song-poetry','','[]','軒外蕭騷靜碧雲，有來君子助通津。',64,'全唐诗/poet.song.109000.json','["軒外蕭騷靜碧雲，有來君子助通津。", "烟幢羽蓋誠銷暑，玉軸牙籤不受塵。", "解籜竹林宜瑣碎，漙梢風露獻清新。", "茶瓜雅納開懷客，俱喜高材似主人。"]'),
('ba491fbc-93f6-48ce-8c9b-a2dec33813df','友人所居竹岡以關名之','曹勛','宋','宋诗','song-poetry','','[]','曉驅羸馬踏塵埃，喜見前關亦快哉。',64,'全唐诗/poet.song.109000.json','["曉驅羸馬踏塵埃，喜見前關亦快哉。", "幾啟雙扉迎曉日，未妨斜月掩蒼苔。", "聲摇沙塞可無此，翠鎖城埤寒未開。", "趁得雞鳴也須度，棄繻不是俗人來。"]'),
('b63c34c0-8aa7-40ae-8f7f-94f938723ddc','贈許察院','曹勛','宋','宋诗','song-poetry','','[]','海內知名第一流，詩從偉度破優柔。',64,'全唐诗/poet.song.109000.json','["海內知名第一流，詩從偉度破優柔。", "知公少駐摶風翼，念我都如露地牛。", "解臘天容先布暖，得春梅意小遲留。", "紅穿碧甲聊隨俗，不奈心驚雁過樓。"]'),
('d3ed9913-c82b-451e-9151-d0ebdf773fcd','贈李嚴州','曹勛','宋','宋诗','song-poetry','','[]','謫仙風骨今何如，自我不見三年餘。',64,'全唐诗/poet.song.109000.json','["謫仙風骨今何如，自我不見三年餘。", "雙眸如電尚可想，兩鬢欲雪今安無。", "干戈塞路軍麾滿，骨肉避地星散居。", "未知草堂可歸否，有使可寄平安書。"]'),
('79846080-769a-4745-b45f-24f0a0a39852','贈聞人子進','曹勛','宋','宋诗','song-poetry','','[]','丹地清江若有期，卜居仍俯小漣漪。',64,'全唐诗/poet.song.109000.json','["丹地清江若有期，卜居仍俯小漣漪。", "頗憐松竹無多地，祇頓琴書已近籬。", "久雨不妨田要潤，暫凉真與病相宜。", "何當去此炎歊酷，日待風高脫葉時。"]'),
('fe42b502-0572-4392-9324-6f816ff7ca50','贈靈隠老','曹勛','宋','宋诗','song-poetry','','[]','一笑相逢語上方，水雲旂跡覺清凉。',64,'全唐诗/poet.song.109000.json','["一笑相逢語上方，水雲旂跡覺清凉。", "未論方丈葛藤話，且喜齋厨蔬笋香。", "閑拄瘦筇隨意立，却愁款段入城忙。", "宿山更作他時約，枕簟茶瓜冷不妨。"]'),
('d36dd844-5eba-4a71-ace2-e853626833e9','潮州贈劉大夫','曹勛','宋','宋诗','song-poetry','','[]','山繞蒙庵十里陰，兩翁逸駕每駸駸。',64,'全唐诗/poet.song.109000.json','["山繞蒙庵十里陰，兩翁逸駕每駸駸。", "人隨衡雁野雲薄，夢繞鱷溪秋水深。", "別後詩章清有思，向來游處賸關心。", "何妨一笑雲蘿上，小約湖邊特特尋。"]'),
('cf653c7e-276a-4cb8-8e69-a3ae0afabc0f','贈李次仲致政','曹勛','宋','宋诗','song-poetry','','[]','縠水柯山隔幾年，又來輦轂拜雲天。',64,'全唐诗/poet.song.109000.json','["縠水柯山隔幾年，又來輦轂拜雲天。", "東西南北任造化，甲乙丙丁皆宿緣。", "老境精神惟坐卧，故居松竹想清妍。", "豈如溪上木中子，日飲溪光今地仙。"]');
